import { activityStore } from '$shared/stores/activity.svelte';
import { assistantStore } from '$features/assistant/stores/assistant.svelte';
import { editorStore, isVoltVirtualPath } from '$features/editor/stores/editor.svelte';
import { problemsStore } from '$shared/stores/problems.svelte';
import { projectStore } from '$shared/stores/project.svelte';
import { terminalStore } from '$features/terminal/stores/terminal.svelte';
import { gitStore } from '$features/git/stores/git.svelte';
import { readFileQuiet } from '$core/services/file-system';
import { getEditorSelection } from '$core/services/monaco-models';
import { createContextBudget, estimateTextTokens, type ContextBudget, type ContextLane } from '$core/ai/context/context-budget';
import { buildHybridSemanticSnippets } from '$core/ai/retrieval/semantic-retrieval';
import {
  extractCursorWindow,
  extractQueryWindow,
  getLineCount,
  getLineWindow,
  scoreSnippetCandidate,
} from '$core/ai/context/context-v2-helpers';

export type ContextSource = 'editor' | 'disk';

export interface ContextSnippet {
  id: string;
  lane: ContextLane;
  path?: string;
  title: string;
  content: string;
  startLine?: number;
  endLine?: number;
  score: number;
  source: ContextSource;
  timestamp: number;
  stale: boolean;
  tokens: number;
}

export interface ContextV2 {
  query: string;
  builtAt: number;
  workspaceRoot?: string;
  activeFilePath?: string;
  workingSetSummary?: string;
  budget: ContextBudget;
  snippets: ContextSnippet[];
  diagnosticsSummary: string;
  runtimeSummary: string;
  insufficiencyHint?: string;
  stats: {
    estimatedTokensUsed: number;
    snippetsSelected: number;
    droppedCandidates: number;
    staleSnippetCount: number;
    freshSnippetCount: number;
    buildLatencyMs: number;
    fallbackUsed: boolean;
    semanticCandidates: number;
    semanticSelected: number;
    hybridDropped: number;
    semanticQueryMs: number;
    semanticIndexStalenessMs: number;
    semanticBackend: string;
    semanticModelLoadMs: number;
    semanticLastError?: string;
  };
}

export interface BuildContextV2Input {
  query?: string;
  modelId: string;
  workingSetSummary?: string;
}

interface SnippetDraft {
  lane: ContextLane;
  path?: string;
  title: string;
  content: string;
  startLine?: number;
  endLine?: number;
  score: number;
  source: ContextSource;
  timestamp: number;
  stale: boolean;
}

interface FileSnapshot {
  path: string;
  content: string;
  source: ContextSource;
  timestamp: number;
  stale: boolean;
}

interface CachedSnapshot {
  content: string;
  source: ContextSource;
  timestamp: number;
}

const snapshotCache = new Map<string, CachedSnapshot>();
const MAX_SNIPPETS = 16;
const MAX_FILES = 10;
function normalizePath(path: string): string {
  return path.replace(/\\/g, '/');
}

function toRelativePath(path: string, root?: string | null): string {
  const normalized = normalizePath(path);
  if (!root) return normalized;
  const rootNorm = normalizePath(root).replace(/\/$/, '');
  const lowerPath = normalized.toLowerCase();
  const lowerRoot = rootNorm.toLowerCase();
  if (lowerPath === lowerRoot) return '.';
  if (lowerPath.startsWith(`${lowerRoot}/`)) {
    return normalized.slice(rootNorm.length + 1);
  }
  return normalized;
}

function collectTouchedPaths(): string[] {
  const paths: string[] = [];
  const recentMessages = assistantStore.messages.slice(-140).reverse();
  for (const msg of recentMessages) {
    const toolCalls = [
      ...(msg.toolCalls ?? []),
      ...(msg.inlineToolCalls ?? []),
    ];
    for (const tc of toolCalls) {
      if (tc.status !== 'completed') continue;
      const toolName = String(tc.name || '');
      if (!/(apply_patch|str_replace|multi_replace|replace_lines|write_file|append_file|rename_path|delete_file)/.test(toolName)) {
        continue;
      }
      const metaPath = (tc.meta as Record<string, unknown> | undefined)?.fileEdit as Record<string, unknown> | undefined;
      const rel = typeof metaPath?.relativePath === 'string' ? String(metaPath.relativePath) : '';
      const argPath = typeof tc.arguments?.path === 'string' ? String(tc.arguments.path) : '';
      const candidate = normalizePath(rel || argPath);
      if (!candidate) continue;
      if (!paths.includes(candidate)) paths.push(candidate);
      if (paths.length >= 8) return paths;
    }
  }
  return paths;
}

async function loadSnapshot(path: string): Promise<FileSnapshot | null> {
  const normalized = normalizePath(path);
  const openFile = editorStore.openFiles.find((f) => normalizePath(f.path) === normalized);
  if (openFile) {
    const snap: FileSnapshot = {
      path: normalized,
      content: openFile.content,
      source: 'editor',
      timestamp: Date.now(),
      stale: false,
    };
    snapshotCache.set(normalized, {
      content: snap.content,
      source: snap.source,
      timestamp: snap.timestamp,
    });
    return snap;
  }

  try {
    const content = await readFileQuiet(path);
    if (typeof content !== 'string' || !content) return null;

    const cached = snapshotCache.get(normalized);
    const stale = cached ? cached.content !== content : false;
    const timestamp = Date.now();
    snapshotCache.set(normalized, { content, source: 'disk', timestamp });

    return {
      path: normalized,
      content,
      source: 'disk',
      timestamp,
      stale,
    };
  } catch {
    return null;
  }
}

function buildRuntimeSummary(): string {
  const terminals = terminalStore.sessions.slice(0, 4).map((s) => ({
    cwd: s.cwd || s.info.cwd,
    label: terminalStore.getSessionLabel(s.id),
  }));
  const payload = {
    time_utc: new Date().toISOString(),
    workspace: projectStore.rootPath || null,
    terminals,
    git: {
      isRepo: gitStore.isRepo,
      branch: gitStore.status?.branch ?? null,
      staged: gitStore.status?.staged.length ?? 0,
      unstaged: gitStore.status?.unstaged.length ?? 0,
      untracked: gitStore.status?.untracked.length ?? 0,
      conflicted: gitStore.status?.conflicted.length ?? 0,
    },
  };
  return JSON.stringify(payload, null, 2);
}

function buildDiagnosticsSummary(root?: string | null): string {
  const totalErrors = problemsStore.errorCount;
  const totalWarnings = problemsStore.warningCount;
  const hotFiles = problemsStore.filesWithProblems.slice(0, 5).map((path) => {
    const list = problemsStore.getProblemsForFile(path);
    const errors = list.filter((p) => p.severity === 'error').length;
    const warnings = list.filter((p) => p.severity === 'warning').length;
    return `${toRelativePath(path, root)} (E:${errors} W:${warnings})`;
  });
  const lines = [
    `Errors: ${totalErrors}`,
    `Warnings: ${totalWarnings}`,
  ];
  if (hotFiles.length > 0) lines.push(`Top files: ${hotFiles.join(', ')}`);
  return lines.join('\n');
}

function addDraft(
  drafts: SnippetDraft[],
  laneUsage: Record<ContextLane, number>,
  budget: ContextBudget,
  state: { totalTokens: number; dropped: number },
  draft: SnippetDraft,
): void {
  const content = draft.content.trim();
  if (!content) {
    state.dropped++;
    return;
  }
  const tokens = estimateTextTokens(content);
  if (tokens <= 0) {
    state.dropped++;
    return;
  }
  const laneBudget = budget.laneBudgets[draft.lane] ?? 0;
  if (laneUsage[draft.lane] + tokens > laneBudget || state.totalTokens + tokens > budget.availableContextTokens) {
    state.dropped++;
    return;
  }
  laneUsage[draft.lane] += tokens;
  state.totalTokens += tokens;
  drafts.push(draft);
}

export async function buildContextV2(input: BuildContextV2Input): Promise<ContextV2> {
  const startedAt = Date.now();
  const query = (input.query ?? '').trim();
  const workspaceRoot = projectStore.rootPath ?? undefined;
  const budget = createContextBudget(input.modelId);
  const drafts: SnippetDraft[] = [];
  const laneUsage: Record<ContextLane, number> = {
    active: 0,
    selection: 0,
    touched: 0,
    query: 0,
    imports: 0,
    diagnostics: 0,
    runtime: 0,
  };
  const state = { totalTokens: 0, dropped: 0 };
  let hybridStats: {
    semanticCandidates: number;
    semanticSelected: number;
    hybridDropped: number;
    semanticQueryMs: number;
    semanticIndexStalenessMs: number;
    semanticBackend: string;
    semanticModelLoadMs: number;
    semanticLastError?: string;
  } | null = null;

  const active = editorStore.activeFile && !isVoltVirtualPath(editorStore.activeFile.path)
    ? editorStore.activeFile
    : null;

  if (active) {
    const cursorLine = editorStore.cursorPosition.line || 1;
    const cursorWindow = extractCursorWindow(active.content, cursorLine);
    const queryWin = query ? extractQueryWindow(active.content, query) : null;
    addDraft(drafts, laneUsage, budget, state, {
      lane: 'active',
      path: toRelativePath(active.path, workspaceRoot),
      title: `Active file focus (${toRelativePath(active.path, workspaceRoot)})`,
      content: (queryWin?.content || cursorWindow.content).slice(0, 8000),
      startLine: queryWin?.startLine || cursorWindow.startLine,
      endLine: queryWin?.endLine || cursorWindow.endLine,
      score: scoreSnippetCandidate('active', queryWin?.hitCount ?? 0, 20),
      source: 'editor',
      timestamp: Date.now(),
      stale: false,
    });
  }

  const selection = getEditorSelection();
  if (selection?.text && selection.path) {
    addDraft(drafts, laneUsage, budget, state, {
      lane: 'selection',
      path: toRelativePath(selection.path, workspaceRoot),
      title: `Editor selection (${toRelativePath(selection.path, workspaceRoot)})`,
      content: selection.text.slice(0, 4000),
      startLine: selection.range?.startLineNumber,
      endLine: selection.range?.endLineNumber,
      score: scoreSnippetCandidate('selection', query ? 1 : 0, 30),
      source: 'editor',
      timestamp: Date.now(),
      stale: false,
    });
  }

  const touchedPaths = collectTouchedPaths();
  for (const path of touchedPaths.slice(0, MAX_FILES)) {
    const snapshot = await loadSnapshot(path);
    if (!snapshot) continue;
    const queryWin = query ? extractQueryWindow(snapshot.content, query) : null;
    const lineCount = getLineCount(snapshot.content);
    const startLine = queryWin?.startLine ?? 1;
    const endLine = queryWin?.endLine ?? Math.min(lineCount, 60);
    const snippetContent = queryWin?.content ?? getLineWindow(snapshot.content, startLine, endLine);
    addDraft(drafts, laneUsage, budget, state, {
      lane: 'touched',
      path: toRelativePath(snapshot.path, workspaceRoot),
      title: `Recently touched file (${toRelativePath(snapshot.path, workspaceRoot)})`,
      content: snippetContent.slice(0, 5000),
      startLine,
      endLine,
      score: scoreSnippetCandidate('touched', queryWin?.hitCount ?? 0),
      source: snapshot.source,
      timestamp: snapshot.timestamp,
      stale: snapshot.stale,
    });
  }

  const candidateOpenFiles = editorStore.openFiles
    .filter((f) => !isVoltVirtualPath(f.path))
    .slice(0, MAX_FILES);

  if (query) {
    for (const file of candidateOpenFiles) {
      if (active && normalizePath(file.path) === normalizePath(active.path)) continue;
      const queryWin = extractQueryWindow(file.content, query);
      if (!queryWin) continue;
      addDraft(drafts, laneUsage, budget, state, {
        lane: 'query',
        path: toRelativePath(file.path, workspaceRoot),
        title: `Query evidence (${toRelativePath(file.path, workspaceRoot)})`,
        content: queryWin.content.slice(0, 4000),
        startLine: queryWin.startLine,
        endLine: queryWin.endLine,
        score: scoreSnippetCandidate('query', queryWin.hitCount),
        source: 'editor',
        timestamp: Date.now(),
        stale: false,
      });
    }
  }

  if (active) {
    const importRegex = /from\s+['\"]([^'\"]+)['\"]/g;
    const importTargets: string[] = [];
    for (const match of active.content.matchAll(importRegex)) {
      const spec = match[1] || '';
      if (!spec.startsWith('.')) continue;
      importTargets.push(spec.split('/').pop() || spec);
    }
    for (const target of importTargets.slice(0, 3)) {
      const neighbor = candidateOpenFiles.find((f) => f.name.toLowerCase().includes(target.toLowerCase()));
      if (!neighbor) continue;
      const lineCount = getLineCount(neighbor.content);
      addDraft(drafts, laneUsage, budget, state, {
        lane: 'imports',
        path: toRelativePath(neighbor.path, workspaceRoot),
        title: `Import neighbor (${toRelativePath(neighbor.path, workspaceRoot)})`,
        content: getLineWindow(neighbor.content, 1, Math.min(50, lineCount)).slice(0, 3200),
        startLine: 1,
        endLine: Math.min(50, lineCount),
        score: scoreSnippetCandidate('imports', 0),
        source: 'editor',
        timestamp: Date.now(),
        stale: false,
      });
    }
  }

  const diagnosticFiles = problemsStore.filesWithProblems.slice(0, 4);
  for (const filePath of diagnosticFiles) {
    const snapshot = await loadSnapshot(filePath);
    if (!snapshot) continue;
    const problems = problemsStore.getProblemsForFile(filePath);
    const primary = problems.find((p) => p.severity === 'error') || problems[0];
    if (!primary) continue;
    const lineCount = getLineCount(snapshot.content);
    const startLine = Math.max(1, primary.line - 5);
    const endLine = Math.min(lineCount, primary.endLine + 5);
    addDraft(drafts, laneUsage, budget, state, {
      lane: 'diagnostics',
      path: toRelativePath(filePath, workspaceRoot),
      title: `Diagnostics focus (${toRelativePath(filePath, workspaceRoot)})`,
      content: getLineWindow(snapshot.content, startLine, endLine).slice(0, 2800),
      startLine,
      endLine,
      score: scoreSnippetCandidate('diagnostics', 0, 5),
      source: snapshot.source,
      timestamp: snapshot.timestamp,
      stale: snapshot.stale,
    });
  }

  // Hybrid semantic retrieval lane: lexical + semantic candidates, then strict budget gate.
  if (query && workspaceRoot) {
    const hybrid = await buildHybridSemanticSnippets({
      rootPath: workspaceRoot,
      query,
      touchedPaths: touchedPaths.map((p) => toRelativePath(p, workspaceRoot)),
      activePath: active ? toRelativePath(active.path, workspaceRoot) : undefined,
      diagnosticsPaths: diagnosticFiles.map((p) => toRelativePath(p, workspaceRoot)),
    });
    hybridStats = {
      semanticCandidates: hybrid.semanticCandidates,
      semanticSelected: hybrid.semanticSelected,
      hybridDropped: hybrid.hybridDropped,
      semanticQueryMs: hybrid.semanticQueryMs,
      semanticIndexStalenessMs: hybrid.semanticIndexStalenessMs,
      semanticBackend: hybrid.semanticBackend,
      semanticModelLoadMs: hybrid.semanticModelLoadMs,
      semanticLastError: hybrid.semanticLastError,
    };
    for (const semantic of hybrid.snippets) {
      addDraft(drafts, laneUsage, budget, state, {
        lane: semantic.lane,
        path: semantic.path,
        title: semantic.title,
        content: semantic.content.slice(0, 3600),
        startLine: semantic.startLine,
        endLine: semantic.endLine,
        score: semantic.score,
        source: semantic.source,
        timestamp: semantic.timestamp,
        stale: semantic.stale,
      });
    }
  }

  const ranked = drafts
    .sort((a, b) => b.score - a.score)
    .slice(0, MAX_SNIPPETS)
    .map((draft, index) => {
      const tokens = estimateTextTokens(draft.content);
      return {
        id: `ctxv2-${index + 1}`,
        lane: draft.lane,
        path: draft.path,
        title: draft.title,
        content: draft.content,
        startLine: draft.startLine,
        endLine: draft.endLine,
        score: draft.score,
        source: draft.source,
        timestamp: draft.timestamp,
        stale: draft.stale,
        tokens,
      } satisfies ContextSnippet;
    });

  const staleSnippetCount = ranked.filter((s) => s.stale).length;
  const freshSnippetCount = ranked.length - staleSnippetCount;
  const estimatedTokensUsed = ranked.reduce((sum, s) => sum + s.tokens, 0);

  const context: ContextV2 = {
    query,
    builtAt: Date.now(),
    workspaceRoot,
    activeFilePath: active ? toRelativePath(active.path, workspaceRoot) : undefined,
    workingSetSummary: input.workingSetSummary?.trim() || undefined,
    budget,
    snippets: ranked,
    diagnosticsSummary: buildDiagnosticsSummary(workspaceRoot),
    runtimeSummary: buildRuntimeSummary(),
    insufficiencyHint:
      ranked.length <= 1
        ? 'Context is intentionally minimal. If evidence is insufficient, use file_outline/read_file/read_code for targeted reads.'
        : undefined,
    stats: {
      estimatedTokensUsed,
      snippetsSelected: ranked.length,
      droppedCandidates: state.dropped,
      staleSnippetCount,
      freshSnippetCount,
      buildLatencyMs: Date.now() - startedAt,
      fallbackUsed: false,
      semanticCandidates: 0,
      semanticSelected: 0,
      hybridDropped: 0,
      semanticQueryMs: 0,
      semanticIndexStalenessMs: 0,
      semanticBackend: 'disabled',
      semanticModelLoadMs: 0,
    },
  };

  if (hybridStats) {
    context.stats.semanticCandidates = hybridStats.semanticCandidates;
    context.stats.semanticSelected = hybridStats.semanticSelected;
    context.stats.hybridDropped = hybridStats.hybridDropped;
    context.stats.semanticQueryMs = hybridStats.semanticQueryMs;
    context.stats.semanticIndexStalenessMs = hybridStats.semanticIndexStalenessMs;
    context.stats.semanticBackend = hybridStats.semanticBackend;
    context.stats.semanticModelLoadMs = hybridStats.semanticModelLoadMs;
    context.stats.semanticLastError = hybridStats.semanticLastError;
  }

  return context;
}

export function formatContextV2(context: ContextV2): string {
  const lines: string[] = [];
  lines.push('# CONTEXT V2');
  lines.push('Use this focused evidence pack. If missing details, run targeted read/search tools before editing.');
  if (context.workspaceRoot) lines.push(`Workspace: ${context.workspaceRoot}`);
  if (context.activeFilePath) lines.push(`Active file: ${context.activeFilePath}`);
  if (context.query) lines.push(`User query: ${context.query}`);
  if (context.workingSetSummary) {
    lines.push('## Compact Working Set');
    lines.push('```yaml');
    lines.push(context.workingSetSummary);
    lines.push('```');
  }
  lines.push(
    `Budget: ~${context.stats.estimatedTokensUsed}/${context.budget.availableContextTokens} context tokens; snippets=${context.stats.snippetsSelected}; dropped=${context.stats.droppedCandidates}`,
  );
  lines.push(
    `Hybrid retrieval: backend=${context.stats.semanticBackend}; semanticCandidates=${context.stats.semanticCandidates}; semanticSelected=${context.stats.semanticSelected}; hybridDropped=${context.stats.hybridDropped}; semanticQueryMs=${context.stats.semanticQueryMs}; modelLoadMs=${context.stats.semanticModelLoadMs}`,
  );

  lines.push('## Evidence Snippets');
  if (context.snippets.length === 0) {
    lines.push('- No snippets selected. Use focused tools (find_files/workspace_search/read_file/read_code).');
  } else {
    for (const s of context.snippets) {
      const pathPart = s.path ? ` path=${s.path}` : '';
      const rangePart =
        typeof s.startLine === 'number' && typeof s.endLine === 'number'
          ? ` lines=${s.startLine}-${s.endLine}`
          : '';
      lines.push(`### ${s.title}`);
      lines.push(`lane=${s.lane}${pathPart}${rangePart} source=${s.source} stale=${s.stale} score=${s.score}`);
      lines.push('```text');
      lines.push(s.content);
      lines.push('```');
    }
  }

  lines.push('## Diagnostics Summary');
  lines.push('```text');
  lines.push(context.diagnosticsSummary);
  lines.push('```');

  lines.push('## Runtime Summary');
  lines.push('```json');
  lines.push(context.runtimeSummary);
  lines.push('```');

  if (context.insufficiencyHint) {
    lines.push('## Context Hint');
    lines.push(context.insufficiencyHint);
  }

  return lines.join('\n');
}

export function buildMinimalContextFallback(query: string): string {
  const active = editorStore.activeFile && !isVoltVirtualPath(editorStore.activeFile.path)
    ? editorStore.activeFile
    : null;
  const selection = getEditorSelection();
  const root = projectStore.rootPath ?? null;
  const lines: string[] = [];
  lines.push('# CONTEXT V2 (Fallback)');
  lines.push('Focused context build failed; using minimal runtime/editor context.');
  if (root) lines.push(`Workspace: ${root}`);
  if (query.trim()) lines.push(`User query: ${query.trim()}`);
  if (active) lines.push(`Active file: ${toRelativePath(active.path, root)}`);
  if (selection?.path && selection?.range) {
    lines.push(`Selection: ${toRelativePath(selection.path, root)}:${selection.range.startLineNumber}-${selection.range.endLineNumber}`);
  }
  lines.push('Use targeted tools next: file_outline, read_code, read_file, workspace_search.');
  return lines.join('\n');
}

export function clearContextV2Cache(): void {
  snapshotCache.clear();
}

/**
 * ============================================================================
 * VOLT ADVANCED RAG CONTEXT ENGINE v3.0
 * ============================================================================
 *
 * LEGACY NOTE:
 * This module is intentionally retained for reference/back-compat history.
 * Active runtime context assembly now lives in context-v2.ts.
 * 
 * A production-grade context gathering system inspired by:
 * - Advanced: Sub-agents, semantic search, intelligent file discovery
 * - Cursor: Rules system, symbol extraction, smart truncation
 * - Claude Code: Hierarchical memory, project understanding
 * - GitHub Copilot: Relevance scoring, context prioritization
 * 
 * KEY FEATURES:
 * 1. Semantic Understanding - Understands code relationships, not just text
 * 2. Multi-Signal Relevance - Combines imports, symbols, recency, query match
 * 3. Intelligent Chunking - AST-aware truncation preserving structure
 * 4. Dependency Graph - Follows imports to find related code
 * 5. Symbol Extraction - Finds classes, functions, types across codebase
 * 6. Query Intent Analysis - Understands what user is asking for
 * 7. Budget Management - Prioritizes high-value context within limits
 * 8. Caching Layer - Avoids redundant file reads
 * 
 * ============================================================================
 */

import { editorStore } from '$features/editor/stores/editor.svelte';
import { projectStore } from '$shared/stores/project.svelte';
import { terminalStore } from '$features/terminal/stores/terminal.svelte';
import { problemsStore, type Problem } from '$shared/stores/problems.svelte';
import { activityStore } from '$shared/stores/activity.svelte';
import { gitStore } from '$features/git/stores/git.svelte';
import { readFileQuiet } from '$core/services/file-system';
import { contextEventsStore } from '$features/assistant/stores/context-events.svelte';

// ============================================================================
// TYPES
// ============================================================================

/** Extracted symbol from code */
export interface CodeSymbol {
  name: string;
  kind: 'class' | 'function' | 'interface' | 'type' | 'const' | 'variable' | 'enum' | 'method';
  line: number;
  exported: boolean;
  signature?: string;
}

/** File with full context metadata */
export interface ContextFile {
  path: string;
  content: string;
  relevanceScore: number;
  reasons: string[];
  symbols: CodeSymbol[];
  truncated: boolean;
  size: number;
}

/** Query intent classification */
export interface QueryIntent {
  type: 'explain' | 'fix' | 'implement' | 'refactor' | 'debug' | 'search' | 'general';
  keywords: string[];
  targetSymbols: string[];
  targetFiles: string[];
  needsTerminal: boolean;
  needsGit: boolean;
}

/** The main context object */
export interface SmartContext {
  /** Analyzed query intent */
  intent: QueryIntent;
  /** Project memory from VOLT.md */
  projectMemory?: string;
  /** Active file with full analysis */
  activeFile?: ContextFile;
  /** Related files sorted by relevance */
  relatedFiles: ContextFile[];
  /** Symbol index for quick lookup */
  symbolIndex: Map<string, { file: string; symbol: CodeSymbol }>;
  /** Terminal output if relevant */
  terminalOutput?: string;
  /** Git status if relevant */
  gitContext?: string;
  /** Diagnostic problems (errors, warnings) */
  problems?: string;
  /** Workspace root */
  workspaceRoot?: string;
  /** Files already in context (prevents re-reading) */
  filesInContext: Set<string>;
  /** Total context size */
  totalSize: number;
  /** Budget utilization percentage */
  budgetUsed: number;
}

// ============================================================================
// CONFIGURATION
// ============================================================================

const CONFIG = {
  /** Maximum context size in characters */
  MAX_CONTEXT_CHARS: 250_000,
  /** Reserved space for system prompt + response */
  RESERVED_CHARS: 30_000,
  /** Maximum files to include */
  MAX_FILES: 25,
  /** Maximum symbols to track */
  MAX_SYMBOLS: 200,
  /** Cache TTL in milliseconds */
  CACHE_TTL: 60_000,
  /** Budget allocation */
  BUDGET: {
    projectMemory: 0.03,
    activeFile: 0.30,
    relatedFiles: 0.50,
    terminal: 0.10,
    git: 0.07,
    problems: 0.15,
  },
  /** Per-file size limits */
  FILE_LIMITS: {
    activeFile: 50_000,
    relatedFile: 20_000,
    minUseful: 500,
  },
};

/** Patterns to exclude from context */
const EXCLUDED_PATTERNS = [
  'node_modules/', '.git/', 'dist/', 'build/', '.svelte-kit/',
  'target/', '.next/', '.nuxt/', 'coverage/', '__pycache__/',
  '.volt/agent/', 'src/lib/services/ai/', // Don't leak AI internals
  '.env', '.lock', '-lock.json',
];

/** Memory file locations (checked in order) */
const MEMORY_FILES = ['VOLT.md', '.volt/VOLT.md', '.volt/instructions.md', 'CLAUDE.md'];

/** File extensions we care about */
const CODE_EXTENSIONS = [
  '.ts', '.tsx', '.js', '.jsx', '.svelte', '.vue',
  '.rs', '.go', '.py', '.rb', '.java', '.kt',
  '.css', '.scss', '.html', '.json', '.yaml', '.yml', '.toml',
  '.md', '.mdx',
];

// ============================================================================
// CACHING LAYER
// ============================================================================

interface CacheEntry {
  content: string;
  symbols: CodeSymbol[];
  timestamp: number;
  size: number;
}

const fileCache = new Map<string, CacheEntry>();
const symbolCache = new Map<string, CodeSymbol[]>();

/** Clear all caches */
export function clearContextCache(): void {
  fileCache.clear();
  symbolCache.clear();
}

/** Invalidate specific file */
export function invalidateCacheEntry(path: string): void {
  fileCache.delete(path);
  symbolCache.delete(path);
}

/** Get file content with caching */
async function getCachedFile(path: string): Promise<CacheEntry | null> {
  // Check cache first
  const cached = fileCache.get(path);
  if (cached && Date.now() - cached.timestamp < CONFIG.CACHE_TTL) {
    return cached;
  }

  // Check editor store (most up-to-date for open files)
  const openFile = editorStore.openFiles.find(f => f.path === path);
  if (openFile) {
    const symbols = extractSymbols(openFile.content, path);
    const entry: CacheEntry = {
      content: openFile.content,
      symbols,
      timestamp: Date.now(),
      size: openFile.content.length,
    };
    fileCache.set(path, entry);
    return entry;
  }

  // Read from disk (use quiet version to avoid toast spam during context gathering)
  try {
    const content = await readFileQuiet(path);
    if (content) {
      const symbols = extractSymbols(content, path);
      const entry: CacheEntry = {
        content,
        symbols,
        timestamp: Date.now(),
        size: content.length,
      };
      fileCache.set(path, entry);
      return entry;
    }
  } catch {
    // File doesn't exist or can't be read
  }

  return null;
}

// ============================================================================
// SYMBOL EXTRACTION (AST-lite)
// ============================================================================

/** Extract symbols from code using regex patterns (fast, no AST parser needed) */
function extractSymbols(content: string, filePath: string): CodeSymbol[] {
  const symbols: CodeSymbol[] = [];
  const lines = content.split('\n');
  const ext = filePath.split('.').pop()?.toLowerCase();

  // TypeScript/JavaScript patterns
  if (['ts', 'tsx', 'js', 'jsx', 'svelte'].includes(ext || '')) {
    const patterns: Array<{ regex: RegExp; kind: CodeSymbol['kind'] }> = [
      { regex: /^(export\s+)?(async\s+)?function\s+(\w+)/m, kind: 'function' },
      { regex: /^(export\s+)?class\s+(\w+)/m, kind: 'class' },
      { regex: /^(export\s+)?interface\s+(\w+)/m, kind: 'interface' },
      { regex: /^(export\s+)?type\s+(\w+)/m, kind: 'type' },
      { regex: /^(export\s+)?enum\s+(\w+)/m, kind: 'enum' },
      { regex: /^(export\s+)?(const|let|var)\s+(\w+)\s*=/m, kind: 'const' },
      { regex: /^\s+(async\s+)?(\w+)\s*\([^)]*\)\s*[:{]/m, kind: 'method' },
    ];

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      for (const { regex, kind } of patterns) {
        const match = line.match(regex);
        if (match) {
          const exported = line.includes('export');
          const name = match[match.length - 1]; // Last capture group is the name
          if (name && name.length > 1 && !['if', 'for', 'while', 'switch'].includes(name)) {
            symbols.push({
              name,
              kind,
              line: i + 1,
              exported,
              signature: line.trim().slice(0, 100),
            });
          }
        }
      }
    }
  }

  // Rust patterns
  if (ext === 'rs') {
    const patterns: Array<{ regex: RegExp; kind: CodeSymbol['kind'] }> = [
      { regex: /^(pub\s+)?fn\s+(\w+)/m, kind: 'function' },
      { regex: /^(pub\s+)?struct\s+(\w+)/m, kind: 'class' },
      { regex: /^(pub\s+)?trait\s+(\w+)/m, kind: 'interface' },
      { regex: /^(pub\s+)?enum\s+(\w+)/m, kind: 'enum' },
      { regex: /^(pub\s+)?type\s+(\w+)/m, kind: 'type' },
      { regex: /^(pub\s+)?const\s+(\w+)/m, kind: 'const' },
    ];

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      for (const { regex, kind } of patterns) {
        const match = line.match(regex);
        if (match) {
          const exported = line.includes('pub');
          const name = match[2];
          if (name) {
            symbols.push({ name, kind, line: i + 1, exported, signature: line.trim().slice(0, 100) });
          }
        }
      }
    }
  }

  // Python patterns
  if (ext === 'py') {
    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      const classMatch = line.match(/^class\s+(\w+)/);
      const funcMatch = line.match(/^(async\s+)?def\s+(\w+)/);
      if (classMatch) {
        symbols.push({ name: classMatch[1], kind: 'class', line: i + 1, exported: true });
      }
      if (funcMatch) {
        symbols.push({ name: funcMatch[2], kind: 'function', line: i + 1, exported: !line.startsWith('  ') });
      }
    }
  }

  return symbols;
}

// ============================================================================
// QUERY INTENT ANALYSIS
// ============================================================================

/** Analyze user query to understand intent */
function analyzeQueryIntent(query: string): QueryIntent {
  const lowerQuery = query.toLowerCase();
  const words = lowerQuery.split(/\s+/);

  // Determine intent type
  let type: QueryIntent['type'] = 'general';
  if (/\b(explain|what|how|why|describe)\b/.test(lowerQuery)) type = 'explain';
  else if (/\b(fix|bug|error|issue|broken|wrong|fail)\b/.test(lowerQuery)) type = 'fix';
  else if (/\b(add|create|implement|build|make|write)\b/.test(lowerQuery)) type = 'implement';
  else if (/\b(refactor|improve|clean|optimize|simplify)\b/.test(lowerQuery)) type = 'refactor';
  else if (/\b(debug|trace|log|inspect|check)\b/.test(lowerQuery)) type = 'debug';
  else if (/\b(find|search|where|locate|look)\b/.test(lowerQuery)) type = 'search';

  // Extract potential symbol names (CamelCase, snake_case, UPPER_CASE)
  const symbolPattern = /\b([A-Z][a-zA-Z0-9]*|[a-z][a-zA-Z0-9]*_[a-zA-Z0-9_]*|[A-Z][A-Z0-9_]+)\b/g;
  const targetSymbols = [...new Set(query.match(symbolPattern) || [])].filter(s => s.length > 2);

  // Extract file references
  const filePattern = /\b[\w-]+\.(ts|js|svelte|rs|py|tsx|jsx|vue|go|css|html|json)\b/gi;
  const targetFiles = [...new Set(query.match(filePattern) || [])];

  // Extract meaningful keywords (filter common words)
  const stopWords = new Set(['the', 'a', 'an', 'is', 'are', 'was', 'were', 'be', 'been', 'being',
    'have', 'has', 'had', 'do', 'does', 'did', 'will', 'would', 'could', 'should', 'may', 'might',
    'must', 'can', 'this', 'that', 'these', 'those', 'i', 'you', 'he', 'she', 'it', 'we', 'they',
    'what', 'which', 'who', 'when', 'where', 'why', 'how', 'all', 'each', 'every', 'both', 'few',
    'more', 'most', 'other', 'some', 'such', 'no', 'nor', 'not', 'only', 'own', 'same', 'so',
    'than', 'too', 'very', 'just', 'and', 'but', 'if', 'or', 'because', 'as', 'until', 'while',
    'of', 'at', 'by', 'for', 'with', 'about', 'against', 'between', 'into', 'through', 'during',
    'before', 'after', 'above', 'below', 'to', 'from', 'up', 'down', 'in', 'out', 'on', 'off']);

  const keywords = words
    .filter(w => w.length > 2 && !stopWords.has(w))
    .slice(0, 15);

  return {
    type,
    keywords,
    targetSymbols,
    targetFiles,
    needsTerminal: /\b(error|terminal|run|build|test|npm|cargo|fail|output|log)\b/.test(lowerQuery),
    needsGit: /\b(git|commit|branch|diff|change|modified|staged)\b/.test(lowerQuery),
  };
}

// ============================================================================
// IMPORT/DEPENDENCY RESOLUTION
// ============================================================================

/** Extract and resolve imports from file content */
function resolveImports(content: string, currentPath: string, workspaceRoot: string): string[] {
  const imports: string[] = [];
  const sep = currentPath.includes('\\') ? '\\' : '/';
  const dir = currentPath.substring(0, currentPath.lastIndexOf(sep) + 1);

  // Match various import patterns
  const patterns = [
    /(?:import|export)\s+(?:[\w\s{},*]+\s+from\s+)?['"]([^'"]+)['"]/g,
    /require\s*\(\s*['"]([^'"]+)['"]\s*\)/g,
    /use\s+(?:crate::)?(\w+(?:::\w+)*)/g, // Rust
    /from\s+['"]([^'"]+)['"]\s+import/g, // Python
  ];

  for (const pattern of patterns) {
    let match;
    while ((match = pattern.exec(content)) !== null) {
      const importPath = match[1];
      if (!importPath) continue;

      // Skip node_modules/external imports
      if (!importPath.startsWith('.') && !importPath.startsWith('$lib') && !importPath.startsWith('@/')) {
        continue;
      }

      let resolved: string;

      // Helper: join path segments with the platform separator
      const join = (...segments: string[]) => segments.join(sep).replace(/[/\\]+/g, sep);

      if (importPath.startsWith('$lib')) {
        // SvelteKit $lib alias
        const rest = importPath.slice(4).replace(/\//g, sep);
        resolved = join(workspaceRoot, 'src', 'lib') + rest;
      } else if (importPath.startsWith('@/')) {
        // Common @ alias (src/)
        const rest = importPath.slice(2).replace(/\//g, sep);
        resolved = join(workspaceRoot, 'src') + sep + rest;
      } else {
        // Relative import
        const rest = importPath.replace(/\//g, sep);
        resolved = join(dir, rest);
      }

      // Normalize path (remove ./ and resolve ..)
      resolved = normalizePath(resolved);

      // Try to resolve extension
      if (!resolved.match(/\.\w+$/)) {
        const extensions = ['.ts', '.tsx', '.js', '.jsx', '.svelte', '.vue', '/index.ts', '/index.js'];
        for (const ext of extensions) {
          imports.push(resolved + ext);
        }
      } else {
        imports.push(resolved);
      }
    }
  }

  return [...new Set(imports)];
}

/** Normalize file path - handles Windows drive letters and UNC paths */
function normalizePath(path: string): string {
  // Detect the dominant separator
  const sep = path.includes('\\') ? '\\' : '/';

  // Normalize all separators to the dominant one first
  const normalized = path.replace(/[/\\]/g, sep);

  // Preserve Windows drive letter prefix (e.g., "C:")
  let prefix = '';
  let rest = normalized;

  // Handle UNC paths: \\server\share
  if (rest.startsWith(sep + sep)) {
    prefix = sep + sep;
    rest = rest.slice(2);
  }
  // Handle drive letter: C:\...
  else if (/^[A-Za-z]:/.test(rest)) {
    prefix = rest.slice(0, 2) + sep; // "C:\"
    rest = rest.slice(rest[2] === sep ? 3 : 2);
  }

  const parts = rest.split(sep);
  const result: string[] = [];

  for (const part of parts) {
    if (part === '..') {
      result.pop();
    } else if (part !== '.' && part !== '') {
      result.push(part);
    }
  }

  return prefix + result.join(sep);
}

/** Check if path should be excluded */
function isExcluded(path: string): boolean {
  return EXCLUDED_PATTERNS.some(pattern => path.includes(pattern));
}

/** Check if file has a code extension */
function isCodeFile(path: string): boolean {
  return CODE_EXTENSIONS.some(ext => path.endsWith(ext));
}

// ============================================================================
// RELEVANCE SCORING ENGINE
// ============================================================================

interface ScoringContext {
  query: string;
  intent: QueryIntent;
  activeFilePath?: string;
  activeFileImports: string[];
}

/** Calculate relevance score for a file */
function scoreFileRelevance(
  filePath: string,
  fileContent: string,
  symbols: CodeSymbol[],
  ctx: ScoringContext
): { score: number; reasons: string[] } {
  let score = 0;
  const reasons: string[] = [];
  const lowerPath = filePath.toLowerCase();
  const lowerContent = fileContent.toLowerCase();

  // 1. DIRECT FILE REFERENCE (highest priority)
  for (const targetFile of ctx.intent.targetFiles) {
    if (lowerPath.includes(targetFile.toLowerCase())) {
      score += 100;
      reasons.push(`Directly referenced: ${targetFile}`);
    }
  }

  // 2. SYMBOL MATCH (very high priority)
  for (const targetSymbol of ctx.intent.targetSymbols) {
    const matchingSymbol = symbols.find(s =>
      s.name.toLowerCase() === targetSymbol.toLowerCase() ||
      s.name.includes(targetSymbol) ||
      targetSymbol.includes(s.name)
    );
    if (matchingSymbol) {
      score += 80;
      reasons.push(`Contains symbol: ${matchingSymbol.name}`);
    }
  }

  // 3. IMPORT RELATIONSHIP (high priority)
  if (ctx.activeFileImports.some(imp => filePath.includes(imp.split(/[/\\]/).pop()?.replace(/\.\w+$/, '') || ''))) {
    score += 60;
    reasons.push('Imported by active file');
  }

  // 4. KEYWORD MATCHES IN PATH
  for (const keyword of ctx.intent.keywords) {
    if (lowerPath.includes(keyword)) {
      score += 25;
      reasons.push(`Path matches: ${keyword}`);
    }
  }

  // 5. KEYWORD MATCHES IN CONTENT (capped)
  let contentMatches = 0;
  for (const keyword of ctx.intent.keywords) {
    // Escape special regex characters in keyword
    const escapedKeyword = keyword.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    try {
      const regex = new RegExp(`\\b${escapedKeyword}\\b`, 'gi');
      const matches = lowerContent.match(regex);
      if (matches) {
        contentMatches += Math.min(matches.length, 10);
      }
    } catch {
      // If regex still fails, do simple string match
      if (lowerContent.includes(keyword)) {
        contentMatches += 1;
      }
    }
  }
  if (contentMatches > 0) {
    score += Math.min(contentMatches * 3, 40);
    reasons.push(`Content matches: ${contentMatches} keywords`);
  }

  // 6. RECENT ACTIVITY BONUS
  const recentIndex = activityStore.recentPaths.indexOf(filePath);
  if (recentIndex !== -1 && recentIndex < 10) {
    const bonus = 30 - recentIndex * 3;
    score += bonus;
    reasons.push(`Recently accessed (#${recentIndex + 1})`);
  }

  // 7. OPEN TAB BONUS
  if (editorStore.openFiles.some(f => f.path === filePath)) {
    score += 20;
    reasons.push('Open in editor');
  }

  // 8. FILE TYPE RELEVANCE
  if (filePath.endsWith('.svelte') || filePath.endsWith('.tsx') || filePath.endsWith('.vue')) {
    score += 5; // UI components often important
  }
  if (filePath.includes('store') || filePath.includes('service') || filePath.includes('util')) {
    score += 5; // Core logic files
  }

  // 9. EXPORTED SYMBOLS BONUS
  const exportedCount = symbols.filter(s => s.exported).length;
  if (exportedCount > 0) {
    score += Math.min(exportedCount * 2, 15);
  }

  // 10. SIZE PENALTY (prefer focused files)
  if (fileContent.length > 20000) score -= 10;
  if (fileContent.length > 50000) score -= 20;

  return { score, reasons };
}

// ============================================================================
// INTELLIGENT CONTENT TRUNCATION
// ============================================================================

interface TruncationOptions {
  maxChars: number;
  query?: string;
  cursorLine?: number;
  preserveSymbols?: boolean;
}

/** Intelligently truncate content while preserving structure */
function truncateContent(content: string, options: TruncationOptions): { content: string; truncated: boolean } {
  const { maxChars, query, cursorLine, preserveSymbols = true } = options;

  if (content.length <= maxChars) {
    return { content, truncated: false };
  }

  const lines = content.split('\n');
  const keepLines = new Set<number>();
  const lineScores = new Map<number, number>();

  // Score each line
  for (let i = 0; i < lines.length; i++) {
    let score = 0;
    const line = lines[i];
    const trimmed = line.trim();

    // Imports/exports always important
    if (/^(import|export|from|use|require)/.test(trimmed)) {
      score += 100;
    }

    // Symbol definitions
    if (preserveSymbols && /^(export\s+)?(async\s+)?(function|class|interface|type|enum|const|let|pub\s+fn|struct|trait|def)\s+\w+/.test(trimmed)) {
      score += 80;
    }

    // Query keyword matches
    if (query) {
      const keywords = query.toLowerCase().split(/\s+/).filter(k => k.length > 2);
      for (const kw of keywords) {
        if (line.toLowerCase().includes(kw)) {
          score += 30;
        }
      }
    }

    // Cursor proximity
    if (cursorLine !== undefined) {
      const distance = Math.abs(i - cursorLine);
      if (distance < 50) {
        score += 50 - distance;
      }
    }

    // Comments with TODO/FIXME/NOTE
    if (/\/\/\s*(TODO|FIXME|NOTE|HACK|XXX)/i.test(line)) {
      score += 20;
    }

    lineScores.set(i, score);
  }

  // Always keep first N lines (imports)
  const importEnd = Math.min(40, lines.length);
  for (let i = 0; i < importEnd; i++) {
    keepLines.add(i);
  }

  // Always keep last few lines
  for (let i = Math.max(0, lines.length - 10); i < lines.length; i++) {
    keepLines.add(i);
  }

  // Add high-scoring lines
  const sortedByScore = [...lineScores.entries()]
    .sort((a, b) => b[1] - a[1])
    .slice(0, 200);

  for (const [lineNum] of sortedByScore) {
    keepLines.add(lineNum);
    // Add context around important lines
    for (let j = Math.max(0, lineNum - 3); j <= Math.min(lines.length - 1, lineNum + 3); j++) {
      keepLines.add(j);
    }
  }

  // Build result with truncation markers
  const sortedLines = [...keepLines].sort((a, b) => a - b);
  let result = '';
  let lastLine = -1;
  let currentSize = 0;

  for (const lineNum of sortedLines) {
    if (currentSize > maxChars) break;

    if (lastLine !== -1 && lineNum > lastLine + 1) {
      const gap = lineNum - lastLine - 1;
      if (gap > 0) {
        const marker = `\n/* ... ${gap} lines omitted ... */\n`;
        result += marker;
        currentSize += marker.length;
      }
    }

    const lineContent = lines[lineNum] + '\n';
    result += lineContent;
    currentSize += lineContent.length;
    lastLine = lineNum;
  }

  return { content: result.trim(), truncated: true };
}

// ============================================================================
// FILE DISCOVERY ENGINE
// ============================================================================

interface FileCandidate {
  path: string;
  content: string;
  symbols: CodeSymbol[];
  score: number;
  reasons: string[];
}

/** Discover relevant files beyond just open tabs */
async function discoverRelevantFiles(
  ctx: ScoringContext,
  workspaceRoot: string,
  alreadyIncluded: Set<string>
): Promise<FileCandidate[]> {
  const candidates: FileCandidate[] = [];

  // 1. Open tabs (already loaded, high priority)
  for (const file of editorStore.openFiles) {
    if (alreadyIncluded.has(file.path)) continue;
    if (isExcluded(file.path)) continue;

    const symbols = extractSymbols(file.content, file.path);
    const { score, reasons } = scoreFileRelevance(file.path, file.content, symbols, ctx);

    candidates.push({
      path: file.path,
      content: file.content,
      symbols,
      score,
      reasons,
    });
  }

  // 2. Imports from active file
  for (const importPath of ctx.activeFileImports) {
    if (alreadyIncluded.has(importPath)) continue;
    if (isExcluded(importPath)) continue;

    const cached = await getCachedFile(importPath);
    if (cached) {
      const { score, reasons } = scoreFileRelevance(importPath, cached.content, cached.symbols, ctx);
      candidates.push({
        path: importPath,
        content: cached.content,
        symbols: cached.symbols,
        score: score + 30, // Bonus for being imported
        reasons: [...reasons, 'Imported by active file'],
      });
    }
  }

  // 3. Recent files (scoped to current workspace)
  for (const recentPath of activityStore.recentPaths.slice(0, 15)) {
    if (workspaceRoot && !recentPath.startsWith(workspaceRoot)) continue;
    if (alreadyIncluded.has(recentPath)) continue;
    if (isExcluded(recentPath)) continue;
    if (!isCodeFile(recentPath)) continue;

    const cached = await getCachedFile(recentPath);
    if (cached) {
      const { score, reasons } = scoreFileRelevance(recentPath, cached.content, cached.symbols, ctx);
      candidates.push({
        path: recentPath,
        content: cached.content,
        symbols: cached.symbols,
        score,
        reasons,
      });
    }
  }

  // 4. Symbol-based discovery (find files containing target symbols)
  if (ctx.intent.targetSymbols.length > 0 && workspaceRoot) {
    const symbolFiles = await findFilesWithSymbols(ctx.intent.targetSymbols, workspaceRoot, alreadyIncluded);
    for (const sf of symbolFiles) {
      if (!candidates.some(c => c.path === sf.path)) {
        candidates.push(sf);
      }
    }
  }

  // 5. Keyword-based file discovery
  if (ctx.intent.keywords.length > 0 && workspaceRoot) {
    const keywordFiles = await findFilesByKeywords(ctx.intent.keywords, workspaceRoot, alreadyIncluded);
    for (const kf of keywordFiles) {
      if (!candidates.some(c => c.path === kf.path)) {
        candidates.push(kf);
      }
    }
  }

  // Sort by score and deduplicate
  return candidates
    .sort((a, b) => b.score - a.score)
    .filter((c, i, arr) => arr.findIndex(x => x.path === c.path) === i);
}

/** Find files containing specific symbols */
async function findFilesWithSymbols(
  symbols: string[],
  workspaceRoot: string,
  exclude: Set<string>
): Promise<FileCandidate[]> {
  const results: FileCandidate[] = [];

  // Check cached files first
  for (const [path, entry] of fileCache.entries()) {
    if (exclude.has(path)) continue;

    for (const symbol of symbols) {
      const match = entry.symbols.find(s =>
        s.name.toLowerCase().includes(symbol.toLowerCase()) ||
        symbol.toLowerCase().includes(s.name.toLowerCase())
      );
      if (match) {
        results.push({
          path,
          content: entry.content,
          symbols: entry.symbols,
          score: 70,
          reasons: [`Contains symbol: ${match.name}`],
        });
        break;
      }
    }
  }

  return results.slice(0, 5);
}

/** Find files by keyword in path */
async function findFilesByKeywords(
  keywords: string[],
  workspaceRoot: string,
  exclude: Set<string>
): Promise<FileCandidate[]> {
  const results: FileCandidate[] = [];

  // Check cached files
  for (const [path, entry] of fileCache.entries()) {
    if (exclude.has(path)) continue;

    const lowerPath = path.toLowerCase();
    for (const keyword of keywords) {
      if (lowerPath.includes(keyword.toLowerCase())) {
        results.push({
          path,
          content: entry.content,
          symbols: entry.symbols,
          score: 40,
          reasons: [`Path contains: ${keyword}`],
        });
        break;
      }
    }
  }

  return results.slice(0, 5);
}

// ============================================================================
// TERMINAL & GIT CONTEXT
// ============================================================================

/** Get recent terminal output */
function getTerminalContext(maxChars: number): string | undefined {
  const workspaceRoot = projectStore.rootPath;
  const sessions = terminalStore.sessions.filter(s => {
    if (!workspaceRoot) return true;
    const cwd = s.cwd || s.info.cwd || '';
    return cwd.includes(workspaceRoot);
  });

  if (sessions.length === 0) return undefined;

  let output = '';
  const perSession = Math.floor(maxChars / sessions.length);

  for (const session of sessions) {
    const sessionOutput = session.getRecentOutput(perSession);
    if (sessionOutput.trim()) {
      output += `═══ Terminal: ${session.id} ═══\n`;
      output += sessionOutput.trim();
      output += '\n\n';
    }
  }

  return output.trim() || undefined;
}

/** Get diagnostic problems from the store */
function getProblemsContext(maxChars: number): string | undefined {
  const problemsByFile = problemsStore.problemsByFile;
  const workspaceRoot = projectStore.rootPath;
  const files = Object.keys(problemsByFile).filter(file => {
    if (!workspaceRoot) return true;
    return file.includes(workspaceRoot);
  });

  if (files.length === 0) return undefined;

  let output = '';
  // Prioritize errors
  const sortedFiles = files.sort((a, b) => {
    const aErrors = problemsByFile[a].filter(p => p.severity === 'error').length;
    const bErrors = problemsByFile[b].filter(p => p.severity === 'error').length;
    return bErrors - aErrors;
  });

  for (const file of sortedFiles) {
    const problems = problemsByFile[file];
    const relPath = file.split(/[/\\]/).pop() || file;
    let fileOutput = `\nFile: ${relPath}\n`;

    for (const prob of problems) {
      const line = `  [${prob.severity.toUpperCase()}] line ${prob.line}, col ${prob.column}: ${prob.message} (${prob.source})\n`;
      if (output.length + fileOutput.length + line.length > maxChars) break;
      fileOutput += line;
    }

    if (fileOutput.length > `\nFile: ${relPath}\n`.length) {
      output += fileOutput;
    }

    if (output.length >= maxChars) break;
  }

  return output.trim() || undefined;
}

/** Get git context (status, recent changes) from the live gitStore */
function getGitContext(workspaceRoot: string, maxChars: number): string | undefined {
  // Use the live gitStore which already tracks git state reactively
  if (!gitStore.isRepo || !gitStore.status) return undefined;

  const status = gitStore.status;
  let output = '';

  // Branch info
  if (status.branch) {
    output += `Branch: ${status.branch}`;
    if (status.upstream) {
      output += ` → ${status.upstream}`;
      if (status.ahead > 0 || status.behind > 0) {
        const parts: string[] = [];
        if (status.ahead > 0) parts.push(`${status.ahead} ahead`);
        if (status.behind > 0) parts.push(`${status.behind} behind`);
        output += ` (${parts.join(', ')})`;
      }
    }
    output += '\n';
  }

  // Staged changes
  if (status.staged.length > 0) {
    output += `\nStaged (${status.staged.length}):\n`;
    for (const file of status.staged.slice(0, 15)) {
      output += `  + ${file.status} ${file.path}\n`;
      if (output.length > maxChars) break;
    }
    if (status.staged.length > 15) {
      output += `  ... and ${status.staged.length - 15} more\n`;
    }
  }

  // Unstaged changes
  if (status.unstaged.length > 0) {
    output += `\nModified (${status.unstaged.length}):\n`;
    for (const file of status.unstaged.slice(0, 15)) {
      output += `  ~ ${file.status} ${file.path}\n`;
      if (output.length > maxChars) break;
    }
    if (status.unstaged.length > 15) {
      output += `  ... and ${status.unstaged.length - 15} more\n`;
    }
  }

  // Untracked files
  if (status.untracked.length > 0) {
    output += `\nUntracked (${status.untracked.length}):\n`;
    for (const file of status.untracked.slice(0, 10)) {
      output += `  ? ${file.path}\n`;
      if (output.length > maxChars) break;
    }
    if (status.untracked.length > 10) {
      output += `  ... and ${status.untracked.length - 10} more\n`;
    }
  }

  // Conflicts
  if (status.conflicted.length > 0) {
    output += `\n⚠️ CONFLICTS (${status.conflicted.length}):\n`;
    for (const file of status.conflicted) {
      output += `  !! ${file.path}\n`;
    }
  }

  return output.trim() || undefined;
}

