/**
 * OpenAI Provider
 * 
 * Supports GPT-5 series with Thinking modes
 */

import type {
    AIProvider,
    ChatRequest,
    ChatResponse,
    StreamChunk,
} from '$core/ai/types';
import { invoke, Channel } from '@tauri-apps/api/core';
import { computeNovelStreamText } from './stream-dedupe';

const OPENAI_THINKING_SUFFIX = '|thinking';
const LOCAL_CODEX_PROXY_BASE_URL = 'http://localhost:8317/v1';
const LOCAL_CODEX_PROXY_API_KEY = 'dummy-key';

type ReasoningEffort = 'none' | 'low' | 'medium' | 'high' | 'xhigh';

interface OpenAIRequest {
    model: string;
    messages: any[];
    stream?: boolean;
    tools?: any[];
    max_completion_tokens?: number;
    temperature?: number;
    thinking?: {
        enabled: boolean;
        time_limit?: number;
    };
    reasoning_effort?: ReasoningEffort;
}

interface OpenAIMessage {
    role: 'system' | 'user' | 'assistant' | 'tool';
    content?: string | OpenAIContentPart[];
    name?: string;
    tool_calls?: Array<{
        id: string;
        type: 'function';
        function: {
            name: string;
            arguments: string;
        };
    }>;
    tool_call_id?: string;
}

interface OpenAIContentPart {
    type: 'text' | 'image_url';
    text?: string;
    image_url?: {
        url: string;
        detail?: 'auto';
    };
}

function isReasoningModel(model: string): boolean {
    return model.endsWith(OPENAI_THINKING_SUFFIX);
}

interface OpenAIChoice {
    message?: {
        content?: string | null;
        tool_calls?: Array<{
            id: string;
            function: {
                name: string;
                arguments: string;
            };
        }>;
    };
    delta?: {
        content?: string | null;
        tool_calls?: Array<{
            index?: number;
            id?: string;
            function?: {
                name?: string;
                arguments?: string;
            };
        }>;
        reasoning_content?: string | null;
    };
    finish_reason?: string | null;
}

interface OpenAIResponse {
    choices?: OpenAIChoice[];
    usage?: {
        prompt_tokens?: number;
        completion_tokens?: number;
        total_tokens?: number;
    };
    error?: {
        message?: string;
        code?: string | number;
    };
}

function extractStreamContent(choice: OpenAIChoice): string {
    if (typeof choice.delta?.content === 'string' && choice.delta.content.length > 0) {
        return choice.delta.content;
    }

    if (typeof choice.message?.content === 'string' && choice.message.content.length > 0) {
        return choice.message.content;
    }

    return '';
}

function toOpenAIMessageText(message: ChatRequest['messages'][number]): string {
    if (message.content?.trim()) return message.content;
    if (!message.parts?.length) return '';

    const textParts = message.parts
        .filter((part) => part.type === 'text' || part.type === 'thinking')
        .map((part) => part.text);

    return textParts.join('\n').trim();
}

function toOpenAIContentParts(message: ChatRequest['messages'][number]): OpenAIContentPart[] {
    const contentParts: OpenAIContentPart[] = [];

    if (!message.parts?.length) {
        const text = message.content?.trim();
        return text ? [{ type: 'text', text }] : [];
    }

    for (const part of message.parts) {
        if (part.type === 'text' || part.type === 'thinking') {
            if (part.text.trim()) {
                contentParts.push({ type: 'text', text: part.text });
            }
            continue;
        }

        if (part.type === 'image') {
            contentParts.push({
                type: 'image_url',
                image_url: {
                    url: `data:${part.mimeType};base64,${part.data}`,
                    detail: 'auto',
                },
            });
        }
    }

    return contentParts;
}

export function toOpenAIMessages(messages: ChatRequest['messages'], systemPrompt?: string): OpenAIMessage[] {
    const result: OpenAIMessage[] = [];
    const seenToolCallIds = new Set<string>();
    const consumedToolCallIds = new Set<string>();

    if (systemPrompt?.trim()) {
        result.push({ role: 'system', content: systemPrompt.trim() });
    }

    for (const message of messages) {
        const functionCalls = message.parts?.filter((part) => part.type === 'function_call') ?? [];
        const functionResponses = message.parts?.filter((part) => part.type === 'function_response') ?? [];
        const textContent = toOpenAIMessageText(message);

        if (functionCalls.length > 0) {
            for (const part of functionCalls) {
                if (part.id?.trim()) {
                    seenToolCallIds.add(part.id);
                }
            }
            result.push({
                role: 'assistant',
                content: textContent || '',
                tool_calls: functionCalls.map((part) => ({
                    id: part.id,
                    type: 'function',
                    function: {
                        name: part.name,
                        arguments: JSON.stringify(part.arguments ?? {}),
                    },
                })),
            });
            continue;
        }

        if (functionResponses.length > 0) {
            for (const part of functionResponses) {
                const toolCallId = part.id?.trim();
                if (!toolCallId || !seenToolCallIds.has(toolCallId) || consumedToolCallIds.has(toolCallId)) {
                    continue;
                }
                result.push({
                    role: 'tool',
                    name: part.name,
                    tool_call_id: toolCallId,
                    content: JSON.stringify(part.response ?? {}),
                });
                consumedToolCallIds.add(toolCallId);
            }
            continue;
        }

        const contentParts = toOpenAIContentParts(message);
        if (contentParts.length === 0) continue;

        const content =
            contentParts.length === 1 && contentParts[0].type === 'text'
                ? contentParts[0].text ?? ''
                : contentParts;
        result.push({
            role: message.role === 'system' ? 'system' : message.role === 'assistant' ? 'assistant' : 'user',
            content,
        });
    }

    return result;
}

function mapOpenAIError(response: Response, data?: OpenAIResponse | null, fallback?: string): string {
    const proxyMessage = data?.error?.message?.trim();
    if (proxyMessage) {
        return `Codex proxy error (Status ${response.status} ${response.statusText}): ${proxyMessage}`;
    }
    if (fallback?.trim()) {
        return `Codex proxy error (Status ${response.status} ${response.statusText}): ${fallback.trim()}`;
    }
    return `Codex proxy error (Status ${response.status} ${response.statusText})`;
}

async function parseProxyJson(response: Response): Promise<OpenAIResponse> {
    const raw = await response.text();
    if (!raw.trim()) {
        throw new Error('Codex proxy returned an empty response body.');
    }

    try {
        return JSON.parse(raw) as OpenAIResponse;
    } catch {
        throw new Error(`Codex proxy returned malformed JSON: ${raw.slice(0, 400)}`);
    }
}

function extractChoiceMessage(data: OpenAIResponse): OpenAIChoice {
    const choice = data.choices?.[0];
    if (!choice) {
        throw new Error('Codex proxy returned no choices.');
    }
    return choice;
}

async function fetchLocalCodexProxy(body: OpenAIRequest, signal?: AbortSignal): Promise<OpenAIResponse> {
    const response = await fetch(`${LOCAL_CODEX_PROXY_BASE_URL}/chat/completions`, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${LOCAL_CODEX_PROXY_API_KEY}`,
        },
        body: JSON.stringify(body),
        signal,
    });

    const data = await parseProxyJson(response);
    if (!response.ok || data.error) {
        throw new Error(mapOpenAIError(response, data));
    }
    return data;
}

function buildOpenAIRequest(request: ChatRequest): OpenAIRequest {
    const thinking = isReasoningModel(request.model);
    const baseModel = thinking ? request.model.slice(0, -OPENAI_THINKING_SUFFIX.length) : request.model;

    const body: OpenAIRequest = {
        model: baseModel,
        messages: toOpenAIMessages(request.messages, request.systemPrompt),
        max_completion_tokens: request.maxTokens,
        temperature: thinking ? undefined : request.temperature,
        reasoning_effort: request.reasoningEffort,
    };

    if (thinking) {
        body.temperature = undefined;
    }

    if (request.tools && request.tools.length > 0) {
        body.tools = request.tools.map((t) => ({
            type: 'function',
            function: {
                name: t.name,
                description: t.description,
                parameters: t.parameters,
            },
        }));
    }

    if (!body.messages.length) {
        body.messages = [{ role: 'user', content: 'Please continue.' }];
    }

    return body;
}

function parseToolArguments(raw: string): Record<string, unknown> {
    try {
        return raw ? JSON.parse(raw) : {};
    } catch {
        return {};
    }
}

function getStreamedToolArguments(raw: string): {
    arguments: Record<string, unknown>;
    complete: boolean;
} {
    const trimmed = raw.trim();
    if (!trimmed) {
        return { arguments: {}, complete: false };
    }

    try {
        return {
            arguments: JSON.parse(trimmed) as Record<string, unknown>,
            complete: true,
        };
    } catch {
        return { arguments: {}, complete: false };
    }
}

export async function validateOpenAIKey(apiKey: string): Promise<{ success: boolean; error?: string }> {
    try {
        await fetchLocalCodexProxy({
            model: 'gpt-5.4',
            max_completion_tokens: 1,
            messages: [{ role: 'user', content: 'Hi' }],
        });
        return { success: true };
    } catch (err) {
        return { success: false, error: String(err) };
    }
}

export const openaiProvider: AIProvider = {
    id: 'openai',
    name: 'OpenAI',
    capabilities: {
        supportsStreaming: true,
        supportsTools: true,
        supportsJsonSchema: true,
        maxContextHint: 1000000
    },

    async sendChat(request: ChatRequest, apiKey: string, signal?: AbortSignal): Promise<ChatResponse> {
        const body = buildOpenAIRequest(request);
        const data = await fetchLocalCodexProxy(body, signal);
        const choice = extractChoiceMessage(data);
        const usage = data.usage &&
            typeof data.usage.prompt_tokens === 'number' &&
            typeof data.usage.completion_tokens === 'number' &&
            typeof data.usage.total_tokens === 'number'
            ? {
                promptTokens: data.usage.prompt_tokens,
                completionTokens: data.usage.completion_tokens,
                totalTokens: data.usage.total_tokens,
            }
            : undefined;
        return {
            content: choice.message?.content || '',
            toolCalls: choice.message?.tool_calls?.map((tc) => ({
                id: tc.id,
                name: tc.function.name,
                arguments: parseToolArguments(tc.function.arguments)
            })),
            finishReason: choice.finish_reason === 'tool_calls' ? 'tool_calls' : 'stop',
            usage
        };
    },

    async *streamChat(request: ChatRequest, apiKey: string, signal?: AbortSignal): AsyncGenerator<StreamChunk> {
        const reasoningEnabled = isReasoningModel(request.model);
        const body = {
            ...buildOpenAIRequest(request),
            stream: true,
        } satisfies OpenAIRequest;

        const response = await fetch(`${LOCAL_CODEX_PROXY_BASE_URL}/chat/completions`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${LOCAL_CODEX_PROXY_API_KEY}`,
            },
            body: JSON.stringify(body),
            signal,
        });

        if (!response.ok) {
            let data: OpenAIResponse | null = null;
            let raw = '';
            try {
                raw = await response.text();
                data = raw.trim() ? JSON.parse(raw) as OpenAIResponse : null;
            } catch {
                data = null;
            }
            yield { type: 'error', error: mapOpenAIError(response, data, raw) };
            return;
        }

        if (!response.body) {
            yield { type: 'error', error: 'Codex proxy returned no streaming body.' };
            return;
        }

        const reader = response.body.getReader();
        const decoder = new TextDecoder();
        const pendingToolCalls = new Map<
            number,
            {
                id: string;
                name: string;
                arguments: string;
                emittedPartial: boolean;
                emittedArgsKey: string | null;
                emittedFinal: boolean;
            }
        >();
        let buffer = '';
        let accumulatedContent = '';

        try {
            while (true) {
                const { done, value } = await reader.read();
                if (done) break;

                buffer += decoder.decode(value, { stream: true });
                const lines = buffer.split(/\r?\n/);
                buffer = lines.pop() ?? '';

                for (const rawLine of lines) {
                    const trimmed = rawLine.trim();
                    if (!trimmed || !trimmed.startsWith('data:')) continue;

                    const jsonStr = trimmed.slice(5).trim();
                    if (!jsonStr) continue;
                    if (jsonStr === '[DONE]') continue;

                    let event: OpenAIResponse;
                    try {
                        event = JSON.parse(jsonStr) as OpenAIResponse;
                    } catch {
                        yield {
                            type: 'error',
                            error: `Codex proxy returned malformed SSE JSON: ${jsonStr.slice(0, 400)}`,
                        };
                        return;
                    }

                    if (event.error) {
                        yield {
                            type: 'error',
                            error: event.error.message || 'Codex proxy streaming error',
                        };
                        return;
                    }

                    const choice = event.choices?.[0];
                    if (!choice) continue;

                    const streamedContent = extractStreamContent(choice);
                    if (streamedContent) {
                        const next = computeNovelStreamText(streamedContent, accumulatedContent);
                        accumulatedContent = next.nextAccumulated;
                        if (next.novel) {
                            yield { type: 'content', content: next.novel };
                        }
                    }

                    if (reasoningEnabled && choice.delta?.reasoning_content) {
                        yield { type: 'thinking', thinking: choice.delta.reasoning_content };
                    }

                    if (Array.isArray(choice.delta?.tool_calls)) {
                        for (const call of choice.delta.tool_calls) {
                            const idx = call.index ?? 0;
                            if (!pendingToolCalls.has(idx)) {
                                pendingToolCalls.set(idx, {
                                    id: call.id || `call_${Date.now()}_${idx}`,
                                    name: '',
                                    arguments: '',
                                    emittedPartial: false,
                                    emittedArgsKey: null,
                                    emittedFinal: false,
                                });
                            }

                            const pending = pendingToolCalls.get(idx)!;
                            if (call.id) pending.id = call.id;
                            if (call.function?.name) pending.name = call.function.name;
                            if (call.function?.arguments) pending.arguments += call.function.arguments;

                            if (!pending.name) {
                                continue;
                            }

                            const parsed = getStreamedToolArguments(pending.arguments);
                            const argsKey = JSON.stringify(parsed.arguments);
                            const shouldEmit =
                                !pending.emittedPartial ||
                                argsKey !== pending.emittedArgsKey;

                            if (!shouldEmit) {
                                continue;
                            }

                            yield {
                                type: 'tool_call',
                                partial: true,
                                toolCall: {
                                    id: pending.id,
                                    name: pending.name,
                                    arguments: parsed.arguments,
                                },
                            };

                            pending.emittedPartial = true;
                            pending.emittedArgsKey = argsKey;
                            pending.emittedFinal = false;
                        }
                    }
                }
            }
        } finally {
            reader.releaseLock();
        }

        for (const [, pending] of pendingToolCalls) {
            if (!pending.name) continue;
            const parsed = getStreamedToolArguments(pending.arguments);
            yield {
                type: 'tool_call',
                partial: false,
                toolCall: {
                    id: pending.id,
                    name: pending.name,
                    arguments: parsed.complete ? parsed.arguments : parseToolArguments(pending.arguments),
                },
            };
        }

        yield { type: 'done' };
    },

    validateKey: validateOpenAIKey
};

/**
 * OpenRouter AI Provider
 * 
 * OpenRouter provides access to multiple AI models through a single API.
 * API is OpenAI-compatible with some extensions.
 * 
 * Docs: https://openrouter.ai/docs/api-reference/overview
 * Free models: Qwen3, GLM, StepFun, etc.
 */

import type {
  AIProvider,
  ChatRequest,
  ChatResponse,
  StreamChunk,
  ChatMessage,
  ToolDefinition,
  ToolCall,
  ProviderCapabilities
} from '$core/ai/types';
import { getModelConfig } from '$core/ai/models';
import { invoke, Channel } from '@tauri-apps/api/core';

const OPENROUTER_API_BASE = 'https://openrouter.ai/api/v1';

// OpenRouter request types (OpenAI-compatible)
interface OpenRouterMessage {
  role: 'system' | 'user' | 'assistant' | 'tool';
  content: string | OpenRouterContentPart[];
  name?: string;
  tool_calls?: OpenRouterToolCall[];
  tool_call_id?: string;
}

interface OpenRouterContentPart {
  type: 'text' | 'image_url';
  text?: string;
  image_url?: {
    url: string;
    detail?: string;
  };
}

interface OpenRouterToolCall {
  id: string;
  type: 'function';
  function: {
    name: string;
    arguments: string; // JSON string
  };
}

interface OpenRouterTool {
  type: 'function';
  function: {
    name: string;
    description: string;
    parameters: Record<string, unknown>;
  };
}

interface OpenRouterRequest {
  model: string;
  messages: OpenRouterMessage[];
  tools?: OpenRouterTool[];
  tool_choice?: 'none' | 'auto' | { type: 'function'; function: { name: string } };
  stream?: boolean;
  max_tokens?: number;
  temperature?: number;
  top_p?: number;
  stop?: string[];
}

interface OpenRouterChoice {
  index: number;
  message?: {
    role: string;
    content: string | null;
    tool_calls?: OpenRouterToolCall[];
  };
  delta?: {
    role?: string;
    content?: string | null;
    reasoning?: string | null;
    reasoning_content?: string | null;
    tool_calls?: Array<{
      index: number;
      id?: string;
      type?: string;
      function?: {
        name?: string;
        arguments?: string;
      };
    }>;
  };
  finish_reason: string | null;
}

interface OpenRouterResponse {
  id: string;
  model: string;
  choices: OpenRouterChoice[];
  usage?: {
    prompt_tokens: number;
    completion_tokens: number;
    total_tokens: number;
  };
  error?: {
    code: number | string;
    message: string;
  };
}

/**
 * Convert our message format to OpenRouter format
 */
function toOpenRouterMessages(messages: ChatMessage[], systemPrompt?: string): OpenRouterMessage[] {
  const result: OpenRouterMessage[] = [];

  // Add system prompt first if provided
  if (systemPrompt) {
    result.push({ role: 'system', content: systemPrompt });
  }

  for (const m of messages) {
    if (m.role === 'system') {
      result.push({ role: 'system', content: m.content || '' });
      continue;
    }

    // Handle multimodal parts
    if (m.parts && m.parts.length > 0) {
      const contentParts: OpenRouterContentPart[] = [];
      const toolCalls: OpenRouterToolCall[] = [];

      for (const part of m.parts) {
        if (part.type === 'text') {
          contentParts.push({ type: 'text', text: part.text });
        } else if (part.type === 'image') {
          contentParts.push({
            type: 'image_url',
            image_url: {
              url: `data:${part.mimeType};base64,${part.data}`,
              detail: 'auto'
            }
          });
        } else if (part.type === 'function_call') {
          // Assistant's tool calls
          toolCalls.push({
            id: part.id || `call_${Date.now()}`,
            type: 'function',
            function: {
              name: part.name,
              arguments: JSON.stringify(part.arguments)
            }
          });
        } else if (part.type === 'function_response') {
          // Tool response - add as separate message
          result.push({
            role: 'tool',
            content: JSON.stringify(part.response),
            tool_call_id: part.id || ''
          });
          continue;
        }
      }

      if (m.role === 'assistant' && toolCalls.length > 0) {
        // Assistant message with tool calls
        result.push({
          role: 'assistant',
          content: contentParts.length > 0 ? contentParts : '',
          tool_calls: toolCalls
        } as any);
      } else if (contentParts.length > 0) {
        result.push({
          role: m.role === 'assistant' ? 'assistant' : 'user',
          content: contentParts.length === 1 && contentParts[0].type === 'text'
            ? contentParts[0].text!
            : contentParts
        });
      }
    } else if (m.content && m.content.trim()) {
      result.push({
        role: m.role === 'assistant' ? 'assistant' : 'user',
        content: m.content
      });
    }
  }

  return result;
}

/**
 * Convert tool definitions to OpenRouter format
 */
function toOpenRouterTools(tools: ToolDefinition[]): OpenRouterTool[] {
  return tools.map(t => ({
    type: 'function',
    function: {
      name: t.name,
      description: t.description,
      parameters: t.parameters
    }
  }));
}

/**
 * Extract tool calls from OpenRouter response
 */
function extractToolCalls(choice: OpenRouterChoice): ToolCall[] {
  const calls: ToolCall[] = [];
  const toolCalls = choice.message?.tool_calls || [];

  for (const tc of toolCalls) {
    try {
      calls.push({
        id: tc.id,
        name: tc.function.name,
        arguments: JSON.parse(tc.function.arguments)
      });
    } catch {
      // Skip malformed tool calls
      console.warn('[OpenRouter] Failed to parse tool call arguments:', tc.function.arguments);
    }
  }

  return calls;
}

/**
 * Map OpenRouter error to user-friendly message
 */
function mapOpenRouterError(error: OpenRouterResponse['error']): string {
  if (!error) return 'Unknown error';

  const code = error.code;
  const message = error.message;

  if (code === 401 || message.includes('Unauthorized')) {
    return 'Invalid API key. Please check your OpenRouter API key.';
  }
  if (code === 402 || message.includes('insufficient')) {
    return 'Insufficient credits. Please add credits to your OpenRouter account.';
  }
  if (code === 429 || message.includes('rate')) {
    return 'Rate limit exceeded. Please wait a moment and try again.';
  }
  if (code === 503 || message.includes('unavailable')) {
    return 'Model is temporarily unavailable. Please try again later.';
  }

  // Redact potential sensitive data
  const safeMessage = message.replace(/[A-Za-z0-9_-]{20,}/g, '[REDACTED]');
  return `OpenRouter error: ${safeMessage}`;
}

/**
 * Validate an OpenRouter API key
 */
export async function validateOpenRouterKey(apiKey: string): Promise<{ success: boolean; error?: string }> {
  try {
    // Use the models endpoint to validate - lightweight check
    const response = await fetch(`${OPENROUTER_API_BASE}/models`, {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'HTTP-Referer': 'https://volt.dev',
        'X-Title': 'Volt IDE'
      }
    });

    if (!response.ok) {
      if (response.status === 401) {
        return { success: false, error: 'Invalid API key' };
      }
      return { success: false, error: `HTTP ${response.status}` };
    }

    return { success: true };
  } catch (err) {
    if (err instanceof TypeError && err.message.includes('fetch')) {
      return { success: false, error: 'Network error. Please check your internet connection.' };
    }
    const msg = err instanceof Error ? err.message : 'Unknown error';
    return { success: false, error: msg };
  }
}

function getStreamedToolArguments(raw: string): {
  arguments: Record<string, unknown>;
  complete: boolean;
} {
  const trimmed = raw.trim();
  if (!trimmed) {
    return { arguments: {}, complete: false };
  }

  try {
    return {
      arguments: JSON.parse(trimmed) as Record<string, unknown>,
      complete: true,
    };
  } catch {
    return { arguments: {}, complete: false };
  }
}

/**
 * OpenRouter AI Provider implementation
 */
export const openRouterProvider: AIProvider = {
  id: 'openrouter',
  name: 'OpenRouter',
  capabilities: {
    supportsStreaming: true,
    supportsTools: true,
    supportsJsonSchema: true,
    maxContextHint: 128000 // Varies by model, use conservative default
  } as ProviderCapabilities,

  async sendChat(request: ChatRequest, apiKey: string, signal?: AbortSignal): Promise<ChatResponse> {
    void signal;

    // Get model-specific max output, fallback to 8192
    const modelConfig = getModelConfig(request.model);
    const safeMaxTokens = request.maxTokens ?? Math.min(modelConfig?.maxOutput ?? 8192, 8192);

    const openRouterRequest: OpenRouterRequest = {
      model: request.model,
      messages: toOpenRouterMessages(request.messages, request.systemPrompt),
      max_tokens: safeMaxTokens,
      temperature: request.temperature
    };

    if (request.tools && request.tools.length > 0) {
      openRouterRequest.tools = toOpenRouterTools(request.tools);
      openRouterRequest.tool_choice = 'auto';
    }

    const data = await invoke<OpenRouterResponse>('openrouter_proxy', {
      body: openRouterRequest,
      apiKey: apiKey.trim(),
    });

    if (data.error) {
      throw new Error(mapOpenRouterError(data.error));
    }

    if (!data.choices || data.choices.length === 0) {
      throw new Error('No response from OpenRouter');
    }

    const choice = data.choices[0];
    const toolCalls = extractToolCalls(choice);
    const content = choice.message?.content || '';

    let finishReason: ChatResponse['finishReason'] = 'stop';
    if (toolCalls.length > 0) {
      finishReason = 'tool_calls';
    } else if (choice.finish_reason === 'length') {
      finishReason = 'length';
    }

    return {
      content,
      toolCalls: toolCalls.length > 0 ? toolCalls : undefined,
      finishReason,
      usage: data.usage ? {
        promptTokens: data.usage.prompt_tokens,
        completionTokens: data.usage.completion_tokens,
        totalTokens: data.usage.total_tokens
      } : undefined
    };
  },

  async *streamChat(request: ChatRequest, apiKey: string, signal?: AbortSignal): AsyncGenerator<StreamChunk> {
    const url = `${OPENROUTER_API_BASE}/chat/completions`;

    // Get model-specific limits - use conservative max for streaming
    const modelConfig = getModelConfig(request.model);
    const maxOutput = modelConfig?.maxOutput ?? 8192;
    // For streaming, use smaller of model max or 16K to avoid context overflow
    const safeMaxTokens = request.maxTokens ?? Math.min(maxOutput, 16384);

    const openRouterRequest: OpenRouterRequest = {
      model: request.model,
      messages: toOpenRouterMessages(request.messages, request.systemPrompt),
      stream: true,
      max_tokens: safeMaxTokens,
      temperature: request.temperature
    };

    if (request.tools && request.tools.length > 0) {
      openRouterRequest.tools = toOpenRouterTools(request.tools);
      openRouterRequest.tool_choice = 'auto';
    }

    const channel = new Channel<string>();
    const chunkQueue: string[] = [];
    let resolveNext: ((v: string | null) => void) | null = null;
    let isDone = false;
    let error: any = null;

    channel.onmessage = (chunk: string) => {
      if (resolveNext) {
        resolveNext(chunk);
        resolveNext = null;
      } else {
        chunkQueue.push(chunk);
      }
    };

    const invokePromise = invoke('openrouter_proxy_stream', {
      body: openRouterRequest,
      apiKey: apiKey.trim(),
      onEvent: channel
    }).then(() => {
      isDone = true;
      if (resolveNext) resolveNext(null);
    }).catch(err => {
      isDone = true;
      error = err;
      if (resolveNext) resolveNext(null);
    });

    let buffer = '';

    // Track tool calls being built up across chunks
    const pendingToolCalls: Map<
      number,
      {
        id: string;
        name: string;
        arguments: string;
        emittedPartial: boolean;
        emittedArgsKey: string | null;
        emittedFinal: boolean;
      }
    > = new Map();
    let sawDeltaContent = false;
    let fallbackAccumulated = '';

    try {
      while (true) {
        let line: string | null = null;
        if (chunkQueue.length > 0) {
          line = chunkQueue.shift()!;
        } else if (!isDone) {
          line = await new Promise<string | null>(r => { resolveNext = r; });
        } else {
          break;
        }

        if (error) {
          yield { type: 'error', error: String(error) };
          return;
        }

        if (line === null) break;

        const trimmed = line.trim();
        if (!trimmed || !trimmed.startsWith('data:')) continue;

        const jsonStr = trimmed.slice(5).trim();
        if (!jsonStr || jsonStr === '[DONE]') continue;

        try {
          const data = JSON.parse(jsonStr) as OpenRouterResponse;

          if (data.error) {
            yield { type: 'error', error: mapOpenRouterError(data.error) };
            return;
          }

          if (data.choices && data.choices.length > 0) {
            const choice = data.choices[0];
            const delta = choice.delta;

            if (delta?.content) {
              sawDeltaContent = true;
              yield { type: 'content', content: delta.content };
            }

            // Some OpenRouter models stream reasoning in separate fields.
            // Surface it as thinking so UI does not appear "stuck" while reasoning streams.
            if (delta?.reasoning) {
              yield { type: 'thinking', thinking: delta.reasoning };
            }
            if (delta?.reasoning_content) {
              yield { type: 'thinking', thinking: delta.reasoning_content };
            }

            // Some upstream providers only send final/cumulative message content in stream events.
            // Emit fallback content only when no delta content has been seen, and only emit novel suffix.
            if (
              !sawDeltaContent &&
              !delta?.content &&
              typeof choice.message?.content === 'string' &&
              choice.message.content.length > 0
            ) {
              const nextContent = choice.message.content;
              let novel = nextContent;
              if (fallbackAccumulated && nextContent.startsWith(fallbackAccumulated)) {
                novel = nextContent.slice(fallbackAccumulated.length);
              } else if (nextContent === fallbackAccumulated) {
                novel = '';
              }
              fallbackAccumulated = nextContent;
              if (novel) {
                yield { type: 'content', content: novel };
              }
            }

            // Handle streaming tool calls
            if (delta?.tool_calls) {
              for (const tc of delta.tool_calls) {
                const idx = tc.index;

                if (!pendingToolCalls.has(idx)) {
                  pendingToolCalls.set(idx, {
                    id: tc.id || `call_${Date.now()}_${idx}`,
                    name: tc.function?.name || '',
                    arguments: '',
                    emittedPartial: false,
                    emittedArgsKey: null,
                    emittedFinal: false,
                  });
                }

                const pending = pendingToolCalls.get(idx)!;
                if (tc.function?.name) pending.name = tc.function.name;
                if (tc.function?.arguments) pending.arguments += tc.function.arguments;

                if (!pending.name) {
                  continue;
                }

                const parsed = getStreamedToolArguments(pending.arguments);
                const argsKey = JSON.stringify(parsed.arguments);
                const shouldEmit =
                  !pending.emittedPartial ||
                  argsKey !== pending.emittedArgsKey;

                if (!shouldEmit) {
                  continue;
                }

                yield {
                  type: 'tool_call',
                  partial: true,
                  toolCall: {
                    id: pending.id,
                    name: pending.name,
                    arguments: parsed.arguments,
                  }
                };

                pending.emittedPartial = true;
                pending.emittedArgsKey = argsKey;
                pending.emittedFinal = false;
              }
            }
          }
        } catch (err) {
          console.warn('[OpenRouter] Failed to parse SSE chunk:', err, line);
        }
      }
    } finally {
      // Final tool call emission if stream ended
      for (const [, tc] of pendingToolCalls) {
        if (!tc.name) continue;
        const parsed = getStreamedToolArguments(tc.arguments);
        yield {
          type: 'tool_call',
          partial: false,
          toolCall: {
            id: tc.id,
            name: tc.name,
            arguments: parsed.arguments
          }
        };
      }
      yield { type: 'done' };
      await invokePromise;
    }
  },

  validateKey: validateOpenRouterKey
};

import { invoke } from '@tauri-apps/api/core';

export interface SemanticSnippetCandidate {
  snippetId: string;
  path: string;
  relativePath: string;
  startLine: number;
  endLine: number;
  text: string;
  textHash: string;
  semanticScore: number;
  lexicalScore: number;
  combinedScore: number;
}

export interface SemanticQueryResult {
  candidates: SemanticSnippetCandidate[];
  totalCandidates: number;
  topK: number;
  laneCap: number;
  semanticEnabled: boolean;
  backend: string;
  queryMs: number;
}

export interface SemanticIndexStatus {
  rootPath: string;
  semanticEnabled: boolean;
  backend: string;
  fileCount: number;
  snippetCount: number;
  vectorCount: number;
  lastIndexedAt: number | null;
  staleMs: number | null;
  modelPath?: string | null;
  modelLoadMs?: number | null;
  lastError?: string | null;
}

interface SemanticMutationResult {
  processedFiles: number;
  processedPaths: string[];
  semanticEnabled: boolean;
  backend: string;
}

const DEFAULT_TOP_K = Number(import.meta.env.VITE_VOLT_SEMANTIC_TOP_K || 24);
const DEFAULT_MAX_SELECTED = Number(import.meta.env.VITE_VOLT_SEMANTIC_MAX_SELECTED || 8);
const DEFAULT_DEBOUNCE_MS = Number(import.meta.env.VITE_VOLT_SEMANTIC_REINDEX_DEBOUNCE_MS || 500);
const DEFAULT_IDLE_BATCH_SIZE = Number(import.meta.env.VITE_VOLT_SEMANTIC_IDLE_BATCH_SIZE || 32);
const DEFAULT_FORCE_FLUSH_MS = Number(import.meta.env.VITE_VOLT_SEMANTIC_FORCE_FLUSH_MS || 10000);
const ENABLED_BY_ENV = (() => {
  const value = String(import.meta.env.VITE_VOLT_SEMANTIC_INDEX ?? 'on').toLowerCase();
  return value === 'on' || value === '1' || value === 'true';
})();

let queueRoot: string | null = null;
let upsertQueue = new Set<string>();
let removeQueue = new Set<string>();
let flushTimer: ReturnType<typeof setTimeout> | null = null;
let updateCounter = 0;
let queueFirstQueuedAt = 0;

function logSemantic(message: string): void {
  if (typeof window === 'undefined') {
    console.warn(`[semantic-index] ${message}`);
    return;
  }

  void import('$features/terminal/stores/output.svelte')
    .then(({ logOutput }) => logOutput('Volt', message))
    .catch(() => console.warn(`[semantic-index] ${message}`));
}

function normalizePath(path: string): string {
  return path.replace(/\\/g, '/');
}

function nowMs(): number {
  return Date.now();
}

function scheduleIdleFlush(task: () => void): void {
  if (typeof window !== 'undefined' && 'requestIdleCallback' in window) {
    (
      window as Window & {
        requestIdleCallback: (callback: IdleRequestCallback, options?: IdleRequestOptions) => number;
      }
    ).requestIdleCallback(() => task(), { timeout: DEFAULT_FORCE_FLUSH_MS });
    return;
  }
  setTimeout(task, 120);
}

function dequeueBatch(queue: Set<string>, maxItems: number): string[] {
  const output: string[] = [];
  for (const value of queue) {
    output.push(value);
    queue.delete(value);
    if (output.length >= maxItems) break;
  }
  return output;
}

function scheduleFlush(debounceMs = DEFAULT_DEBOUNCE_MS): void {
  if (flushTimer) clearTimeout(flushTimer);
  flushTimer = setTimeout(() => {
    flushTimer = null;
    const overdue = queueFirstQueuedAt > 0 && nowMs() - queueFirstQueuedAt >= DEFAULT_FORCE_FLUSH_MS;
    if (overdue) {
      void flushQueues();
      return;
    }
    scheduleIdleFlush(() => {
      void flushQueues();
    });
  }, debounceMs);
}

async function flushQueues(): Promise<void> {
  if (!isSemanticIndexEnabled()) return;
  const root = queueRoot;
  if (!root) return;

  const batchSize = Math.max(1, DEFAULT_IDLE_BATCH_SIZE);
  const removals = dequeueBatch(removeQueue, batchSize);
  const upserts = dequeueBatch(upsertQueue, batchSize);

  if (removals.length > 0) {
    try {
      await invoke<SemanticMutationResult>('semantic_index_remove_paths', {
        args: { rootPath: root, paths: removals },
      });
    } catch (error) {
      logSemantic(`Semantic remove failed: ${error}`);
    }
  }

  if (upserts.length > 0) {
    try {
      await invoke<SemanticMutationResult>('semantic_index_upsert_files', {
        args: {
          rootPath: root,
          paths: upserts,
        },
      });
      updateCounter += upserts.length;
      if (updateCounter >= 250) {
        updateCounter = 0;
        void compactSemanticIndex(root);
      }
    } catch (error) {
      logSemantic(`Semantic upsert failed: ${error}`);
    }
  }

  if (removeQueue.size > 0 || upsertQueue.size > 0) {
    scheduleIdleFlush(() => {
      void flushQueues();
    });
  } else {
    queueFirstQueuedAt = 0;
  }
}

export function isSemanticIndexEnabled(): boolean {
  return ENABLED_BY_ENV;
}

export function getSemanticDefaults(): { topK: number; maxSelected: number; debounceMs: number } {
  return {
    topK: Math.max(1, DEFAULT_TOP_K),
    maxSelected: Math.max(1, DEFAULT_MAX_SELECTED),
    debounceMs: Math.max(50, DEFAULT_DEBOUNCE_MS),
  };
}

export async function warmSemanticIndex(rootPath: string): Promise<void> {
  if (!isSemanticIndexEnabled()) return;
  queueRoot = normalizePath(rootPath);
  try {
    await invoke<SemanticMutationResult>('semantic_index_upsert_files', {
      args: {
        rootPath: queueRoot,
      },
    });
  } catch (error) {
    logSemantic(`Semantic warm index failed: ${error}`);
  }
}

export async function rebuildSemanticIndex(rootPath: string): Promise<void> {
  if (!isSemanticIndexEnabled()) return;
  queueRoot = normalizePath(rootPath);
  await invoke<SemanticMutationResult>('semantic_index_rebuild', {
    args: { rootPath: queueRoot },
  });
}

export async function compactSemanticIndex(rootPath: string): Promise<void> {
  if (!isSemanticIndexEnabled()) return;
  await invoke<SemanticMutationResult>('semantic_index_compact', {
    args: { rootPath: normalizePath(rootPath) },
  });
}

export async function getSemanticStatus(rootPath: string): Promise<SemanticIndexStatus | null> {
  if (!isSemanticIndexEnabled()) return null;
  try {
    return await invoke<SemanticIndexStatus>('semantic_index_status', {
      args: { rootPath: normalizePath(rootPath) },
    });
  } catch {
    return null;
  }
}

export async function querySemanticIndex(
  rootPath: string,
  query: string,
  options?: { topK?: number; laneCap?: number },
): Promise<SemanticQueryResult | null> {
  if (!isSemanticIndexEnabled() || !query.trim()) return null;
  try {
    return await invoke<SemanticQueryResult>('semantic_index_query', {
      args: {
        query,
        rootPath: normalizePath(rootPath),
        topK: options?.topK ?? Math.max(1, DEFAULT_TOP_K),
        laneCap: options?.laneCap ?? Math.max(1, DEFAULT_MAX_SELECTED),
      },
    });
  } catch {
    return null;
  }
}

export function queueSemanticUpsert(rootPath: string, absolutePath: string): void {
  if (!isSemanticIndexEnabled()) return;
  if (!queueFirstQueuedAt) queueFirstQueuedAt = nowMs();
  queueRoot = normalizePath(rootPath);
  const normalized = normalizePath(absolutePath);
  removeQueue.delete(normalized);
  upsertQueue.add(normalized);
  scheduleFlush();
}

export function queueSemanticRemove(rootPath: string, absolutePath: string): void {
  if (!isSemanticIndexEnabled()) return;
  if (!queueFirstQueuedAt) queueFirstQueuedAt = nowMs();
  queueRoot = normalizePath(rootPath);
  const normalized = normalizePath(absolutePath);
  upsertQueue.delete(normalized);
  removeQueue.add(normalized);
  scheduleFlush();
}

export function clearSemanticQueue(): void {
  upsertQueue.clear();
  removeQueue.clear();
  queueRoot = null;
  queueFirstQueuedAt = 0;
  if (flushTimer) {
    clearTimeout(flushTimer);
    flushTimer = null;
  }
}

/**
 * LSP Tool Handlers - Expose Language Server capabilities to AI
 * 
 * These tools give the AI semantic code intelligence:
 * - lsp_go_to_definition: Jump to where a symbol is defined
 * - lsp_find_references: Find all usages of a symbol
 * - lsp_get_hover: Get type info and documentation
 * - lsp_rename_symbol: Safely rename a symbol across all files
 * 
 * SUPPORTED LANGUAGES:
 * - TypeScript/JavaScript (.ts, .tsx, .js, .jsx, .mts, .cts, .mjs, .cjs) - Full support
 * - Svelte (.svelte) - Definition, references, hover
 * - HTML (.html, .htm) - Definition, references, hover
 * - CSS/SCSS/LESS (.css, .scss, .sass, .less) - Definition, references, hover
 * - JSON (.json, .jsonc) - Hover only (schema info)
 * - Dart (.dart) - Full support (definition, references, hover, rename, code actions)
 * - YAML (.yaml, .yml, pubspec.yaml) - Hover, completions, formatting
 * - XML (.xml, .plist, AndroidManifest.xml, .xsd) - Hover, completions, formatting
 * - Tailwind CSS (hover for class utilities in any file)
 * 
 * ADVANTAGE over text search:
 * - Semantic understanding (knows imports, aliases, etc.)
 * - No false positives (won't match in strings/comments)
 * - Atomic operations (rename updates all correctly)
 */

