    'through', 'during', 'before', 'after', 'above', 'below', 'between',
    'and', 'but', 'or', 'nor', 'so', 'yet', 'both', 'either', 'neither',
    'not', 'only', 'own', 'same', 'than', 'too', 'very', 'just', 'also',
    'this', 'that', 'these', 'those', 'what', 'which', 'who', 'whom', 'whose',
    'where', 'when', 'why', 'how', 'all', 'each', 'every', 'any', 'some',
    'file', 'code', 'function', 'find', 'look', 'see', 'check', 'read', 'get',
    'i', 'me', 'my', 'we', 'our', 'you', 'your', 'it', 'its', 'they', 'their'
  ]);

  const words = explanation.toLowerCase()
    .replace(/[^a-z0-9_\-]/g, ' ')
    .split(/\s+/)
    .filter(w => w.length > 2 && !stopWords.has(w));

  return [...new Set(words)];
}

/**
 * Score a line's relevance based on keywords
 */
function scoreLineRelevance(line: string, keywords: string[]): number {
  if (keywords.length === 0) return 1;

  const lineLower = line.toLowerCase();
  let score = 0;

  for (const keyword of keywords) {
    if (lineLower.includes(keyword)) {
      score += 2;
      // Bonus for exact word match
      if (new RegExp(`\\b${keyword}\\b`).test(lineLower)) {
        score += 1;
      }
    }
  }

  // Bonus for important code patterns
  if (/^(export|function|class|interface|type|const|let|var)\s/.test(line.trim())) {
    score += 1;
  }

  return score;
}

/**
 * Intelligently prune file content based on explanation
 * Keeps relevant sections + context, removes irrelevant parts
 */
function pruneContent(content: string, explanation: string, maxLines = 300): {
  pruned: string;
  wasPruned: boolean;
  relevantRanges: Array<{ start: number; end: number }>;
} {
  const lines = content.split('\n');

  // If file is small enough, return as-is
  if (lines.length <= maxLines || !explanation) {
    return { pruned: content, wasPruned: false, relevantRanges: [] };
  }

  const keywords = extractKeywords(explanation);
  if (keywords.length === 0) {
    // No keywords - just truncate
    return {
      pruned: lines.slice(0, maxLines).join('\n') + '\n... [truncated]',
      wasPruned: true,
      relevantRanges: []
    };
  }

  // Score each line
  const scores = lines.map((line, i) => ({ line, index: i, score: scoreLineRelevance(line, keywords) }));

  // Find relevant sections (lines with score > 0 + context)
  const contextLines = 5; // Lines before/after relevant code
  const relevantIndices = new Set<number>();
  const relevantRanges: Array<{ start: number; end: number }> = [];

  for (const { index, score } of scores) {
    if (score > 0) {
      const start = Math.max(0, index - contextLines);
      const end = Math.min(lines.length - 1, index + contextLines);

      for (let i = start; i <= end; i++) {
        relevantIndices.add(i);
      }

      // Track ranges for metadata
      if (relevantRanges.length === 0 || relevantRanges[relevantRanges.length - 1].end < start - 1) {
        relevantRanges.push({ start: start + 1, end: end + 1 }); // 1-based
      } else {
        relevantRanges[relevantRanges.length - 1].end = end + 1;
      }
    }
  }

  // Always include first 20 lines (imports, class definition)
  for (let i = 0; i < Math.min(20, lines.length); i++) {
    relevantIndices.add(i);
  }

  // Build pruned output
  const sortedIndices = [...relevantIndices].sort((a, b) => a - b);
  const prunedLines: string[] = [];
  let lastIndex = -1;

  for (const index of sortedIndices) {
    if (prunedLines.length >= maxLines) break;

    // Add ellipsis for gaps
    if (lastIndex >= 0 && index > lastIndex + 1) {
      const gap = index - lastIndex - 1;
      prunedLines.push(`... [${gap} lines omitted]`);
    }

    prunedLines.push(lines[index]);
    lastIndex = index;
  }

  // Add final ellipsis if needed
  if (lastIndex < lines.length - 1) {
    const remaining = lines.length - lastIndex - 1;
    prunedLines.push(`... [${remaining} lines omitted]`);
  }

  return {
    pruned: prunedLines.join('\n'),
    wasPruned: true,
    relevantRanges
  };
}

/**
 * Read a single file with optional line slice
 * Includes line numbers, intelligent pruning based on explanation
 */
export async function handleReadFile(
  args: Record<string, unknown>,
  runtime?: ToolRuntimeContext,
): Promise<ToolResult> {
  const relativePath = String(args.path);
  const explanation = args.explanation ? String(args.explanation) : '';
  const path = resolvePath(relativePath);
  runtime?.onUpdate?.({ liveStatus: 'Reading file...' });

  let content: string;
  try {
    // Use fileService for consistent file access - always get fresh from disk for AI reads
    const doc = await fileService.read(path, true);
    if (!doc) {
      return {
        success: false,
        error:
          `File not found: ${relativePath}\n` +
          'If you are exploring a new or empty workspace, use list_dir or get_file_tree first.\n' +
          'If you intend to create this file from scratch, use write_file or apply_patch with an Add File patch.',
      };
    }
    content = doc.content;
  } catch (err) {
    return {
      success: false,
      error:
        `File not found: ${relativePath}\n` +
        'If you are exploring a new or empty workspace, use list_dir or get_file_tree first.\n' +
        'If you intend to create this file from scratch, use write_file or apply_patch with an Add File patch.',
    };
  }

  const totalLines = content.split('\n').length;

  const rawOffset = Number(args.offset);
  const rawLimit = Number(args.limit);
  const offset = Number.isFinite(rawOffset) ? Math.max(0, Math.floor(rawOffset)) : 0;
  const limit = Number.isFinite(rawLimit)
    ? Math.min(2000, Math.max(1, Math.floor(rawLimit)))
    : totalLines;
  const startLine = Math.min(totalLines, offset + 1);
  const endLine = Math.min(totalLines, startLine + limit - 1);

  let output = content;
  let wasPruned = false;
  let relevantRanges: Array<{ start: number; end: number }> = [];

  if (offset > 0 || Number.isFinite(rawLimit)) {
    // Explicit slice requested.
    const lines = content.split('\n');
    output = lines.slice(startLine - 1, endLine).join('\n');
  } else if (explanation) {
    // No line range but has explanation - use intelligent pruning
    const pruneResult = pruneContent(content, explanation);
    output = pruneResult.pruned;
    wasPruned = pruneResult.wasPruned;
    relevantRanges = pruneResult.relevantRanges;
  }

  // Format with line numbers
  const formatted = formatWithLineNumbers(output, startLine);

  // Add header
  let header = startLine === 1 && endLine === totalLines
    ? `${relativePath} (${totalLines} lines)`
    : `${relativePath} lines ${startLine}-${endLine} of ${totalLines}`;

  if (wasPruned) {
    header += ' [intelligently pruned]';
  }
  header += '\n';

  const { text, truncated } = truncateOutput(header + formatted);

  return {
    success: true,
    output: text,
    truncated,
    meta: {
      startLine,
      endLine,
      totalLines,
      wasPruned,
      relevantRanges
    }
  };
}

/**
 * Read multiple files at once
 */
export async function handleReadFiles(
  args: Record<string, unknown>,
  runtime?: ToolRuntimeContext,
): Promise<ToolResult> {
  const paths = args.paths as string[] | undefined;
  if (!paths || !Array.isArray(paths) || paths.length === 0) {
    return { success: false, error: 'No paths provided' };
  }
  runtime?.onUpdate?.({
    liveStatus: paths.length === 1 ? 'Reading file...' : `Reading ${paths.length} files...`,
  });

  const results: string[] = [];
  let totalLines = 0;

  for (const relativePath of paths) {
    const path = resolvePath(relativePath);
    try {
      // Use fileService for consistent file access - always get fresh from disk
      const doc = await fileService.read(path, true);
      if (!doc) {
        results.push(`── ${relativePath} ──\n[Error: File not found]`);
        continue;
      }
      const content = doc.content;
      const lines = content.split('\n').length;
      totalLines += lines;

      const formatted = formatWithLineNumbers(content);
      results.push(`── ${relativePath} (${lines} lines) ──\n${formatted}`);
    } catch {
      results.push(`── ${relativePath} ──\n[Error: File not found]`);
    }
  }

  const { text, truncated } = truncateOutput(results.join('\n\n'));

  return {
    success: true,
    output: text,
    truncated,
    meta: { totalLines, fileCount: paths.length }
  };
}

/**
 * List directory contents
 */
export async function handleListDir(args: Record<string, unknown>): Promise<ToolResult> {
  const relativePath = String(args.path || '.');
  const path = resolvePath(relativePath);

  try {
    const entries = await invoke<Array<{
      name: string;
      isDir: boolean;
      size: number;
    }>>('list_dir', { path });

    if (entries.length === 0) {
      return {
        success: true,
        output:
          `${relativePath}/ (empty)\n` +
          'Workspace appears empty. Scaffold new files or directories instead of assuming existing project files.',
      };
    }

    // Sort: directories first, then files
    entries.sort((a, b) => {
      if (a.isDir !== b.isDir) return a.isDir ? -1 : 1;
      return a.name.localeCompare(b.name);
    });

    const lines = entries.map(e => {
      const icon = e.isDir ? '📁' : '📄';
      const size = e.isDir ? '' : ` (${formatSize(e.size)})`;
      return `${icon} ${e.name}${size}`;
    });

    return {
      success: true,
      output: `${relativePath}/\n${lines.join('\n')}`
    };
  } catch (err) {
    return { success: false, error: `Cannot list: ${relativePath}` };
  }
}

/**
 * Get file tree structure (recursive directory listing)
 * List directory contents:
 * - Shows file type icons/emojis
 * - Shows file counts per directory
 * - Smarter directory skipping
 * - Shows project type detection (React, Svelte, etc.)
 * - LARGE PROJECT SAFE: Caps total entries to prevent context overflow
 */
export async function handleGetFileTree(args: Record<string, unknown>): Promise<ToolResult> {
  const relativePath = String(args.path || '.');
  const maxDepth = Math.min(Number(args.depth) || 3, 4); // Cap at 4 for safety
  const path = resolvePath(relativePath);

  try {
    const { tree, stats, wasTruncated } = await buildFileTreeWithStats(path, relativePath, 0, maxDepth);
    const output = formatFileTreeBetter(tree, relativePath, stats, wasTruncated);
    const { text, truncated } = truncateOutput(output);
    return { success: true, output: text, truncated: truncated || wasTruncated };
  } catch (err) {
    return { success: false, error: `Cannot get tree: ${relativePath}` };
  }
}

interface TreeEntry {
  name: string;
  isDir: boolean;
  children?: TreeEntry[];
  fileCount?: number; // For directories
}

interface TreeStats {
  totalFiles: number;
  totalDirs: number;
  fileTypes: Map<string, number>;
  projectType?: string;
}

// Global limit to prevent context overflow on huge projects
const MAX_TREE_ENTRIES = 200;

/**
 * Recursively build file tree with statistics
 * LARGE PROJECT SAFE: Stops after MAX_TREE_ENTRIES
 */
async function buildFileTreeWithStats(
  absolutePath: string,
  relativePath: string,
  currentDepth: number,
  maxDepth: number
): Promise<{ tree: TreeEntry[]; stats: TreeStats; wasTruncated: boolean }> {
  const stats: TreeStats = {
    totalFiles: 0,
    totalDirs: 0,
    fileTypes: new Map(),
  };

  let entryCount = 0;
  let wasTruncated = false;

  const tree = await buildFileTreeRecursive(absolutePath, relativePath, currentDepth, maxDepth, stats,
    () => entryCount++,
    () => entryCount >= MAX_TREE_ENTRIES,
    () => { wasTruncated = true; }
  );

  // Detect project type from file types
  if (stats.fileTypes.has('svelte')) stats.projectType = 'Svelte';
  else if (stats.fileTypes.has('tsx') || stats.fileTypes.has('jsx')) stats.projectType = 'React';
  else if (stats.fileTypes.has('vue')) stats.projectType = 'Vue';
  else if (stats.fileTypes.has('py')) stats.projectType = 'Python';
  else if (stats.fileTypes.has('rs')) stats.projectType = 'Rust';
  else if (stats.fileTypes.has('go')) stats.projectType = 'Go';
  else if (stats.fileTypes.has('ts') || stats.fileTypes.has('js')) stats.projectType = 'Node.js';

  return { tree, stats, wasTruncated };
}

async function buildFileTreeRecursive(
  absolutePath: string,
  relativePath: string,
  currentDepth: number,
  maxDepth: number,
  stats: TreeStats,
  incrementCount: () => void,
  shouldStop: () => boolean,
  markTruncated: () => void
): Promise<TreeEntry[]> {
  if (currentDepth >= maxDepth || shouldStop()) return [];

  try {
    const entries = await invoke<Array<{ name: string; isDir: boolean; path: string }>>('list_dir', { path: absolutePath });

    // Sort: directories first, then alphabetically
    entries.sort((a, b) => {
      if (a.isDir && !b.isDir) return -1;
      if (!a.isDir && b.isDir) return 1;
      return a.name.toLowerCase().localeCompare(b.name.toLowerCase());
    });

    // Skip common non-essential directories
    const skipDirs = ['node_modules', '.git', 'dist', 'build', '.svelte-kit', '__pycache__', '.next', 'coverage', '.turbo', '.cache', 'vendor', 'target', '.pnpm', '.yarn'];

    const result: TreeEntry[] = [];
    for (const entry of entries) {
      // Check if we should stop
      if (shouldStop()) {
        markTruncated();
        break;
      }

      // Skip hidden files at root level (except important ones)
      if (entry.name.startsWith('.') && currentDepth === 0) {
        if (!['env', '.env', '.env.local', '.gitignore', '.eslintrc', '.prettierrc'].some(f => entry.name.includes(f))) {
          continue;
        }
      }
      if (skipDirs.includes(entry.name)) continue;

      incrementCount();

      const treeEntry: TreeEntry = {
        name: entry.name,
        isDir: entry.isDir,
      };

      if (entry.isDir) {
        stats.totalDirs++;
        if (currentDepth < maxDepth - 1 && !shouldStop()) {
          treeEntry.children = await buildFileTreeRecursive(
            entry.path,
            `${relativePath}/${entry.name}`,
            currentDepth + 1,
            maxDepth,
            stats,
            incrementCount,
            shouldStop,
            markTruncated
          );
          treeEntry.fileCount = treeEntry.children.filter(c => !c.isDir).length;
        }
      } else {
        stats.totalFiles++;
        // Track file types
        const ext = entry.name.split('.').pop()?.toLowerCase() || '';
        if (ext) {
          stats.fileTypes.set(ext, (stats.fileTypes.get(ext) || 0) + 1);
        }
      }

      result.push(treeEntry);
    }

    return result;
  } catch {
    return [];
  }
}

/**
 * Format tree with icons and better structure
 */
function formatFileTreeBetter(entries: TreeEntry[], rootPath: string, stats: TreeStats, wasTruncated: boolean): string {
  const lines: string[] = [];

  // Header with project info
  lines.push(`📂 ${rootPath}/`);
  if (stats.projectType) {
    lines.push(`   Project: ${stats.projectType} | ${stats.totalFiles} files, ${stats.totalDirs} directories`);
  } else {
    lines.push(`   ${stats.totalFiles} files, ${stats.totalDirs} directories`);
  }

  if (wasTruncated) {
    lines.push(`   ⚠️ Large project - showing first ${MAX_TREE_ENTRIES} entries. Use find_files or workspace_search for specific files.`);
  }

  if (entries.length === 0) {
    lines.push('   Workspace appears empty. Scaffold new files/directories instead of assuming existing app files.');
  }
  lines.push('');

  // Tree
  lines.push(formatTreeRecursive(entries, ''));

  if (wasTruncated) {
    lines.push('');
    lines.push('... (truncated for large project)');
  }

  return lines.join('\n');
}

function formatTreeRecursive(entries: TreeEntry[], prefix: string): string {
  let output = '';

  for (let i = 0; i < entries.length; i++) {
    const entry = entries[i];
    const isLast = i === entries.length - 1;
    const connector = isLast ? '└── ' : '├── ';
    const childPrefix = isLast ? '    ' : '│   ';

    if (entry.isDir) {
      const countInfo = entry.fileCount !== undefined ? ` (${entry.fileCount})` : '';
      output += `${prefix}${connector}📁 ${entry.name}/${countInfo}\n`;
    } else {
      const icon = getFileTypeIcon(entry.name);
      output += `${prefix}${connector}${icon} ${entry.name}\n`;
    }

    if (entry.children && entry.children.length > 0) {
      output += formatTreeRecursive(entry.children, prefix + childPrefix);
    }
  }

  return output;
}

/**
 * Get icon for file type
 */
function getFileTypeIcon(filename: string): string {
  const ext = filename.split('.').pop()?.toLowerCase() || '';

  const icons: Record<string, string> = {
    'ts': '📘', 'tsx': '⚛️', 'js': '📒', 'jsx': '⚛️',
    'svelte': '🔶', 'vue': '💚', 'py': '🐍', 'rs': '🦀',
    'go': '🐹', 'java': '☕', 'rb': '💎', 'php': '🐘',
    'html': '🌐', 'css': '🎨', 'scss': '🎨', 'sass': '🎨',
    'json': '📋', 'yaml': '📋', 'yml': '📋', 'toml': '📋',
    'md': '📝', 'txt': '📄', 'sql': '🗃️',
    'png': '🖼️', 'jpg': '🖼️', 'svg': '🎨', 'ico': '🖼️',
    'lock': '🔒', 'env': '🔐',
  };

  return icons[ext] || '📄';
}

/**
 * Get file info (size, modified date, etc.)
 */
export async function handleGetFileInfo(args: Record<string, unknown>): Promise<ToolResult> {
  const relativePath = String(args.path);
  const path = resolvePath(relativePath);

  try {
    const info = await invoke<{
      name: string;
      isDir: boolean;
      isFile: boolean;
      isReadonly: boolean;
      size: number;
      modified: number | null;
    }>('get_file_info', { path });

    const output = [
      `Name: ${info.name}`,
      `Type: ${info.isDir ? 'Directory' : 'File'}`,
      `Size: ${formatSize(info.size)}`,
      info.modified ? `Modified: ${new Date(info.modified).toLocaleString()}` : null
    ].filter(Boolean).join('\n');

    return { success: true, output };
  } catch (err) {
    return { success: false, error: `File not found: ${relativePath}` };
  }
}

/**
 * Format file size in human readable format
 */
function formatSize(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}


/**
 * Read code file with smart structure analysis
 * Smart code reader:
 * - Shows file structure (functions, classes, exports)
 * - Can read specific symbol by name
 * - Auto-detects and highlights important sections
 * - LARGE FILE SAFE: Skips structure analysis for huge files
 */
export async function handleReadCode(
  args: Record<string, unknown>,
  runtime?: ToolRuntimeContext,
): Promise<ToolResult> {
  const relativePath = String(args.path);
  const symbolName = args.symbol ? String(args.symbol) : '';
  const showStructure = args.structure !== false; // Default true
  const path = resolvePath(relativePath);
  runtime?.onUpdate?.({ liveStatus: 'Reading code...' });

  let content: string;
  try {
    const doc = await fileService.read(path, true);
    if (!doc) {
      return { success: false, error: `File not found: ${relativePath}` };
    }
    content = doc.content;
  } catch (err) {
    return { success: false, error: `File not found: ${relativePath}` };
  }

  const lines = content.split('\n');
  const totalLines = lines.length;
  const ext = relativePath.split('.').pop()?.toLowerCase() || '';

  // Skip structure analysis for huge files (>2000 lines) to prevent slowdown
  const isHugeFile = totalLines > 2000;

  // Analyze code structure (skip for huge files unless symbol requested)
  const structure = (isHugeFile && !symbolName)
    ? { symbols: [], imports: [] }
    : analyzeCodeStructure(content, ext);

  // If symbol requested, find and return just that symbol
  if (symbolName) {
    const symbol = structure.symbols.find(s =>
      s.name.toLowerCase() === symbolName.toLowerCase() ||
      s.name.toLowerCase().includes(symbolName.toLowerCase())
    );

    if (symbol) {
      const symbolContent = lines.slice(symbol.startLine - 1, symbol.endLine).join('\n');
      const formatted = formatWithLineNumbers(symbolContent, symbol.startLine);

      return {
        success: true,
        output: `${relativePath} - ${symbol.kind}: ${symbol.name} (lines ${symbol.startLine}-${symbol.endLine})\n\n${formatted}`,
        meta: { symbol, totalLines }
      };
    } else {
      const availableSymbols = structure.symbols.length > 0
        ? structure.symbols.slice(0, 20).map(s => s.name).join(', ')
        : '(file too large for full analysis - try workspace_search)';
      return {
        success: false,
        error: `Symbol "${symbolName}" not found. Available: ${availableSymbols}`
      };
    }
  }

  // Build output with structure header
  const outputLines: string[] = [];

  // Header
  outputLines.push(`📄 ${relativePath} (${totalLines} lines)`);

  if (isHugeFile) {
    outputLines.push(`⚠️ Large file - structure analysis skipped. Use symbol parameter to read specific functions.`);
  }

  // Structure summary if requested and file has structure
  if (showStructure && structure.symbols.length > 0 && !isHugeFile) {
    outputLines.push('');
    outputLines.push('📋 Structure:');

    // Group by kind
    const byKind = new Map<string, typeof structure.symbols>();
    for (const sym of structure.symbols) {
      if (!byKind.has(sym.kind)) byKind.set(sym.kind, []);
      byKind.get(sym.kind)!.push(sym);
    }

    for (const [kind, syms] of byKind) {
      const icon = kind === 'function' ? '⚡' : kind === 'class' ? '🏛️' : kind === 'interface' ? '📐' : kind === 'type' ? '📝' : '•';
      for (const sym of syms.slice(0, 15)) { // Cap at 15 per kind
        const exported = sym.exported ? '↗️' : '  ';
        outputLines.push(`   ${exported} ${icon} ${sym.name} (L${sym.startLine})`);
      }
      if (syms.length > 15) {
        outputLines.push(`   ... +${syms.length - 15} more ${kind}s`);
      }
    }
    outputLines.push('');
  }

  // File content with line numbers
  const formatted = formatWithLineNumbers(content);
  const { text, truncated } = truncateOutput(outputLines.join('\n') + '\n' + formatted);

  return {
    success: true,
    output: text,
    truncated,
    meta: { totalLines, structure: isHugeFile ? null : structure }
  };
}

interface CodeSymbol {
  name: string;
  kind: 'function' | 'class' | 'interface' | 'type' | 'const' | 'variable';
  startLine: number;
  endLine: number;
  exported: boolean;
}

interface CodeStructure {
  symbols: CodeSymbol[];
  imports: string[];
}

/**
 * Analyze code structure using regex patterns
 * Works for TS/JS/Svelte - no LSP needed
 */
function analyzeCodeStructure(content: string, ext: string): CodeStructure {
  const lines = content.split('\n');
  const symbols: CodeSymbol[] = [];
  const imports: string[] = [];

  // Patterns for different constructs
  const patterns = {
    function: /^(export\s+)?(async\s+)?function\s+(\w+)/,
    arrowFunction: /^(export\s+)?(const|let)\s+(\w+)\s*=\s*(async\s*)?\([^)]*\)\s*(:\s*\w+)?\s*=>/,
    class: /^(export\s+)?class\s+(\w+)/,
    interface: /^(export\s+)?interface\s+(\w+)/,
    type: /^(export\s+)?type\s+(\w+)/,
    constExport: /^export\s+const\s+(\w+)/,
    import: /^import\s+/,
  };

  let braceDepth = 0;
  let currentSymbol: CodeSymbol | null = null;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const trimmed = line.trim();
    const lineNum = i + 1;

    // Track imports
    if (patterns.import.test(trimmed)) {
      imports.push(trimmed);
      continue;
    }

    // Skip if inside a symbol body
    if (currentSymbol) {
      // Count braces
      for (const char of line) {
        if (char === '{') braceDepth++;
        if (char === '}') braceDepth--;
      }

      if (braceDepth === 0) {
        currentSymbol.endLine = lineNum;
        symbols.push(currentSymbol);
        currentSymbol = null;
      }
      continue;
    }

    // Check for new symbols
    let match: RegExpMatchArray | null;

    if ((match = trimmed.match(patterns.function))) {
      currentSymbol = {
        name: match[3],
        kind: 'function',
        startLine: lineNum,
        endLine: lineNum,
        exported: !!match[1]
      };
      braceDepth = (line.match(/{/g) || []).length - (line.match(/}/g) || []).length;
      if (braceDepth === 0 && line.includes('{') && line.includes('}')) {
        symbols.push(currentSymbol);
        currentSymbol = null;
      }
    } else if ((match = trimmed.match(patterns.arrowFunction))) {
      currentSymbol = {
        name: match[3],
        kind: 'function',
        startLine: lineNum,
        endLine: lineNum,
        exported: !!match[1]
      };
      braceDepth = (line.match(/{/g) || []).length - (line.match(/}/g) || []).length;
      if (braceDepth <= 0) {
        // Single line arrow function
        symbols.push(currentSymbol);
        currentSymbol = null;
        braceDepth = 0;
      }
    } else if ((match = trimmed.match(patterns.class))) {
      currentSymbol = {
        name: match[2],
        kind: 'class',
        startLine: lineNum,
        endLine: lineNum,
        exported: !!match[1]
      };
      braceDepth = (line.match(/{/g) || []).length - (line.match(/}/g) || []).length;
    } else if ((match = trimmed.match(patterns.interface))) {
      currentSymbol = {
        name: match[2],
        kind: 'interface',
        startLine: lineNum,
        endLine: lineNum,
        exported: !!match[1]
      };
      braceDepth = (line.match(/{/g) || []).length - (line.match(/}/g) || []).length;
      if (braceDepth === 0) {
        symbols.push(currentSymbol);
        currentSymbol = null;
      }
    } else if ((match = trimmed.match(patterns.type))) {
      currentSymbol = {
        name: match[2],
        kind: 'type',
        startLine: lineNum,
        endLine: lineNum,
        exported: !!match[1]
      };
      // Types usually end with ; on same or next line
      if (trimmed.endsWith(';') || trimmed.endsWith('}')) {
        symbols.push(currentSymbol);
        currentSymbol = null;
      } else {
        braceDepth = (line.match(/{/g) || []).length - (line.match(/}/g) || []).length;
      }
    } else if ((match = trimmed.match(patterns.constExport))) {
      // Simple exported const (not arrow function)
      symbols.push({
        name: match[1],
        kind: 'const',
        startLine: lineNum,
        endLine: lineNum,
        exported: true
      });
    }
  }

  // Close any unclosed symbol
  if (currentSymbol) {
    currentSymbol.endLine = lines.length;
    symbols.push(currentSymbol);
  }

  return { symbols, imports };
}

// ============================================================================
// FILE OUTLINE - Structure only, no content (token-efficient)
// ============================================================================

/**
 * Get file structure outline without loading content.
 * Returns classes, functions, interfaces, types with line ranges.
 * Works on large files (no content = no size limit concerns).
 * ~100x more token-efficient than read_code for understanding file structure.
 */
export async function handleFileOutline(args: Record<string, unknown>): Promise<ToolResult> {
  const relativePath = String(args.path);
  const path = resolvePath(relativePath);

  let content: string;
  try {
    const doc = await fileService.read(path, true);
    if (!doc) {
      return { success: false, error: `File not found: ${relativePath}` };
    }
    content = doc.content;
  } catch {
    return { success: false, error: `File not found: ${relativePath}` };
  }

  const lines = content.split('\n');
  const totalLines = lines.length;
  const ext = relativePath.split('.').pop()?.toLowerCase() || '';

  // Analyze structure — no size limit since we're not returning content
  const structure = analyzeCodeStructure(content, ext);

  // Build compact outline
  const outputLines: string[] = [];
  outputLines.push(`📄 ${relativePath} (${totalLines} lines)`);

  // Import summary
  if (structure.imports.length > 0) {
    outputLines.push(`\nImports: ${structure.imports.length} imports`);
  }

  // Symbols grouped by kind
  if (structure.symbols.length === 0) {
    outputLines.push('\nNo symbols detected (may be a config, data, or markup file)');
  } else {
    outputLines.push('\nSymbols:');

    // Group by kind
    const byKind = new Map<string, typeof structure.symbols>();
    for (const sym of structure.symbols) {
      if (!byKind.has(sym.kind)) byKind.set(sym.kind, []);
      byKind.get(sym.kind)!.push(sym);
    }

    for (const [kind, syms] of byKind) {
      const icon = kind === 'function' ? '⚡' : kind === 'class' ? '🏛️' : kind === 'interface' ? '📐' : kind === 'type' ? '📝' : kind === 'const' ? '📦' : '•';
      for (const sym of syms.slice(0, 30)) {
        const exported = sym.exported ? '↗️ ' : '   ';
        const range = sym.endLine > sym.startLine ? `L${sym.startLine}-L${sym.endLine}` : `L${sym.startLine}`;
        outputLines.push(`  ${exported}${icon} ${sym.name} (${range})`);
      }
      if (syms.length > 30) {
        outputLines.push(`  ... +${syms.length - 30} more ${kind}s`);
      }
    }
  }

  return {
    success: true,
    output: outputLines.join('\n'),
    meta: {
      totalLines,
      symbolCount: structure.symbols.length,
      importCount: structure.imports.length,
    }
  };
}

/**
 * Search tool handlers
 *
 * - Result grouping by relevance
 * - Code-aware context (shows surrounding lines)
 * - Deduplication of overlapping matches
 * - file:line format for easy navigation
 */

import { invoke } from '@tauri-apps/api/core';
import { fileService } from '$core/services/file-service';
import { projectStore } from '$shared/stores/project.svelte';
import { truncateOutput, resolvePath, type ToolResult } from '$core/ai/tools/utils';
import { getWorkspaceSymbols as getTsWorkspaceSymbols, isTsLspConnected, ensureTsLspStarted } from '$core/lsp/typescript-sidecar';
import { getWorkspaceSymbols as getDartWorkspaceSymbols, isDartLspRunning } from '$core/lsp/dart-sidecar';

interface WorkspaceSearchTelemetry {
  requestedEngine: string;
  engine: string;
  fallbackUsed: boolean;
  fallbackReason?: string | null;
  elapsedMs: number;
  rgSource?: string;
  rgPath?: string | null;
}

interface WorkspaceSearchInvokeResult {
  files: Array<{
    path: string;
    matches: Array<{ line: number; lineContent: string }>;
  }>;
  totalMatches: number;
  truncated: boolean;
  telemetry?: WorkspaceSearchTelemetry;
}

interface WorkspaceSearchRequest {
  query: string;
  rootPath: string;
  isRegex: boolean;
  includeHidden: boolean;
  caseSensitive: boolean;
  includePattern: string;
  excludePattern: string;
}

interface WorkspaceSearchAttempt {
  result: WorkspaceSearchInvokeResult;
  fallbackNote: string | null;
}

function formatSearchEngineLabel(telemetry: {
  engine?: string | null;
  rgSource?: string | null;
  fallbackUsed?: boolean;
}): string {
  const engine = telemetry.engine ?? 'unknown';
  if (engine === 'rg') {
    if (telemetry.rgSource === 'bundled') return 'rg-bundled';
    if (telemetry.rgSource === 'system') return 'rg-system';
    return 'rg';
  }
  if (engine === 'legacy' && telemetry.fallbackUsed) {
    return 'legacy-fallback';
  }
  return engine;
}

function formatFallbackLabel(telemetry: {
  engine?: string | null;
  fallbackUsed?: boolean;
  fallbackReason?: string | null;
}): string | null {
  if (!telemetry.fallbackUsed) return null;
  return telemetry.fallbackReason ?? (telemetry.engine === 'legacy' ? 'legacy-fallback' : 'used');
}

function looksLikeFileOrPathQuery(query: string): boolean {
  const trimmed = query.trim();
  if (!trimmed) return false;

  return (
    /[\\/]/.test(trimmed) ||
    /\.[a-z0-9]{1,8}$/i.test(trimmed) ||
    /^[a-z0-9._-]+\.[a-z0-9]{1,8}$/i.test(trimmed)
  );
}

async function probeFindFilesHint(args: {
  query: string;
  workspaceRoot: string;
  includePattern: string;
  excludePattern: string;
  includeHidden: boolean;
}): Promise<{
  candidates: string[];
  engineLabel: string | null;
  fallbackLabel: string | null;
} | null> {
  try {
    const excludePatterns = args.excludePattern
      ? [args.excludePattern, ...getDefaultExcludePatterns(args.includeHidden)]
      : getDefaultExcludePatterns(args.includeHidden);

    const result = await invoke<{
      files: string[];
      engine: string;
      fallbackUsed: boolean;
      fallbackReason?: string | null;
    }>('find_files_by_name', {
      options: {
        query: args.query,
        rootPath: args.workspaceRoot,
        includeHidden: args.includeHidden,
        includePatterns: args.includePattern ? [args.includePattern] : [],
        excludePatterns,
        maxResults: 5,
      }
    });

    return {
      candidates: Array.isArray(result.files) ? result.files.slice(0, 5) : [],
      engineLabel: typeof result.engine === 'string' ? result.engine : null,
      fallbackLabel: result.fallbackUsed ? (result.fallbackReason ?? 'used') : 'none',
    };
  } catch {
    return null;
  }
}

function getDefaultExcludePatterns(includeHidden: boolean): string[] {
  const patterns = ['node_modules/**', 'target/**', 'dist/**', 'build/**', '.svelte-kit/**'];
  if (!includeHidden) {
    patterns.push('.git/**', '.next/**');
  }
  return patterns;
}

function normalizeWorkspaceRoot(root: string): string {
  return root.replace(/\\/g, '/').replace(/\/+$/, '');
}

function didWorkspaceRootChange(startRoot: string, currentRoot: string): boolean {
  return normalizeWorkspaceRoot(startRoot) !== normalizeWorkspaceRoot(currentRoot);
}

function isCancelledSearchError(error: unknown): boolean {
  if (error && typeof error === 'object') {
    const maybeType = 'type' in error ? (error as { type?: unknown }).type : undefined;
    if (maybeType === 'Cancelled') return true;
  }
  if (error instanceof Error) {
    return /cancelled/i.test(error.message);
  }
  if (typeof error === 'string') {
    return /cancelled/i.test(error);
  }
  return false;
}

async function delay(ms: number): Promise<void> {
  await new Promise((resolve) => setTimeout(resolve, ms));
}

function buildWorkspaceSearchOptions(request: WorkspaceSearchRequest): Record<string, unknown> {
  const { query, rootPath, isRegex, includeHidden, caseSensitive, includePattern, excludePattern } = request;
  const excludePatterns = excludePattern
    ? [excludePattern, ...getDefaultExcludePatterns(includeHidden)]
    : getDefaultExcludePatterns(includeHidden);
  return {
    query,
    rootPath,
    useRegex: isRegex,
    includeHidden,
    caseSensitive,
    includePatterns: includePattern ? [includePattern] : [],
    excludePatterns,
    maxResults: 50,
    requestId: Date.now(),
  };
}

async function runWorkspaceSearchAttempt(
  request: WorkspaceSearchRequest,
): Promise<WorkspaceSearchInvokeResult> {
  const maxAttempts = 3;
  let lastError: unknown;
  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    try {
      return await invoke<WorkspaceSearchInvokeResult>('workspace_search', {
        options: buildWorkspaceSearchOptions(request),
      });
    } catch (error) {
      lastError = error;
      if (!isCancelledSearchError(error) || attempt === maxAttempts - 1) {
        throw error;
      }
      await delay(30 * (attempt + 1));
    }
  }
  throw lastError;
}

async function resolveWorkspaceSearch(
  request: WorkspaceSearchRequest,
): Promise<WorkspaceSearchAttempt> {
  const primary = await runWorkspaceSearchAttempt(request);
  if (primary.totalMatches > 0 || request.isRegex || !request.caseSensitive) {
    return { result: primary, fallbackNote: null };
  }

  const relaxed = await runWorkspaceSearchAttempt({
    ...request,
    caseSensitive: false,
  });
  if (relaxed.totalMatches > 0) {
    return {
      result: relaxed,
      fallbackNote: 'Retried with caseSensitive: false after an exact-scope miss',
    };
  }

  return { result: primary, fallbackNote: null };
}

/**
 * Search workspace for text/regex patterns
 * - Shows 2 lines of context around each match
 * - Groups results by file
 * - Deduplicates overlapping context lines
 * - Caps at 50 matches, truncates long lines at 120 chars
 */
export async function handleWorkspaceSearch(args: Record<string, unknown>): Promise<ToolResult> {
  const query = String(args.query);
  const isRegex = args.isRegex === true;
  const includeHidden = Boolean(args.includeHidden);
  const includePattern = args.includePattern ? String(args.includePattern) : '';
  const excludePattern = args.excludePattern ? String(args.excludePattern) : '';
  const caseSensitive = Boolean(args.caseSensitive);
  const explanation = args.explanation ? String(args.explanation) : '';
  const workspaceRoot = projectStore.rootPath || '';

  if (!query.trim()) {
    return { success: false, error: 'Search query cannot be empty' };
  }

  if (!workspaceRoot) {
    return { success: false, error: 'No workspace open' };
  }

  // Use the include pattern exactly as the AI specified — don't modify it.
  // The AI is smart enough to set its own glob patterns.

  try {
    const { result, fallbackNote } = await resolveWorkspaceSearch({
      query,
      rootPath: workspaceRoot,
      isRegex,
      includeHidden,
      caseSensitive,
      includePattern,
      excludePattern,
    });
    const currentWorkspaceRoot = projectStore.rootPath || '';
    const workspaceChanged = didWorkspaceRootChange(
      workspaceRoot,
      currentWorkspaceRoot,
    );

    if (workspaceChanged) {
      let msg = `Search result is stale for "${query}"`;
      msg += isRegex ? '\nMode: regex' : '\nMode: literal';
      msg += `\nWorkspace root used: ${workspaceRoot}`;
      msg += `\nCurrent workspace root: ${currentWorkspaceRoot || '(none)'}`;
      if (includeHidden) {
        msg += '\nInclude hidden: true';
      }
      if (includePattern) {
        msg += `\nInclude pattern: ${includePattern}`;
      }
      if (result.telemetry) {
        msg += `\nEngine: ${formatSearchEngineLabel(result.telemetry)}`;
        const fallback = formatFallbackLabel(result.telemetry);
        if (fallback) {
          msg += `\nFallback: ${fallback}`;
        }
      }
      msg += '\nThe open workspace changed before this search completed. Retry the search.';
      return {
        success: true,
        output: msg,
        meta: result.telemetry
          ? {
              staleWorkspaceResult: true,
              searchWorkspaceRoot: workspaceRoot,
              currentWorkspaceRoot,
              searchTelemetry: {
                engine: result.telemetry.engine,
                rgSource: result.telemetry.rgSource ?? 'none',
                rgPath: result.telemetry.rgPath ?? null,
                fallbackUsed: result.telemetry.fallbackUsed,
                fallbackReason: result.telemetry.fallbackReason ?? null,
                elapsedMs: result.telemetry.elapsedMs,
              },
            }
          : {
              staleWorkspaceResult: true,
              searchWorkspaceRoot: workspaceRoot,
              currentWorkspaceRoot,
            },
      };
    }

    if (result.totalMatches === 0) {
      // Helpful message with suggestions
      let msg = `No matches for "${query}"`;
      if (isRegex) {
        msg += '\nMode: regex';
        msg += '\nTip: If this was intended as plain text, retry with isRegex: false or omit isRegex.';
      } else {
        msg += '\nMode: literal';
      }
      msg += `\nWorkspace root: ${workspaceRoot}`;
      if (includeHidden) {
        msg += '\nInclude hidden: true';
      }
      if (caseSensitive && !isRegex) {
        msg += '\nTip: Try with caseSensitive: false';
      }
      if (includePattern) {
        msg += `\nInclude pattern: ${includePattern}`;
      }
      if (excludePattern) {
        msg += `\nExclude pattern: ${excludePattern}`;
      }
      if (result.telemetry) {
        msg += `\nEngine: ${formatSearchEngineLabel(result.telemetry)}`;
        const fallback = formatFallbackLabel(result.telemetry);
        if (fallback) {
          msg += `\nFallback: ${fallback}`;
        }
      }
      if (fallbackNote) {
        msg += `\n${fallbackNote}`;
      }
      if (!isRegex && looksLikeFileOrPathQuery(query)) {
        msg += '\nHint: This query looks like a filename/path. Prefer find_files for path discovery before content search.';
        const fileHint = await probeFindFilesHint({
          query,
          workspaceRoot,
          includePattern,
          excludePattern,
          includeHidden,
        });
        if (fileHint) {
          if (fileHint.engineLabel) {
            msg += `\nFind-files backend: ${formatSearchEngineLabel({ engine: fileHint.engineLabel, fallbackUsed: fileHint.fallbackLabel !== 'none' })}`;
          }
          if (fileHint.fallbackLabel && fileHint.fallbackLabel !== 'none') {
            msg += `\nFind-files fallback: ${fileHint.fallbackLabel}`;
          }
          if (fileHint.candidates.length > 0) {
            msg += '\nPossible file/path matches:';
            for (const candidate of fileHint.candidates) {
              msg += `\n  ${candidate}`;
            }
          }
        }
      }
      return { success: true, output: msg };
    }

    // Format output - clean, scannable format
    const lines: string[] = [];
    const fileCount = result.files.length;
    const matchCount = result.totalMatches;

    lines.push(`Found ${matchCount} match${matchCount > 1 ? 'es' : ''} in ${fileCount} file${fileCount > 1 ? 's' : ''}`);
    lines.push(`Workspace root: ${workspaceRoot}`);
    if (includeHidden) {
      lines.push('Include hidden: true');
    }
    if (result.telemetry) {
      const fallbackLabel = formatFallbackLabel(result.telemetry);
      const fallback = fallbackLabel ? `, fallback: ${fallbackLabel}` : '';
      lines.push(`Engine: ${formatSearchEngineLabel(result.telemetry)} (${result.telemetry.elapsedMs}ms${fallback})`);
    }
    if (includePattern) {
      lines.push(`Include pattern: ${includePattern}`);
    }
    if (excludePattern) {
      lines.push(`Exclude pattern: ${excludePattern}`);
    }
    if (fallbackNote) {
      lines.push(fallbackNote);
    }
    if (result.truncated) {
      lines.push('(results truncated)');
    }
    lines.push('');

    // Process each file - limit to 10 files to prevent context overflow
    const maxFilesToShow = 10;
    for (const file of result.files.slice(0, maxFilesToShow)) {
      const relativePath = file.path.replace(workspaceRoot, '').replace(/^[/\\]/, '');

      // Get file content for context (skip for very large match counts to save time)
      let fileLines: string[] = [];
      if (file.matches.length <= 10) {
        try {
          const doc = await fileService.read(file.path, true);
          if (doc) {
            fileLines = doc.content.split('\n');
          }
        } catch {
          // Continue without context
        }
      }

      lines.push(`── ${relativePath} (${file.matches.length} match${file.matches.length > 1 ? 'es' : ''}) ──`);

      // Track which lines we've shown to avoid duplicates
      const shownLines = new Set<number>();

      for (const match of file.matches.slice(0, 5)) {
        const lineNum = match.line;

        // Skip if we already showed this line in previous context
        if (shownLines.has(lineNum)) continue;

        if (fileLines.length > 0) {
          // Calculate context range (2 lines before and after)
          const contextStart = Math.max(0, lineNum - 3);
          const contextEnd = Math.min(fileLines.length - 1, lineNum + 1);

          // Show context, skipping already-shown lines
          for (let i = contextStart; i <= contextEnd; i++) {
            if (shownLines.has(i + 1)) continue;
            shownLines.add(i + 1);

            const num = String(i + 1).padStart(4, ' ');
            const content = truncateLine(fileLines[i] || '', 120);
            const isMatch = i + 1 === lineNum;

            const marker = isMatch ? '>' : ' ';
            lines.push(`${marker}${num} │ ${content}`);
          }
          lines.push('');
        } else {
          // No file content available - show just the match
          const num = String(lineNum).padStart(4, ' ');
          lines.push(`${num} │ ${truncateLine(match.lineContent.trim(), 120)}`);
        }
      }

      if (file.matches.length > 5) {
        lines.push(`     ... +${file.matches.length - 5} more matches in this file`);
        lines.push('');
      }
    }

    if (result.files.length > maxFilesToShow) {
      lines.push(`\n... and ${result.files.length - maxFilesToShow} more files with matches`);
      lines.push('Tip: Use includePattern to narrow search, e.g. "**/*.svelte"');
    }

    // Add navigation hint
    lines.push('');
    lines.push('Use read_file with offset/limit to see focused context.');

    const { text, truncated } = truncateOutput(lines.join('\n'));
    return {
      success: true,
      output: text,
      truncated,
      meta: result.telemetry
        ? {
            searchWorkspaceRoot: workspaceRoot,
            searchTelemetry: {
              engine: result.telemetry.engine,
              rgSource: result.telemetry.rgSource ?? 'none',
              rgPath: result.telemetry.rgPath ?? null,
              fallbackUsed: result.telemetry.fallbackUsed,
              fallbackReason: result.telemetry.fallbackReason ?? null,
              elapsedMs: result.telemetry.elapsedMs,
            },
          }
        : undefined,
    };

  } catch (err) {
    const message = err instanceof Error
      ? err.message
      : typeof err === 'object' && err !== null
        ? JSON.stringify(err)
        : String(err);
    if (/regex|pattern/i.test(message)) {
      const hint = isRegex
        ? 'The regex appears invalid. Fix the pattern or retry with isRegex: false for literal text search.'
        : 'The query appears to contain regex-like characters. Retry without regex mode or escape special characters.';
      return { success: false, error: `Search failed: ${message}\nHint: ${hint}` };
    }
    return { success: false, error: `Search failed: ${message}` };
  }
}

/**
 * Truncate a line to max length, preserving word boundaries
 */
function truncateLine(line: string, maxLen: number): string {
  if (line.length <= maxLen) return line;

  // Try to break at a word boundary
  const truncated = line.slice(0, maxLen);
  const lastSpace = truncated.lastIndexOf(' ');

  if (lastSpace > maxLen * 0.7) {
    return truncated.slice(0, lastSpace) + '...';
  }

  return truncated + '...';
}

/**
 * Find files by name (fuzzy search)
 * - Groups by directory for easier scanning
 * - Shows file type extension
 */
export async function handleFindFiles(args: Record<string, unknown>): Promise<ToolResult> {
  const query = String(args.query);

  if (!query.trim()) {
    return { success: false, error: 'Search query cannot be empty' };
  }

  const workspaceRoot = projectStore.rootPath || '';
  const includePattern = args.includePattern ? String(args.includePattern) : '';
  const excludePattern = args.excludePattern ? String(args.excludePattern) : '';
  const includeHidden = Boolean(args.includeHidden);
  const excludePatterns = excludePattern
    ? [excludePattern, ...getDefaultExcludePatterns(includeHidden)]
    : getDefaultExcludePatterns(includeHidden);

  function getErrorMessage(error: unknown): string {
    if (error instanceof Error) return error.message;
    if (typeof error === 'string') return error;
    try {
      return JSON.stringify(error);
    } catch {
      return String(error);
    }
  }

  try {
    let results: Array<{ name: string; relativePath: string }>;
    let engineLabel = 'unknown';
    let rgSource: string | null = null;
    let rgPath: string | null = null;
    let elapsedMs = 0;
    let fallbackUsed = false;
    let fallbackReason: string | null = null;

    const backendResult = await invoke<{
      files: string[];
      totalFiles: number;
      truncated: boolean;
      engine: string;
      fallbackUsed: boolean;
      fallbackReason?: string | null;
      elapsedMs: number;
      rgSource?: string | null;
      rgPath?: string | null;
    }>('find_files_by_name', {
      options: {
        query,
        rootPath: workspaceRoot,
        includeHidden,
        engine: 'rg',
        includePatterns: includePattern ? [includePattern] : [],
        excludePatterns,
        maxResults: 25,
      }
    });
    const currentWorkspaceRoot = projectStore.rootPath || '';
    const workspaceChanged = didWorkspaceRootChange(
      workspaceRoot,
      currentWorkspaceRoot,
    );
    engineLabel = backendResult.engine;
    rgSource = backendResult.rgSource ?? null;
    rgPath = backendResult.rgPath ?? null;
    elapsedMs = backendResult.elapsedMs ?? 0;
    fallbackUsed = backendResult.fallbackUsed;
    fallbackReason = backendResult.fallbackReason ?? null;
    results = backendResult.files.map((relativePath) => ({
      relativePath,
      name: relativePath.split('/').pop() || relativePath,
    }));

    if (workspaceChanged) {
      let msg = `Find files result is stale for "${query}"`;
      msg += `\nWorkspace root used: ${workspaceRoot}`;
      msg += `\nCurrent workspace root: ${currentWorkspaceRoot || '(none)'}`;
      if (includePattern) {
        msg += `\nInclude pattern: ${includePattern}`;
      }
      msg += `\nSearch backend: ${formatSearchEngineLabel({ engine: engineLabel, rgSource, fallbackUsed })}`;
      const fallback = formatFallbackLabel({ engine: engineLabel, fallbackUsed, fallbackReason });
      if (fallback) {
        msg += `\nFallback: ${fallback}`;
      }
      msg += '\nThe open workspace changed before this search completed. Retry the search.';
      return {
        success: true,
        output: msg,
        meta: {
          staleWorkspaceResult: true,
          searchWorkspaceRoot: workspaceRoot,
          currentWorkspaceRoot,
          searchTelemetry: {
            engine: engineLabel,
            rgSource: rgSource ?? (engineLabel === 'rg' ? 'unknown' : 'none'),
            rgPath,
            fallbackUsed,
            fallbackReason,
            elapsedMs,
          },
        },
      };
    }

    if (results.length === 0) {
      // Helpful suggestions
      let msg = `No files matching "${query}"`;
      msg += `\nWorkspace root: ${workspaceRoot}`;
      if (includePattern) {
        msg += `\nInclude pattern: ${includePattern}`;
      }
      if (query.includes('.')) {
        msg += `\nTip: Try without extension, e.g. "${query.split('.')[0]}"`;
      }
      if (query.length < 3) {
        msg += '\nTip: Try a longer search term';
      }
      msg += `\nSearch backend: ${formatSearchEngineLabel({ engine: engineLabel, rgSource, fallbackUsed })}`;
      const fallback = formatFallbackLabel({ engine: engineLabel, fallbackUsed, fallbackReason });
      if (fallback) {
        msg += `\nFallback: ${fallback}`;
      }
      return { success: true, output: msg };
    }

    // Format with file type indicators and grouping
    const lines: string[] = [];
    lines.push(`Found ${results.length} file${results.length > 1 ? 's' : ''} matching "${query}":`);
    lines.push(`Workspace root: ${workspaceRoot}`);
    lines.push(`Search backend: ${formatSearchEngineLabel({ engine: engineLabel, rgSource, fallbackUsed })}`);
    const fallback = formatFallbackLabel({ engine: engineLabel, fallbackUsed, fallbackReason });
    if (fallback) {
      lines.push(`Fallback: ${fallback}`);
    }
    if (includePattern) {
      lines.push(`Include pattern: ${includePattern}`);
    }
    lines.push('');

    // Group by parent directory for easier scanning
    const byDir = new Map<string, typeof results>();
    for (const file of results) {
      const parts = file.relativePath.split('/');
      const dir = parts.length > 1 ? parts.slice(0, -1).join('/') : '.';
      if (!byDir.has(dir)) byDir.set(dir, []);
      byDir.get(dir)!.push(file);
    }

    // If all in same dir or few results, show flat list
    if (byDir.size <= 2 || results.length <= 8) {
      for (const file of results) {
        lines.push(`  ${file.relativePath}`);
      }
    } else {
      // Group by directory
      for (const [dir, files] of byDir) {
        if (files.length === 0) continue;
        lines.push(`${dir}/`);
        for (const file of files) {
          lines.push(`  ${file.name}`);
        }
      }
    }

    // Add helpful hint
    lines.push('');
    lines.push('Use read_file to view contents.');

    return {
      success: true,
        output: lines.join('\n'),
        meta: {
          searchWorkspaceRoot: workspaceRoot,
          searchTelemetry: {
            engine: engineLabel,
            rgSource: rgSource ?? (engineLabel === 'rg' ? 'unknown' : 'none'),
            rgPath,
            fallbackUsed,
            fallbackReason,
            elapsedMs,
          },
        },
      };

  } catch (err) {
    const message = err instanceof Error
      ? err.message
      : typeof err === 'object' && err !== null
        ? JSON.stringify(err)
        : String(err);
    return { success: false, error: `Find failed: ${message}` };
  }
}



/**
 * Search for symbols (functions, classes, variables) using LSP
 * Uses workspace symbol queries from connected LSPs with regex text fallback.
 */
export async function handleSearchSymbols(args: Record<string, unknown>): Promise<ToolResult> {
  const query = String(args.query);
  const kindFilter = args.kind ? String(args.kind).toLowerCase() : null;
  const workspaceRoot = projectStore.rootPath || '';

  if (!workspaceRoot) {
    return { success: false, error: 'No workspace open' };
  }

  try {
    // Use workspace symbol search from LSP - query all active LSPs
    let symbols: any[] = [];

    // Query TypeScript LSP if connected
    if (isTsLspConnected()) {
      const tsSymbols = await getTsWorkspaceSymbols(query);
      if (tsSymbols) symbols = symbols.concat(tsSymbols);
    }

    // Query Dart LSP if running
    if (isDartLspRunning()) {
      const dartSymbols = await getDartWorkspaceSymbols(query);
      if (dartSymbols) symbols = symbols.concat(dartSymbols);
    }

    // If no symbols from active LSPs, try to start them if they should be there
    if (symbols.length === 0) {
      // Logic to bootstrap LSP for symbol search if needed
      // (Simplified for now: if no symbols, proceed to fallback)
    }

    if (!symbols || symbols.length === 0) {
      // Fallback: use text search for the symbol name
      const fallbackResult = await handleWorkspaceSearch({
        query: `\\b${query}\\b`,
        includePattern: '**/*.{ts,tsx,js,jsx,svelte,vue,dart}',
        caseSensitive: true
      });

      if (fallbackResult.success && fallbackResult.output) {
        return {
          success: true,
          output: `No LSP symbols found. Text search results:\n${fallbackResult.output}`
        };
      }

      return { success: true, output: `No symbols matching "${query}"` };
    }

    // Map LSP symbol kinds to readable names
    const kindNames: Record<number, string> = {
      1: 'file', 2: 'module', 3: 'namespace', 4: 'package',
      5: 'class', 6: 'method', 7: 'property', 8: 'field',
      9: 'constructor', 10: 'enum', 11: 'interface', 12: 'function',
      13: 'variable', 14: 'constant', 15: 'string', 16: 'number',
      17: 'boolean', 18: 'array', 19: 'object', 20: 'key',
      21: 'null', 22: 'enum_member', 23: 'struct', 24: 'event',
      25: 'operator', 26: 'type_parameter'
    };

    // Filter by kind if specified
    let filtered = symbols;
    if (kindFilter) {
      const kindMap: Record<string, number[]> = {
        'function': [6, 12], // method, function
        'class': [5],
        'variable': [13, 14], // variable, constant
        'type': [11, 26], // interface, type_parameter
        'interface': [11],
        'enum': [10],
        'property': [7, 8], // property, field
      };
      const allowedKinds = kindMap[kindFilter] || [];
      if (allowedKinds.length > 0) {
        filtered = symbols.filter(s => allowedKinds.includes(s.kind));
      }
    }

    // Format results
    const results = filtered.slice(0, 20).map(s => {
      const kindName = kindNames[s.kind] || 'symbol';
      const filePath = s.location.uri.replace('file://', '').replace(workspaceRoot, '').replace(/^[/\\]/, '');
      const line = s.location.range.start.line + 1;
      const container = s.containerName ? ` (in ${s.containerName})` : '';
      return `${s.name} [${kindName}] - ${filePath}:${line}${container}`;
    });

    const { text } = truncateOutput(
      `Found ${filtered.length} symbols:\n${results.join('\n')}`
    );

    return { success: true, output: text };

  } catch (err) {
    // LSP not available - fallback to text search with broader pattern
    // Covers: function declarations, arrow functions, class/interface/type/enum,
    // const/let/var assignments, Dart keywords, decorators/annotations
    const fallbackResult = await handleWorkspaceSearch({
      query: `(function|class|const|let|var|interface|type|enum|export|def|fn|pub|async|final|late|dynamic|@)\\s*${query}\\b|\\b${query}\\s*(=|:)\\s*(\\(|async|function|class)`,
      includePattern: '**/*.{ts,tsx,js,jsx,svelte,vue,dart,rs,py,go}',
      caseSensitive: false
    });

    if (fallbackResult.success && fallbackResult.output) {
      return {
        success: true,
        output: `Symbol search (text fallback):\n${fallbackResult.output}`
      };
    }

    return { success: false, error: `Symbol search failed: ${err}` };
  }
}

interface PatchHunkLine {
  op: 'context' | 'remove' | 'add';
  text: string;
}

export interface ParsedPatchHunk {
  lines: PatchHunkLine[];
}

export interface ParsedCodexPatch {
  path: string;
  hunks: ParsedPatchHunk[];
  mode: 'update' | 'add';
}

export function getCodexPatchLineStats(
  hunks: ParsedPatchHunk[],
): { added: number; removed: number } {
  let added = 0;
  let removed = 0;

  for (const hunk of hunks) {
    for (const line of hunk.lines) {
      if (line.op === 'add') added++;
      else if (line.op === 'remove') removed++;
    }
  }

  return { added, removed };
}

function normalizePatchText(patch: string): string {
  const normalized = patch.replace(/\r\n/g, '\n').trim();

  // Accept fenced output wrappers (```diff ... ``` / ```patch ... ```)
  const fenced = normalized.match(/```(?:diff|patch|text)?\s*\n([\s\S]*?)\n```/i);
  let text = fenced ? fenced[1].trim() : normalized;

  const rawLines = text.split('\n');

  // Tolerate leading VCS headers before Codex patch body.
  const linesWithoutVcsHeaders = rawLines.filter(
    (line) =>
      !(
        line.startsWith('diff --git ') ||
        line.startsWith('index ') ||
        line.startsWith('--- ') ||
        line.startsWith('+++ ')
      ),
  );

  const maybeInsertMissingInitialHunk = (lines: string[]): string[] => {
    if (lines.length < 3) return lines;

    const hasWrapper = lines[0] === '*** Begin Patch';
    const fileHeaderIndex = hasWrapper ? 1 : 0;
    const bodyStartIndex = hasWrapper ? 2 : 1;
    const fileHeader = lines[fileHeaderIndex];
    const firstBodyLine = lines[bodyStartIndex];
    const looksLikeFilePatch =
      fileHeader?.startsWith('*** Update File: ') || fileHeader?.startsWith('*** Add File: ');
    const looksLikeMissingInitialHunk =
      looksLikeFilePatch &&
      firstBodyLine !== undefined &&
      !firstBodyLine.startsWith('@@') &&
      /^[ +\-]/.test(firstBodyLine);

    if (!looksLikeMissingInitialHunk) return lines;

    const next = [...lines];
    next.splice(bodyStartIndex, 0, '@@');
    return next;
  };

  // If body already starts with explicit codex header/footer, keep as-is.
  if (
    linesWithoutVcsHeaders[0] === '*** Begin Patch' &&
    linesWithoutVcsHeaders[linesWithoutVcsHeaders.length - 1] === '*** End Patch'
  ) {
    return maybeInsertMissingInitialHunk(linesWithoutVcsHeaders).join('\n');
  }

  // Common near-miss: model emits "*** Update File" + hunks but forgets Begin/End wrapper.
  if (
    linesWithoutVcsHeaders[0]?.startsWith('*** Update File: ') ||
    linesWithoutVcsHeaders[0]?.startsWith('*** Add File: ')
  ) {
    const bodyLines = maybeInsertMissingInitialHunk(linesWithoutVcsHeaders);

    const wrapped = ['*** Begin Patch', ...bodyLines];
    if (wrapped[wrapped.length - 1] !== '*** End Patch') {
      wrapped.push('*** End Patch');
    }
    return wrapped.join('\n');
  }

  // Another near-miss: wrapper exists but footer is missing.
  if (linesWithoutVcsHeaders[0] === '*** Begin Patch') {
    const wrapped = maybeInsertMissingInitialHunk(linesWithoutVcsHeaders);
    if (wrapped[wrapped.length - 1] !== '*** End Patch') {
      wrapped.push('*** End Patch');
    }
    return wrapped.join('\n');
  }

  text = linesWithoutVcsHeaders.join('\n').trim();
  return text;
}

function parseHunkLine(raw: string, lineNo: number): PatchHunkLine {
  if (raw.length === 0) {
    throw new Error(
      `Malformed patch: invalid patch line at ${lineNo}. Expected prefix " ", "-" or "+".`,
    );
  }
  const marker = raw[0];
  if (marker !== ' ' && marker !== '-' && marker !== '+') {
    throw new Error(
      `Malformed patch: invalid patch line at ${lineNo}. Expected prefix " ", "-" or "+".`,
    );
  }
  return {
    op: marker === ' ' ? 'context' : marker === '-' ? 'remove' : 'add',
    text: raw.slice(1),
  };
}

export function parseCodexPatch(patch: string): ParsedCodexPatch {
  const text = normalizePatchText(patch);
  const lines = text.split('\n');
  if (lines.length < 3 || lines[0] !== '*** Begin Patch') {
    throw new Error('Malformed patch: expected "*** Begin Patch" header.');
  }
  if (lines[lines.length - 1] !== '*** End Patch') {
    throw new Error('Malformed patch: expected "*** End Patch" footer.');
  }

  const fileLine = lines[1];
  const isUpdate = fileLine.startsWith('*** Update File: ');
  const isAdd = fileLine.startsWith('*** Add File: ');
  if (!isUpdate && !isAdd) {
    throw new Error('Malformed patch: only "*** Update File: <path>" or "*** Add File: <path>" is supported.');
  }
  const path = fileLine
    .slice(isUpdate ? '*** Update File: '.length : '*** Add File: '.length)
    .trim();
  if (!path) {
    throw new Error(`Malformed patch: missing file path in "${isUpdate ? '*** Update File' : '*** Add File'}".`);
  }

  const hunks: ParsedPatchHunk[] = [];
  let i = 2;
  while (i < lines.length - 1) {
    const line = lines[i];
    if (!line.startsWith('@@')) {
      throw new Error(`Malformed patch: expected "@@" hunk header at line ${i + 1}.`);
    }
    i++;
    const hunkLines: PatchHunkLine[] = [];
    while (i < lines.length - 1 && !lines[i].startsWith('@@')) {
      hunkLines.push(parseHunkLine(lines[i], i + 1));
      i++;
    }
    if (hunkLines.length === 0) {
      throw new Error('Malformed patch: empty hunk is not allowed.');
    }
    hunks.push({ lines: hunkLines });
  }

  if (hunks.length === 0) {
    throw new Error('Malformed patch: no hunks found.');
  }

  return { path, hunks, mode: isAdd ? 'add' : 'update' };
}

function findSubsequence(
  lines: string[],
  pattern: string[],
  startAt: number,
): number {
  if (pattern.length === 0) {
    return startAt;
  }
  const max = lines.length - pattern.length;
  for (let i = startAt; i <= max; i++) {
    let match = true;
    for (let j = 0; j < pattern.length; j++) {
      if (lines[i + j] !== pattern[j]) {
        match = false;
        break;
      }
    }
    if (match) return i;
  }
  return -1;
}

export function applyCodexPatch(content: string, hunks: ParsedPatchHunk[]): string {
  const inputLines = content.replace(/\r\n/g, '\n').split('\n');
  const output: string[] = [];
  let cursor = 0;

  for (const hunk of hunks) {
    const oldSegment = hunk.lines
      .filter((line) => line.op !== 'add')
      .map((line) => line.text);
    const newSegment = hunk.lines
      .filter((line) => line.op !== 'remove')
      .map((line) => line.text);

    const at = findSubsequence(inputLines, oldSegment, cursor);
    if (at < 0) {
      throw new Error('Patch apply failed: context mismatch. Try a smaller patch or refresh file state if needed.');
    }

    while (cursor < at) {
      output.push(inputLines[cursor]);
      cursor++;
    }
    for (const line of newSegment) {
      output.push(line);
    }
    cursor = at + oldSegment.length;
  }

  while (cursor < inputLines.length) {
    output.push(inputLines[cursor]);
    cursor++;
  }

  return output.join('\n');
}

export interface ToolResult {
  success: boolean;
  output?: string;
  error?: string;
  truncated?: boolean;
  meta?: Record<string, any>;
  data?: any;
  warnings?: string[];
  tool?: string;
  code?: string;
  retryable?: boolean;
  timestamp?: number;
}

export interface CanonicalToolResult {
  success: boolean;
  output: string;
  error: string;
  data: any;
  meta: Record<string, any>;
  warnings: string[];
  tool: string;
  code: string;
  retryable: boolean;
  timestamp: number;
  truncated?: boolean;
}

/**
 * AI Tool Router
 * 
 * Clean architecture:
 * - router.ts: validation + dispatch (this file)
 * - definitions.ts: tool schemas
 * - utils.ts: shared helpers
 * - handlers/: individual tool implementations
 */

import { projectStore } from '$shared/stores/project.svelte';
import { assistantStore } from '$features/assistant/stores/assistant.svelte';
import {
  getAllToolsForMode,
  getToolByName,
  isToolAllowed,
  RETIRED_TOOL_NAMES,
} from '$core/ai/tools/definitions';
import {
  normalizeToolOutputBudget,
  validatePathInWorkspace,
  type ToolResult,
  type CanonicalToolResult,
} from '$core/ai/tools/utils';
import { toolHandlers } from '$core/ai/tools/handlers';
import { isMcpTool, executeMcpTool, isMcpToolAutoApproved, getMcpToolInfo } from '$core/ai/tools/handlers/mcp';
import type { AIMode } from '$features/assistant/stores/ai.svelte';
import { getToolCapabilities } from '$core/ai/tools/capabilities';
import { toolObservabilityStore } from '$features/assistant/stores/tool-observability.svelte';
import { agentTelemetryStore } from '$features/assistant/stores/agent-telemetry.svelte';
import { afterToolHook, beforeToolHook } from '$core/ai/tools/hooks';
import type { ToolRuntimeContext } from '$core/ai/tools/runtime';

// Timeout for tool operations (30 seconds default)
const DEFAULT_TIMEOUT_MS = 30000;
const MAX_TIMEOUT_MS = 5 * 60 * 1000; // 5 minutes max
const TERMINAL_TOOL_DEFAULT_TIMEOUT_MS = MAX_TIMEOUT_MS;
const HIDDEN_HANDLER_NAMES = new Set([
  'lsp_go_to_definition',
  'lsp_find_references',
  'lsp_get_hover',
  'lsp_rename_symbol',
]);
const TOOL_MAX_ATTEMPTS: Record<string, number> = {};
const TOOL_NAME_ALIASES: Record<string, string> = {
  shell_command: 'run_command',
};

export function normalizeToolName(toolName: string): string {
  const trimmed = toolName.trim();
  return TOOL_NAME_ALIASES[trimmed] ?? trimmed;
}

/**
 * Tool execution options
 */
export interface ToolExecutionOptions {
  signal?: AbortSignal;
  idempotencyKey?: string;
  runtime?: ToolRuntimeContext;
}

/**
 * Tool validation result
 */
export interface ToolValidation {
  valid: boolean;
  error?: string;
  requiresApproval: boolean;
}

// Re-export ToolResult types for convenience
export type { ToolResult, CanonicalToolResult } from '$core/ai/tools/utils';

const IDEMPOTENCY_RESULT_TTL_MS = 2 * 60 * 1000;
const idempotentResultCache = new Map<string, { result: CanonicalToolResult; expiresAt: number }>();
const idempotentInFlight = new Map<string, Promise<CanonicalToolResult>>();

/**
 * Validate a tool call before execution
 */
export function validateToolCall(
  toolName: string,
  args: Record<string, unknown>,
  mode: AIMode
): ToolValidation {
  const canonicalToolName = normalizeToolName(toolName);
  // Check if it's an MCP tool
  if (isMcpTool(canonicalToolName)) {
    // MCP tools are allowed in agent and spec mode only
    if (mode !== 'agent' && mode !== 'spec') {
      return {
        valid: false,
        error: `MCP tools are only available in agent or spec mode`,
        requiresApproval: false
      };
    }

    // Check if auto-approved
    const requiresApproval = !isMcpToolAutoApproved(canonicalToolName);
    return { valid: true, requiresApproval };
  }

  // Check if tool exists
  const tool = getToolByName(canonicalToolName);
  if (!tool) {
    if (RETIRED_TOOL_NAMES.has(canonicalToolName)) {
      return {
        valid: false,
        error: `Tool "${canonicalToolName}" was removed from strict profile. Use read_file/workspace_search/apply_patch/run_command equivalents.`,
        requiresApproval: false,
      };
    }
    const suggestion = suggestToolName(canonicalToolName, mode);
    const suffix = suggestion ? ` Did you mean "${suggestion}"?` : '';
    return { valid: false, error: `Unknown tool: ${canonicalToolName}.${suffix}`, requiresApproval: false };
  }
  // If tool is in definitions, proceed to mode/param checks

  // Check if tool is allowed in current mode
  if (!isToolAllowed(canonicalToolName, mode)) {
    return {
      valid: false,
      error: `Tool "${canonicalToolName}" not allowed in ${mode} mode`,
      requiresApproval: false
    };
  }

  // Validate required parameters
  const paramError = validateRequiredParams(canonicalToolName, args);
  if (paramError) {
    return { valid: false, error: paramError, requiresApproval: false };
  }
  if (
    canonicalToolName === 'read_file' &&
    (typeof args.start_line === 'number' ||
      typeof args.end_line === 'number' ||
      typeof args.startLine === 'number' ||
      typeof args.endLine === 'number')
  ) {
    return {
      valid: false,
      error: 'read_file now requires Codex-style slice args: use "offset" and "limit" (line-based).',
      requiresApproval: false,
    };
  }

  // Validate path is within workspace (if path param exists)
  const workspaceRoot = projectStore.rootPath;
  const capabilities = getToolCapabilities(canonicalToolName);
  if (workspaceRoot && capabilities.requiresWorkspacePathValidation) {
    const pathsToValidate = collectPaths(args);
    for (const path of pathsToValidate) {
      const pathValidation = validatePathInWorkspace(path, workspaceRoot);
      if (!pathValidation.valid) {
        return { valid: false, error: pathValidation.error, requiresApproval: false };
      }
    }
  }

  return {
    valid: true,
    requiresApproval: capabilities.requiresApproval
  };
}

function collectPaths(args: Record<string, unknown>): string[] {
  const paths: string[] = [];
  const addPath = (value: unknown): void => {
    if (typeof value === 'string' && value.trim().length > 0) {
      paths.push(value);
    }
  };

  addPath(args.path);
  addPath(args.oldPath);
  addPath(args.newPath);
  addPath(args.cwd);

  if (Array.isArray(args.paths)) {
    for (const value of args.paths) {
      addPath(value);
    }
  }

  return paths;
}

/**
 * Validate required parameters for each tool
 */
function validateRequiredParams(toolName: string, args: Record<string, unknown>): string | null {
  const requireString = (key: string, altKey?: string): string | null => {
    const val = args[key] ?? (altKey ? args[altKey] : undefined);
    if (typeof val === 'string' && val.trim().length > 0) return null;
    return `Missing "${key}"`;
  };

  switch (toolName) {
    // Read tools
    case 'list_dir':
    case 'read_file':
    case 'get_file_info':
      return requireString('path');

    case 'workspace_search':
      return requireString('query');

    // Write tools
    case 'apply_patch': {
      const pathErr = requireString('path');
      if (pathErr) return pathErr;
      return requireString('patch');
    }

    // Terminal tools
    case 'run_command':
      return requireString('command');

    // Browser tools - read-only
    // No required params
    case 'get_diagnostics':
      return null;

    case 'attempt_completion':
      return requireString('result');

    default:
      return validateRequiredParamsFromSchema(toolName, args);
  }
}

function validateRequiredParamsFromSchema(
  toolName: string,
  args: Record<string, unknown>,
): string | null {
  const tool = getToolByName(toolName);
  if (!tool) return null;

  const schema = tool.parameters as Record<string, unknown>;
  const required = schema.required;
  if (!Array.isArray(required) || required.length === 0) return null;

  for (const key of required) {
    if (typeof key !== 'string') continue;
    const value = args[key];
    const missingString = typeof value === 'string' && value.trim().length === 0;
    if (value === undefined || value === null || missingString) {
      return `Missing "${key}"`;
    }
  }

  return null;
}

export function getToolContractParity(): {
  missingHandlers: string[];
  orphanHandlers: string[];
} {
  const definedTools = new Set([
    ...getAllToolsForMode('ask').map((tool) => tool.name),
    ...getAllToolsForMode('plan').map((tool) => tool.name),
    ...getAllToolsForMode('spec').map((tool) => tool.name),
    ...getAllToolsForMode('agent').map((tool) => tool.name),
  ]);
  const handlerTools = new Set(Object.keys(toolHandlers));

  const missingHandlers = [...definedTools]
    .filter((name) => !handlerTools.has(name) && !isMcpTool(name))
    .sort();

  const orphanHandlers = [...handlerTools]
    .filter(
      (name) =>
        !definedTools.has(name) &&
        !getToolByName(name) &&
        !HIDDEN_HANDLER_NAMES.has(name) &&
        !RETIRED_TOOL_NAMES.has(name) &&
        !isMcpTool(name),
    )
    .sort();

  return { missingHandlers, orphanHandlers };
}

function normalizeToolToken(value: string): string {
  return value.toLowerCase().replace(/[-_\s]+/g, '');
}

function suggestToolName(toolName: string, mode: AIMode): string | null {
  const available = getAllToolsForMode(mode).map((tool) => tool.name);
  if (available.length === 0) return null;

  const normalized = normalizeToolToken(toolName);
  const exactNormalized = available.find((name) => normalizeToolToken(name) === normalized);
  if (exactNormalized) return exactNormalized;

  const prefixMatch = available.find((name) => name.startsWith(toolName) || toolName.startsWith(name));
  if (prefixMatch) return prefixMatch;

  let best: { name: string; distance: number } | null = null;
  for (const candidate of available) {
    const distance = levenshteinDistance(normalizeToolToken(candidate), normalized);
    if (!best || distance < best.distance) {
      best = { name: candidate, distance };
    }
  }

  if (!best) return null;
  return best.distance <= 6 ? best.name : null;
}

function levenshteinDistance(a: string, b: string): number {
  if (a === b) return 0;
  if (a.length === 0) return b.length;
  if (b.length === 0) return a.length;

  const rows = a.length + 1;
  const cols = b.length + 1;
  const matrix: number[][] = Array.from({ length: rows }, () => Array(cols).fill(0));

  for (let i = 0; i < rows; i++) matrix[i][0] = i;
  for (let j = 0; j < cols; j++) matrix[0][j] = j;

  for (let i = 1; i < rows; i++) {
    for (let j = 1; j < cols; j++) {
      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
      matrix[i][j] = Math.min(
        matrix[i - 1][j] + 1,
        matrix[i][j - 1] + 1,
        matrix[i - 1][j - 1] + cost,
      );
    }
  }

  return matrix[rows - 1][cols - 1];
}

/**
 * Execute a tool call
 */
export async function executeToolCall(
  toolName: string,
  args: Record<string, unknown>,
  options: ToolExecutionOptions = {}
): Promise<CanonicalToolResult> {
  const canonicalToolName = normalizeToolName(toolName);
  const { signal, idempotencyKey } = options;
  const signature = createToolSignature(canonicalToolName, args);

  purgeExpiredIdempotencyCache();

  if (idempotencyKey) {
    const cached = idempotentResultCache.get(idempotencyKey);
    if (cached && cached.expiresAt > Date.now()) {
      const replayMeta: Record<string, any> = {
        ...(cached.result.meta ?? {}),
        replayed: true,
        idempotencyKey,
        signature,
      };
      const replayResult = {
        ...cached.result,
        timestamp: Date.now(),
        meta: replayMeta,
      };
      toolObservabilityStore.record({
        timestamp: Date.now(),
        toolName: canonicalToolName,
        signature,
        idempotencyKey,
        durationMs: 0,
        success: replayResult.success,
        code: replayResult.code,
        retryable: replayResult.retryable,
        attempt: Number(replayMeta.attempts ?? 1),
        maxAttempts: Number(replayMeta.maxAttempts ?? 1),
        replayed: true,
      });
      return replayResult;
    }

    const inFlight = idempotentInFlight.get(idempotencyKey);
    if (inFlight) {
      toolObservabilityStore.record({
        timestamp: Date.now(),
        toolName: canonicalToolName,
        signature,
        idempotencyKey,
        durationMs: 0,
        success: true,
        code: 'IDEMPOTENT_IN_FLIGHT',
        retryable: false,
        attempt: 1,
        maxAttempts: 1,
        replayed: true,
      });
      return inFlight;
    }
  }

  const executionPromise = executeToolCallInternal(canonicalToolName, args, {
    signal,
    idempotencyKey,
    signature,
  });

  if (idempotencyKey) {
    idempotentInFlight.set(idempotencyKey, executionPromise);
  }

  try {
    const result = await executionPromise;
    if (idempotencyKey) {
      idempotentResultCache.set(idempotencyKey, {
        result,
        expiresAt: Date.now() + IDEMPOTENCY_RESULT_TTL_MS,
      });
    }
    return result;
  } finally {
    if (idempotencyKey) {
      idempotentInFlight.delete(idempotencyKey);
    }
  }
}

async function executeToolCallInternal(
  toolName: string,
  args: Record<string, unknown>,
  options: ToolExecutionOptions & { signature: string }
): Promise<CanonicalToolResult> {
  const { signal, idempotencyKey, signature, runtime } = options;
  if (RETIRED_TOOL_NAMES.has(toolName)) {
    return normalizeToolResult(
      toolName,
      {
        success: false,
        error: `Tool "${toolName}" was removed from strict profile. Use read_file/workspace_search/apply_patch/run_command equivalents.`,
      },
      {
        idempotencyKey,
        signature,
        attempt: 1,
        maxAttempts: 1,
      },
    );
  }

  if (isMcpTool(toolName)) {
    const startedAt = Date.now();
    const result = await executeMcpTool(toolName, args);
    const normalized = normalizeToolResult(toolName, result, {
      idempotencyKey,
      signature,
      attempt: 1,
      maxAttempts: 1,
    });
    recordExecutionTelemetry(toolName, signature, idempotencyKey, normalized, Date.now() - startedAt, 1, 1, false);
    return normalized;
  }

  const capabilities = getToolCapabilities(toolName);
  const defaultTimeout = capabilities.isLongRunning ? TERMINAL_TOOL_DEFAULT_TIMEOUT_MS : DEFAULT_TIMEOUT_MS;
  const requestedTimeout = typeof args.timeout === 'number' ? args.timeout : defaultTimeout;
  const timeoutMs = Math.min(Math.max(0, requestedTimeout), MAX_TIMEOUT_MS);

  const handler = toolHandlers[toolName];
  if (!handler) {
    const normalized = normalizeToolResult(toolName, { success: false, error: `No handler for tool: ${toolName}` }, {
      idempotencyKey,
      signature,
      attempt: 1,
      maxAttempts: 1,
    });
    recordExecutionTelemetry(toolName, signature, idempotencyKey, normalized, 0, 1, 1, false);
    return normalized;
  }

  const toolDef = getToolByName(toolName);
  const maxAttempts = getToolMaxAttempts(toolName, toolDef);
  let attempt = 0;
  const execStarted = Date.now();

  while (attempt < maxAttempts) {
    let timeoutId: ReturnType<typeof setTimeout> | undefined;
    const effectiveTimeout = timeoutMs === 0 ? MAX_TIMEOUT_MS : timeoutMs;
    const timeoutPromise = new Promise<ToolResult>((resolve) => {
      timeoutId = setTimeout(() => {
        resolve({ success: false, error: 'Tool execution timed out' });
      }, effectiveTimeout);
    });

    let abortHandler: (() => void) | undefined;
    const abortPromise = new Promise<ToolResult>((resolve) => {
      if (!signal) return;
      abortHandler = () => resolve({ success: false, error: 'Tool execution cancelled' });
      signal.addEventListener('abort', abortHandler, { once: true });
    });

    try {
      beforeToolHook({
        toolName,
        args,
        attempt: attempt + 1,
        maxAttempts,
        startedAt: execStarted,
      });
      const result = await Promise.race([
        handler(args, runtime),
        timeoutPromise,
        ...(signal ? [abortPromise] : [])
      ]);

      const normalized = normalizeToolResult(toolName, result, {
        idempotencyKey,
        signature,
        attempt: attempt + 1,
        maxAttempts,
      });
      const hookOutcome = afterToolHook(
        {
          toolName,
          args,
          attempt: attempt + 1,
          maxAttempts,
          startedAt: execStarted,
        },
        normalized,
      );
      agentTelemetryStore.record({
        type: 'agent.tool.hook',
        timestamp: Date.now(),
        toolName,
        parseCategory: hookOutcome.parseCategory ?? 'none',
        attempt: attempt + 1,
        maxAttempts,
      });
      recordExecutionTelemetry(toolName, signature, idempotencyKey, normalized, Date.now() - execStarted, attempt + 1, maxAttempts, false);
      if (normalized.success || !shouldRetryResult(toolName, toolDef, normalized, attempt, maxAttempts)) {
        return normalized;
      }
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      const normalized = normalizeToolResult(toolName, { success: false, error: message }, {
        idempotencyKey,
        signature,
        attempt: attempt + 1,
        maxAttempts,
      });
      recordExecutionTelemetry(toolName, signature, idempotencyKey, normalized, Date.now() - execStarted, attempt + 1, maxAttempts, false);
      if (!shouldRetryResult(toolName, toolDef, normalized, attempt, maxAttempts)) {
        return normalized;
      }
    } finally {
      if (timeoutId) clearTimeout(timeoutId);
      if (signal && abortHandler) {
        signal.removeEventListener('abort', abortHandler);
      }
    }

    attempt++;
    await delay(200 * attempt);
  }

  const finalFailure = normalizeToolResult(toolName, { success: false, error: 'Tool execution failed' }, {
    idempotencyKey,
    signature,
    attempt: maxAttempts,
    maxAttempts,
  });
  recordExecutionTelemetry(toolName, signature, idempotencyKey, finalFailure, Date.now() - execStarted, maxAttempts, maxAttempts, false);
  return finalFailure;
}

function normalizeToolResult(
  toolName: string,
  result: ToolResult,
  context: {
    idempotencyKey?: string;
    signature: string;
    attempt: number;
    maxAttempts: number;
  }
): CanonicalToolResult {
  const baseOutput = typeof result.output === 'string'
    ? result.output
    : result.output == null
      ? ''
      : JSON.stringify(result.output, null, 2);

  const baseError = typeof result.error === 'string'
    ? result.error
    : result.error == null
      ? ''
      : String(result.error);

  const success = Boolean(result.success);
  const error = success
    ? (baseError || '')
    : (baseError || baseOutput || 'Tool execution failed');
  const output = baseOutput || (success ? '[ok]' : '');
  const budgeted = normalizeToolOutputBudget(toolName, output);
  const code = success ? 'OK' : mapErrorCode(error);
  const retryable = success ? false : isRetryableError(error);
  const warnings = Array.isArray(result.warnings)
    ? result.warnings.filter((item): item is string => typeof item === 'string')
    : [];
  return {
    success,
    output: budgeted.output,
    error,
    data: result.data ?? null,
    warnings,
    meta: {
      ...(result.meta ?? {}),
      idempotencyKey: context.idempotencyKey,
      signature: context.signature,
      attempts: context.attempt,
      maxAttempts: context.maxAttempts,
    },
    tool: toolName,
    code,
    retryable,
    timestamp: Date.now(),
    truncated: result.truncated || budgeted.truncated,
  };
}

function mapErrorCode(error?: string): string {
  const message = (error ?? '').toLowerCase();
  if (!message) return 'ERROR';
  if (message.includes('completion blocked by diagnostics')) return 'COMPLETION_BLOCKED_BY_DIAGNOSTICS';
  if (message.includes('retry exhausted')) return 'EDIT_RETRY_EXHAUSTED';
  if (message.includes('content changed on disk')) return 'EDIT_STALE_CONTENT';
  if (message.includes('timed out')) return 'TIMEOUT';
  if (message.includes('cancelled')) return 'CANCELLED';
  if (message.includes('no handler') || message.includes('unknown tool')) return 'TOOL_NOT_FOUND';
  if (message.includes('removed from strict profile')) return 'TOOL_DEPRECATED';
  if (message.includes('missing')) return 'MISSING_PARAM';
  if (message.includes('outside workspace')) return 'PATH_OUTSIDE_WORKSPACE';
  if (message.includes('not found')) return 'NOT_FOUND';
  if (message.includes('permission') || message.includes('denied')) return 'PERMISSION_DENIED';
  if (message.includes('invalid line range') || message.includes('exceeds file length')) return 'INVALID_RANGE';
  if (message.includes('syntax')) return 'SYNTAX_ERROR';
  return 'ERROR';
}

function isRetryableError(error?: string): boolean {
  const message = (error ?? '').toLowerCase();
  if (!message) return false;
  if (message.includes('timed out')) return true;
  if (message.includes('temporarily') || message.includes('transient')) return true;
  if (message.includes('network') || message.includes('econn') || message.includes('connection')) return true;
  return false;
}

function shouldRetryTool(toolName: string, toolDef: ReturnType<typeof getToolByName>): boolean {
  if (toolName.startsWith('lsp_')) return false;
  const category = toolDef?.category;
  return category === 'workspace_read' ||
    category === 'workspace_search' ||
    category === 'diagnostics';
}

function getToolMaxAttempts(
  toolName: string,
  toolDef: ReturnType<typeof getToolByName>,
): number {
  if (!shouldRetryTool(toolName, toolDef)) return 1;
  const configured = TOOL_MAX_ATTEMPTS[toolName];
  if (typeof configured === 'number' && configured > 0) return configured;
  return 2;
}

function shouldRetryResult(
  toolName: string,
  toolDef: ReturnType<typeof getToolByName>,
  result: CanonicalToolResult,
  attempt: number,
  maxAttempts: number
): boolean {
  if (attempt >= maxAttempts - 1) return false;
  if (!shouldRetryTool(toolName, toolDef)) return false;
  if (!result.retryable) return false;
  return true;
}

function stableStringify(value: unknown): string {
  if (value == null || typeof value !== 'object') {
    return JSON.stringify(value);
  }
  if (Array.isArray(value)) {
    return `[${value.map((v) => stableStringify(v)).join(',')}]`;
  }
  const obj = value as Record<string, unknown>;
  const keys = Object.keys(obj).sort();
  return `{${keys.map((k) => `${JSON.stringify(k)}:${stableStringify(obj[k])}`).join(',')}}`;
}

function createToolSignature(toolName: string, args: Record<string, unknown>): string {
  return `${toolName}:${stableStringify(args)}`;
}

function purgeExpiredIdempotencyCache(): void {
  const now = Date.now();
  for (const [key, entry] of idempotentResultCache) {
    if (entry.expiresAt <= now) {
      idempotentResultCache.delete(key);
    }
  }
}

function recordExecutionTelemetry(
  toolName: string,
  signature: string,
  idempotencyKey: string | undefined,
  result: CanonicalToolResult,
  durationMs: number,
  attempt: number,
  maxAttempts: number,
  replayed: boolean
): void {
  toolObservabilityStore.record({
    timestamp: Date.now(),
    toolName,
    signature,
    idempotencyKey,
    durationMs,
    success: result.success,
    code: result.code,
    retryable: result.retryable,
    attempt,
    maxAttempts,
    replayed,
  });
  agentTelemetryStore.record({
    type: 'agent.tool.call',
    timestamp: Date.now(),
    toolName,
    success: result.success,
    durationMs,
    code: result.code,
    retryable: result.retryable,
    signature,
  });
  if (!result.success) {
    agentTelemetryStore.record({
      type: 'agent.tool.failure_signature',
      timestamp: Date.now(),
      toolName,
      signature,
    });
  }
}

function delay(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

if (typeof window !== 'undefined' && import.meta.env.DEV) {
  const parity = getToolContractParity();
  if (parity.missingHandlers.length > 0 || parity.orphanHandlers.length > 0) {
    console.warn('[Tools] Contract parity warning', parity);
  }
}

/**
 * Format tool call for display (used in UI)
 */
export function formatToolCallForDisplay(toolCall: { name: string; arguments: Record<string, unknown> }): string {
  const args = { ...toolCall.arguments };
  delete args.meta; // Don't show meta in display

  const argStr = Object.entries(args)
    .filter(([_, v]) => v !== undefined)
    .map(([k, v]) => {
      const val = typeof v === 'string' && v.length > 50
        ? v.slice(0, 50) + '...'
        : JSON.stringify(v);
      return `${k}=${val}`;
    })
    .join(', ');

  return `${toolCall.name}(${argStr})`;
}

/**
 * Shared utilities for tool handlers
 */

import { projectStore } from '$shared/stores/project.svelte';
import { isFileError, getFileErrorMessage } from '$core/types/files';
export type { CanonicalToolResult, ToolResult } from './result';

// Maximum output size (100KB)
export const MAX_OUTPUT_SIZE = 100 * 1024;
const DEFAULT_TOOL_OUTPUT_CAP = 24 * 1024;
const TOOL_OUTPUT_CAPS: Record<string, number> = {
  read_file: 48 * 1024,
  workspace_search: 40 * 1024,
  run_command: 40 * 1024,
  apply_patch: 24 * 1024,
};

/**
 * Truncate output if too large
 */
export function truncateOutput(output: string): { text: string; truncated: boolean } {
  if (output.length <= MAX_OUTPUT_SIZE) {
    return { text: output, truncated: false };
  }
  return {
    text: output.slice(0, MAX_OUTPUT_SIZE) + '\n\n[Output truncated - exceeded 100KB]',
    truncated: true
  };
}

/**
 * Extract error message from unknown error
 */
export function extractErrorMessage(err: unknown): string {
  if (err instanceof Error) return err.message;
  if (typeof err === 'string') return err;
  if (isFileError(err)) return getFileErrorMessage(err);
  if (err && typeof err === 'object' && 'message' in err) return String(err.message);
  return 'Unknown error';
}

/**
 * Calculate simple line-based diff statistics (added/removed)
 * This is used for the green/red indicators in the chat UI
 */
export function calculateDiffStats(before: string, after: string): { added: number; removed: number } {
  if (before === after) return { added: 0, removed: 0 };
  
  const beforeLines = before.split('\n');
  const afterLines = after.split('\n');
  
  // Use a simple map to track line occurrences for counting
  const beforeMap = new Map<string, number>();
  for (const line of beforeLines) {
    beforeMap.set(line, (beforeMap.get(line) || 0) + 1);
  }
  
  let added = 0;
  const afterMap = new Map<string, number>();
  for (const line of afterLines) {
    const count = beforeMap.get(line) || 0;
    if (count > 0) {
      beforeMap.set(line, count - 1);
    } else {
      added++;
    }
  }
  
  // Remaining lines in beforeMap are removed lines
  let removed = 0;
  for (const count of beforeMap.values()) {
    removed += count;
  }
  
  return { added, removed };
}

/**
 * Resolve relative path to absolute using workspace root
 */
export function resolvePath(relativePath: string): string {
  const root = projectStore.rootPath;
  if (!root) return relativePath;

  // Already absolute
  if (relativePath.startsWith('/') || /^[A-Za-z]:/.test(relativePath)) {
    return relativePath;
  }

  // Join with root
  const separator = root.includes('\\') ? '\\' : '/';
  return root.endsWith(separator) ? root + relativePath : root + separator + relativePath;
}

/**
 * Validate path is within workspace
 */
export function validatePathInWorkspace(path: string, workspaceRoot: string): { valid: boolean; absolutePath: string; error?: string } {
  if (!workspaceRoot) {
    return { valid: false, absolutePath: '', error: 'No workspace is open' };
  }

  const normalizedPath = path.replace(/\\/g, '/');
  const normalizedRoot = workspaceRoot.replace(/\\/g, '/');

  // Build absolute path
  let absolutePath: string;
  if (normalizedPath.startsWith('/') || /^[A-Za-z]:/.test(normalizedPath)) {
    absolutePath = normalizedPath;
  } else {
    absolutePath = normalizedRoot.endsWith('/')
      ? normalizedRoot + normalizedPath
      : normalizedRoot + '/' + normalizedPath;
  }

  // Normalize (resolve . and ..)
  const parts = absolutePath.split('/').filter(p => p !== '');
  const resolved: string[] = [];

  for (const part of parts) {
    if (part === '.') continue;
    else if (part === '..') {
      if (resolved.length > 0) resolved.pop();
    } else {
      resolved.push(part);
    }
  }

  let finalPath: string;
  if (/^[A-Za-z]:$/.test(parts[0] || '')) {
    finalPath = resolved.join('/');
  } else {
    finalPath = '/' + resolved.join('/');
  }

  // Check if within workspace
  const normalizedFinal = finalPath.toLowerCase();
  const normalizedRootLower = normalizedRoot.toLowerCase();
  const rootWithSlash = normalizedRootLower.endsWith('/') ? normalizedRootLower : normalizedRootLower + '/';
  const isWithin = normalizedFinal === normalizedRootLower || normalizedFinal.startsWith(rootWithSlash);

  if (!isWithin) {
    return { valid: false, absolutePath: finalPath, error: `Path "${path}" is outside workspace` };
  }

  return { valid: true, absolutePath: finalPath };
}

/**
 * Compare paths for equality (handles different separators)
 */
export function isSameOrSuffixPath(openPath: string, absPath: string, relPath: string): boolean {
  const normalize = (p: string) => p.replace(/\\/g, '/').toLowerCase();
  const openNorm = normalize(openPath);
  const absNorm = normalize(absPath);
  const relNorm = normalize(relPath);

  if (openNorm === absNorm || openNorm === relNorm) return true;

  const relSuffix = '/' + relNorm.replace(/^\/+/, '');
  if (openNorm.endsWith(relSuffix)) return true;
  if (openNorm.endsWith(relNorm) && (openNorm.length === relNorm.length || openNorm[openNorm.length - relNorm.length - 1] === '/')) {
    return true;
  }

  return false;
}

/**
 * Format file content with line numbers
 */
export function formatWithLineNumbers(content: string, startLine: number = 1): string {
  const lines = content.split('\n');
  const maxLineNum = startLine + lines.length - 1;
  const padding = String(maxLineNum).length;

  return lines
    .map((line, i) => {
      const lineNum = String(startLine + i).padStart(padding, ' ');
      return `${lineNum}│${line}`;
    })
    .join('\n');
}

export function normalizeToolOutputBudget(
  toolName: string,
  output: string,
): { output: string; truncated: boolean } {
  const limit = TOOL_OUTPUT_CAPS[toolName] ?? DEFAULT_TOOL_OUTPUT_CAP;
  if (output.length <= limit) {
    return { output, truncated: false };
  }
  return {
    output: `${output.slice(0, limit)}\n\n[Output truncated by tool output policy]`,
    truncated: true,
  };
}

/**
 * LSP Client - Monaco Editor Diagnostics Integration
 * 
 * Monaco Editor has built-in language support through its web workers:
 * - TypeScript/JavaScript
 * - HTML
 * - CSS/SCSS/LESS
 * - JSON
 * 
 * This module:
 * 1. Configures language defaults (TypeScript, HTML, CSS)
 * 2. Registers custom languages (Svelte)
 * 3. Listens for marker (diagnostic) changes
 * 4. Pipes diagnostics to the problems store
 * 5. Implements low-RAM strategy (single LSP at a time when RAM < 4GB)
 */

import type * as Monaco from 'monaco-editor';
import { getMonaco, isMonacoLoaded } from '$core/services/monaco-loader';
import { problemsStore, type Problem, type ProblemSeverity } from '$shared/stores/problems.svelte';
import { configureHtmlDefaults, configureCssDefaults } from './html-css';
import { registerSvelteLanguage } from './svelte';

// Track if LSP client is initialized
let initialized = false;

// Track which language services are active
let activeLanguageServices = new Set<string>();

// Debounce timer for marker updates
let markerUpdateTimer: ReturnType<typeof setTimeout> | null = null;
const MARKER_UPDATE_DEBOUNCE = 150;

// Idle timeout for cleanup (5 minutes)
let idleTimer: ReturnType<typeof setTimeout> | null = null;
const IDLE_TIMEOUT = 5 * 60 * 1000;

// Track active file types
const activeLanguages = new Set<string>();

// Disposables for cleanup
const disposables: Monaco.IDisposable[] = [];

// Low RAM threshold (4GB in bytes)
const LOW_RAM_THRESHOLD = 4 * 1024 * 1024 * 1024;

// Estimated system RAM (will be updated if system info is available)
let estimatedRamBytes = 8 * 1024 * 1024 * 1024; // Default to 8GB

/**
 * Check if system is in low RAM mode
 */
function isLowRamMode(): boolean {
  return estimatedRamBytes < LOW_RAM_THRESHOLD;
}

/**
 * Set estimated RAM (can be called from system detection)
 */
export function setEstimatedRam(ramBytes: number): void {
  estimatedRamBytes = ramBytes;
}

/**
 * Language service categories for low-RAM mode
 */
type LanguageServiceCategory = 'typescript' | 'html' | 'css' | 'svelte';

/**
 * Get the language service category for a language
 */
function getLanguageServiceCategory(language: string): LanguageServiceCategory | null {
  switch (language) {
    case 'typescript':
    case 'javascript':
    case 'typescriptreact':
    case 'javascriptreact':
      return 'typescript';
    case 'html':
    case 'handlebars':
    case 'razor':
      return 'html';
    case 'css':
    case 'scss':
    case 'less':
      return 'css';
    case 'svelte':
      return 'svelte';
    default:
      return null;
  }
}

/**
 * Map Monaco MarkerSeverity to our ProblemSeverity
 */
function mapSeverity(monaco: typeof Monaco, severity: Monaco.MarkerSeverity): ProblemSeverity {
  switch (severity) {
    case monaco.MarkerSeverity.Error:
      return 'error';
    case monaco.MarkerSeverity.Warning:
      return 'warning';
    case monaco.MarkerSeverity.Info:
      return 'info';
    case monaco.MarkerSeverity.Hint:
      return 'hint';
    default:
      return 'info';
  }
}

/**
 * Extract file path from Monaco URI
 */
function getFilePathFromUri(uri: Monaco.Uri): string {
  // Our URIs are in format: inmemory://model/{encodedPath}
  const path = uri.path;
  if (path.startsWith('/')) {
    return decodeURIComponent(path.slice(1));
  }
  return decodeURIComponent(path);
}

/**
 * Check if a file is a TypeScript/JavaScript file
 * These files are handled by the TypeScript sidecar, not Monaco markers
 */
function isTsJsFile(filepath: string): boolean {
  const ext = filepath.split('.').pop()?.toLowerCase() || '';
  return ['ts', 'tsx', 'js', 'jsx', 'mts', 'cts', 'mjs', 'cjs'].includes(ext);
}

/**
 * Extract file name from path
 */
function getFileName(filePath: string): string {
  return filePath.split(/[/\\]/).pop() || filePath;
}

/**
 * Process markers from Monaco and update problems store
 * 
 * NOTE: TypeScript/JavaScript files are handled by the TypeScript sidecar,
 * so we skip Monaco markers for those files to avoid conflicts.
 */
function processMarkers(monaco: typeof Monaco): void {
  const monacoSource = 'monaco-native';
  // Get all markers from Monaco
  const allMarkers = monaco.editor.getModelMarkers({});

  // Group markers by file (excluding TS/JS files which are handled by sidecar)
  const markersByFile = new Map<string, Monaco.editor.IMarker[]>();

  for (const marker of allMarkers) {
    const filePath = getFilePathFromUri(marker.resource);

    // Skip TS/JS files - they're handled by the TypeScript sidecar
    // Also skip markers we've set ourselves to avoid loops
    if (isTsJsFile(filePath) || marker.owner === 'volt-problems') {
      continue;
    }

    const existing = markersByFile.get(filePath) || [];
    existing.push(marker);
    markersByFile.set(filePath, existing);
  }

  // Get all files that currently have problems (excluding TS/JS files)
  const currentFiles = new Set(
    problemsStore.filesWithProblems.filter(f => !isTsJsFile(f))
  );

  // Update problems for each file with markers
  for (const [filePath, markers] of markersByFile) {
    const problems: Problem[] = markers.map((marker, index) => ({
      id: `${filePath}:${marker.startLineNumber}:${marker.startColumn}:${index}`,
      file: filePath,
      fileName: getFileName(filePath),
      line: marker.startLineNumber,
      column: marker.startColumn,
      endLine: marker.endLineNumber,
      endColumn: marker.endColumn,
      message: marker.message,
      severity: mapSeverity(monaco, marker.severity),
      source: monacoSource,
      code: marker.code?.toString()
    }));

    problemsStore.setProblemsForFile(filePath, problems, monacoSource);
    currentFiles.delete(filePath);
  }

  // Clear problems for non-TS/JS files that no longer have markers
  for (const filePath of currentFiles) {
    problemsStore.clearProblemsForFile(filePath, monacoSource);
  }
}

/**
 * Debounced marker update
 */
function scheduleMarkerUpdate(monaco: typeof Monaco): void {
  if (markerUpdateTimer) {
    clearTimeout(markerUpdateTimer);
  }

  markerUpdateTimer = setTimeout(() => {
    processMarkers(monaco);
    markerUpdateTimer = null;
  }, MARKER_UPDATE_DEBOUNCE);
}

/**
 * Reset idle timer
 */
function resetIdleTimer(): void {
  if (idleTimer) {
    clearTimeout(idleTimer);
  }

  idleTimer = setTimeout(() => {
    // Could implement cleanup here if needed
    // For now, we keep the LSP active as long as Monaco is loaded
  }, IDLE_TIMEOUT);
}

/**
 * Configure TypeScript compiler options for better IDE experience
 * Uses dynamic access to avoid TypeScript type issues with Monaco's deprecated namespace
 * 
 * NOTE: We DISABLE Monaco's built-in TS diagnostics because we use the real
 * typescript-language-server sidecar for diagnostics. This prevents conflicts
 * where Monaco squiggles show different errors than the Problems panel.
 */
function configureTypeScript(monaco: typeof Monaco): void {
  // Access TypeScript defaults through dynamic property access
  // This is needed because Monaco's types mark these as deprecated
  const languages = monaco.languages as Record<string, unknown>;
  const typescript = languages['typescript'] as {
    typescriptDefaults?: {
      setCompilerOptions: (options: Record<string, unknown>) => void;
      setDiagnosticsOptions: (options: Record<string, unknown>) => void;
    };
    javascriptDefaults?: {
      setCompilerOptions: (options: Record<string, unknown>) => void;
      setDiagnosticsOptions: (options: Record<string, unknown>) => void;
    };
    ScriptTarget?: Record<string, number>;
    ModuleKind?: Record<string, number>;
    ModuleResolutionKind?: Record<string, number>;
    JsxEmit?: Record<string, number>;
  };

  if (!typescript?.typescriptDefaults || !typescript?.javascriptDefaults) {
    return;
  }

  const compilerOptions: Record<string, unknown> = {
    target: typescript.ScriptTarget?.ESNext ?? 99,
    module: typescript.ModuleKind?.ESNext ?? 99,
    moduleResolution: typescript.ModuleResolutionKind?.NodeJs ?? 2,
    jsx: typescript.JsxEmit?.React ?? 2,
    allowNonTsExtensions: true,
    allowJs: true,
    checkJs: true,
    strict: true,
    noEmit: true,
    esModuleInterop: true,
    skipLibCheck: true,
    forceConsistentCasingInFileNames: true,
    resolveJsonModule: true,
    isolatedModules: true,
    noUnusedLocals: false,
    noUnusedParameters: false,
    noImplicitReturns: true,
    noFallthroughCasesInSwitch: true
  };

  // Apply to both TypeScript and JavaScript
  typescript.typescriptDefaults.setCompilerOptions(compilerOptions);
  typescript.javascriptDefaults.setCompilerOptions(compilerOptions);

  // DISABLE Monaco's built-in TS diagnostics - we use the real TS server sidecar instead
  // This prevents conflicts between Monaco squiggles and Problems panel
  const diagnosticsOptions = {
    noSemanticValidation: true,  // Disable - handled by TS sidecar
    noSyntaxValidation: true,    // Disable - handled by TS sidecar
    noSuggestionDiagnostics: true // Disable - handled by TS sidecar
  };

  typescript.typescriptDefaults.setDiagnosticsOptions(diagnosticsOptions);
  typescript.javascriptDefaults.setDiagnosticsOptions(diagnosticsOptions);

  activeLanguageServices.add('typescript');
}

/**
 * Configure all language services
 */
function configureAllLanguages(monaco: typeof Monaco): void {
  // Configure TypeScript/JavaScript
  configureTypeScript(monaco);

  // Configure HTML
  configureHtmlDefaults(monaco);
  activeLanguageServices.add('html');

  // Configure CSS/SCSS/LESS
  configureCssDefaults(monaco);
  activeLanguageServices.add('css');

  // Register Svelte language
  registerSvelteLanguage(monaco);
  activeLanguageServices.add('svelte');
}

/**
 * Initialize the LSP client
 * Should be called when Monaco is loaded
 */
export function initializeLspClient(): void {
  if (initialized) return;

  const monaco = getMonaco();
  if (!monaco) return;

  // Configure all language services
  configureAllLanguages(monaco);

  // Listen for marker changes
  const markerDisposable = monaco.editor.onDidChangeMarkers(() => {
    scheduleMarkerUpdate(monaco);
    resetIdleTimer();
  });
  disposables.push(markerDisposable);

  // Initial marker processing
  processMarkers(monaco);

  initialized = true;
  resetIdleTimer();
}

/**
 * Check if a language should trigger LSP initialization
 */
export function isLspLanguage(language: string): boolean {
  const lspLanguages = [
    // TypeScript/JavaScript
    'typescript', 'javascript', 'typescriptreact', 'javascriptreact',
    // HTML
    'html', 'handlebars', 'razor',
    // CSS
    'css', 'scss', 'less',
    // Svelte
    'svelte'
  ];
  return lspLanguages.includes(language);
}

/**
 * Get active language services
 */
export function getActiveLanguageServices(): string[] {
  return Array.from(activeLanguageServices);
}

/**
 * Check if running in low RAM mode
 */
export function isInLowRamMode(): boolean {
  return isLowRamMode();
}

/**
 * Notify that a file with a specific language was opened
 * This triggers LSP initialization if needed
 */
export function notifyFileOpened(language: string): void {
  if (!isLspLanguage(language)) return;

  activeLanguages.add(language);

  // Initialize LSP if Monaco is loaded
  if (isMonacoLoaded() && !initialized) {
    initializeLspClient();
  }

  resetIdleTimer();
}

/**
 * Notify that a file was closed
 */
export function notifyFileClosed(language: string): void {
  activeLanguages.delete(language);
}

/**
 * Dispose the LSP client
 */
export function disposeLspClient(): void {
  if (markerUpdateTimer) {
    clearTimeout(markerUpdateTimer);
    markerUpdateTimer = null;
  }

  if (idleTimer) {
    clearTimeout(idleTimer);
    idleTimer = null;
  }

  for (const disposable of disposables) {
    disposable.dispose();
  }
  disposables.length = 0;

  activeLanguages.clear();
  for (const filePath of problemsStore.filesWithSource('monaco-native')) {
    problemsStore.clearProblemsForFile(filePath, 'monaco-native');
  }
  initialized = false;
}

/**
 * Check if LSP client is initialized
 */
export function isLspInitialized(): boolean {
  return initialized;
}

/**
 * CSS LSP Sidecar Service
 * 
 * Provides CSS/SCSS/LESS language intelligence using vscode-css-language-server:
 * - Completions (properties, values, selectors)
 * - Hover information (property docs)
