      setOptions: (options: Record<string, unknown>) => void;
    };
    lessDefaults?: {
      setOptions: (options: Record<string, unknown>) => void;
    };
  };

  const cssOptions = {
    validate: true,
    lint: {
      compatibleVendorPrefixes: 'warning',
      vendorPrefix: 'warning',
