export const dartMonarchLanguage: Monaco.languages.IMonarchLanguage = {
    defaultToken: '',
    tokenPostfix: '', // Keep empty to use standard theme tokens

    keywords: [
        'abstract', 'as', 'assert', 'async', 'await', 'base', 'break', 'case',
