            [/(@digits)/, 'number'],

            // Delimiter
            [/[;,.]/, 'delimiter'],

            // Strings
            [/"""/, 'string', '@multilinestring'],
            [/"/, 'string', '@string_double'],
            [/'/, 'string', '@string_single'],
            [/r"/, 'string', '@rawstring_double'],
            [/r'/, 'string', '@rawstring_single'],
