        whitespace: [
            [/[ \t\r\n]+/, ''],
            [/\/\*\*(?!\/)/, 'comment', '@doccomment'],
            [/\/\*/, 'comment', '@comment'],
            [/\/\/.*$/, 'comment'],
        ],

        comment: [
            [/[^\/*]+/, 'comment'],
            [/\*\//, 'comment', '@pop'],
            [/[\/*]/, 'comment'],
        ],

        doccomment: [
            [/[^\/*]+/, 'comment'],
            [/\*\//, 'comment', '@pop'],
            [/[\/*]/, 'comment'],
        ],

        string_double: [
            [/[^\\"$]+/, 'string'],
            [/@escapes/, 'string'],
            [/\\./, 'string'],
            [/\$\{/, { token: 'variable', next: '@interpolation' }],
            [/\$[a-zA-Z_]\w*/, 'variable'],
            [/"/, 'string', '@pop'],
        ],

        string_single: [
            [/[^\\'$]+/, 'string'],
            [/@escapes/, 'string'],
            [/\\./, 'string'],
            [/\$\{/, { token: 'variable', next: '@interpolation' }],
            [/\$[a-zA-Z_]\w*/, 'variable'],
