        ],

        rawstring_single: [
            [/[^']+/, 'string'],
            [/'/, 'string', '@pop'],
        ],

        multilinestring: [
            [/[^\\"$]+/, 'string'],
            [/@escapes/, 'string'],
            [/\$\{/, { token: 'variable', next: '@interpolation' }],
            [/\$[a-zA-Z_]\w*/, 'variable'],
            [/"""/, 'string', '@pop'],
            [/./, 'string'],
        ],

        interpolation: [
            [/\{/, { token: 'variable', next: '@push' }],
            [/\}/, { token: 'variable', next: '@pop' }],
            { include: 'root' },
        ],
    },
};

/**
 * Register Dart language with Monaco Editor
 */
export function registerDartLanguage(monaco: typeof Monaco): void {
    console.log('[Monaco] Registering Dart language...');
    try {
        const languages = monaco.languages.getLanguages();
        const existing = languages.find(lang => lang.id === 'dart');

        if (existing) {
            console.log('[Monaco] Dart language already registered, updating tokenizer...');
            monaco.languages.setMonarchTokensProvider('dart', dartMonarchLanguage);
            monaco.languages.setLanguageConfiguration('dart', dartLanguageConfiguration);
            return;
        }

        monaco.languages.register({
            id: 'dart',
            extensions: ['.dart'],
            aliases: ['Dart', 'dart'],
        });

        monaco.languages.setLanguageConfiguration('dart', dartLanguageConfiguration);
        monaco.languages.setMonarchTokensProvider('dart', dartMonarchLanguage);

        console.log('[Monaco] Dart language registered successfully');
    } catch (err) {
        console.error('[Monaco] Failed to register Dart language:', err);
    }
}

/**
 * Monaco Editor Lazy Loader
 * Loads Monaco only when first file opens to improve startup performance
 */

import type * as Monaco from 'monaco-editor';
import { voltDarkMonacoTheme } from '$shared/themes/dark';
import { voltLightMonacoTheme } from '$shared/themes/light';
import { voltMidnightMonacoTheme } from '$shared/themes/midnight';
import { voltDarkModernMonacoTheme } from '$shared/themes/dark-modern';
import { registerDartLanguage } from './monaco-dart-language';

// Singleton instance - null until first load
let monacoInstance: typeof Monaco | null = null;
let loadPromise: Promise<typeof Monaco> | null = null;

/**
 * Configure Monaco environment for Vite
 * Sets up web workers for language features
 */
function configureMonacoEnvironment(): void {
  if (typeof self === 'undefined') return;

  self.MonacoEnvironment = {
    getWorker(_workerId: string, label: string): Worker {
      let workerUrl: string;

      switch (label) {
        case 'json':
          workerUrl = new URL(
            'monaco-editor/esm/vs/language/json/json.worker.js',
            import.meta.url
          ).href;
          break;
        case 'css':
        case 'scss':
        case 'less':
          workerUrl = new URL(
            'monaco-editor/esm/vs/language/css/css.worker.js',
            import.meta.url
          ).href;
          break;
        case 'html':
        case 'handlebars':
        case 'razor':
          workerUrl = new URL(
            'monaco-editor/esm/vs/language/html/html.worker.js',
            import.meta.url
          ).href;
          break;
        case 'typescript':
        case 'javascript':
          workerUrl = new URL(
            'monaco-editor/esm/vs/language/typescript/ts.worker.js',
            import.meta.url
          ).href;
          break;
        default:
          workerUrl = new URL(
            'monaco-editor/esm/vs/editor/editor.worker.js',
            import.meta.url
          ).href;
      }

      return new Worker(workerUrl, { type: 'module' });
    }
  };
}

/**
 * Load Monaco Editor lazily
 * Returns cached instance if already loaded
 */
export async function loadMonaco(): Promise<typeof Monaco> {
  // Return cached instance
  if (monacoInstance) {
    return monacoInstance;
  }

  // Return existing promise if load in progress
  if (loadPromise) {
    return loadPromise;
  }

  // Start loading
  loadPromise = (async () => {
    // Configure workers before importing
    configureMonacoEnvironment();

    // Dynamic import - this is where the actual loading happens
    const monaco = await import('monaco-editor');

    // Try to load built-in common languages if they aren't loaded
    try {
      // @ts-ignore
      await import('monaco-editor/esm/vs/basic-languages/dart/dart.contribution');
      console.log('[Monaco] Built-in Dart language loaded');
    } catch (e) {
      console.warn('[Monaco] Built-in Dart language not found, using custom registration');
      // Register custom languages
      registerDartLanguage(monaco);
    }

    // Define custom themes
    monaco.editor.defineTheme('volt-dark', voltDarkMonacoTheme);
    monaco.editor.defineTheme('volt-dark-modern', voltDarkModernMonacoTheme);
    monaco.editor.defineTheme('volt-midnight', voltMidnightMonacoTheme);
    monaco.editor.defineTheme('volt-light', voltLightMonacoTheme);

    // Cache the instance
    monacoInstance = monaco;

    return monaco;
  })();

  return loadPromise;
}

/**
 * Check if Monaco is already loaded
 */
export function isMonacoLoaded(): boolean {
  return monacoInstance !== null;
}

/**
 * Get Monaco instance if loaded (returns null if not loaded)
 */
export function getMonaco(): typeof Monaco | null {
  return monacoInstance;
}

/**
 * Detect language from file extension
 */
export function detectLanguage(filename: string): string {
  if (!filename) return 'plaintext';

  const ext = filename.split('.').pop()?.toLowerCase() || '';

  const languageMap: Record<string, string> = {
    // Mobile Development
    'dart': 'dart',
    'kt': 'kotlin',
    'kts': 'kotlin',
    'swift': 'swift',
    'gradle': 'groovy',

    // JavaScript/TypeScript
    'js': 'javascript',
    'mjs': 'javascript',
    'cjs': 'javascript',
    'jsx': 'javascript',
    'ts': 'typescript',
    'tsx': 'typescript',
    'mts': 'typescript',
    'cts': 'typescript',

    // Svelte/Vue
    'svelte': 'svelte',
    'vue': 'html',

    // Web
    'html': 'html',
    'htm': 'html',
    'css': 'css',
    'scss': 'scss',
    'sass': 'scss',
    'less': 'less',

    // Data formats
    'json': 'json',
    'jsonc': 'json',
    'yaml': 'yaml',
    'yml': 'yaml',
    'xml': 'xml',
    'svg': 'xml',
    'toml': 'ini',
    'ini': 'ini',
    'env': 'ini',

    // Markdown
    'md': 'markdown',
    'mdx': 'markdown',

    // Shell
    'sh': 'shell',
    'bash': 'shell',
    'zsh': 'shell',
    'ps1': 'powershell',
    'bat': 'bat',
    'cmd': 'bat',

    // Other languages
    'py': 'python',
    'rs': 'rust',
    'go': 'go',
    'java': 'java',
    'c': 'c',
    'cpp': 'cpp',
    'h': 'c',
    'hpp': 'cpp',
    'cs': 'csharp',
    'php': 'php',
    'rb': 'ruby',
    'sql': 'sql'
  };

  return languageMap[ext] || 'plaintext';
}

