import type {
  ChatMessage,
  ContentPart,
  FunctionResponsePart,
} from '$core/ai';
import type {
  AssistantMessage,
  ImageAttachment,
} from '$features/assistant/stores/assistant.svelte';

export function toProviderMessages(messages: AssistantMessage[]): ChatMessage[] {
  const out: ChatMessage[] = [];
  const completedToolResultIds = new Set<string>();

  for (const msg of messages) {
    if (msg.role !== 'tool' || !msg.toolCalls?.length) continue;
    for (const tc of msg.toolCalls) {
      if (tc.id?.trim()) {
        completedToolResultIds.add(tc.id);
      }
    }
  }

  for (const msg of messages) {
    if (msg.role === 'system') {
      out.push({ role: 'system', content: msg.content });
      continue;
    }

    if (msg.role === 'tool' && msg.toolCalls && msg.toolCalls.length > 0) {
      for (const tc of msg.toolCalls) {
        const responsePart: FunctionResponsePart = {
          type: 'function_response',
          id: tc.id,
          name: tc.name,
          response: {
            success: tc.status === 'completed',
            output:
              tc.output ??
              (tc.data ? JSON.stringify(tc.data) : undefined) ??
              tc.error ??
              'No output',
            error: tc.error ?? '',
            meta: tc.meta ?? {},
            data: tc.data,
            warnings: Array.isArray((tc.meta as any)?.warnings)
              ? (tc.meta as any).warnings
              : [],
          },
        };
        out.push({
          role: 'user',
          content: '',
          parts: [responsePart],
        });
      }
      continue;
    }

    if (msg.role === 'assistant') {
      const resolvedToolCalls =
        msg.inlineToolCalls?.filter(
          (tc) => tc.id?.trim() && completedToolResultIds.has(tc.id),
        ) ?? [];
      const hasToolCalls = resolvedToolCalls.length > 0;

      if (hasToolCalls) {
        const parts: ContentPart[] = [];

        if (msg.content && msg.content.trim()) {
          parts.push({ type: 'text', text: msg.content });
        }

        for (const tc of resolvedToolCalls) {
            parts.push({
              type: 'function_call',
              id: tc.id,
              name: tc.name,
              arguments: tc.arguments,
              thoughtSignature: tc.thoughtSignature,
            });
        }

        out.push({ role: 'assistant', content: msg.content, parts });
      } else {
        out.push({ role: 'assistant', content: msg.content });
      }
      continue;
    }

    if (msg.role !== 'user') continue;

    const attachments = msg.attachments ?? [];
    const imageAttachments = attachments.filter(
      (a) => a.type === 'image',
    ) as ImageAttachment[];
    const parts: ContentPart[] = [];

    if (msg.smartContextBlock) {
      parts.push({
        type: 'text',
        text: `<system_context>\n${msg.smartContextBlock}\n</system_context>`,
      });
    }

    if (msg.content && msg.content.trim()) {
      parts.push({ type: 'text', text: msg.content });
    }

    for (const img of imageAttachments) {
      parts.push({ type: 'image', mimeType: img.mimeType, data: img.data });
    }

    if (parts.length === 1 && parts[0].type === 'text' && !msg.smartContextBlock) {
      out.push({ role: 'user', content: msg.content });
    } else if (parts.length > 0) {
      out.push({ role: 'user', content: msg.content, parts });
    }
  }

  return out;
}

export interface StreamingTextBuffer {
  append: (chunk: string) => void;
  flushNow: () => Promise<void>;
  close: () => Promise<void>;
}

export interface StreamingTextBufferOptions {
  intervalMs?: number;
  sliceChars?: number;
  onFlush: (text: string) => void;
}

type ChunkingMode = "smooth" | "catch_up";

const ENTER_QUEUE_DEPTH = 8;
const ENTER_OLDEST_AGE_MS = 120;
const EXIT_QUEUE_DEPTH = 2;
const EXIT_OLDEST_AGE_MS = 40;
const EXIT_HOLD_MS = 250;
const REENTER_HOLD_MS = 250;
const SEVERE_QUEUE_DEPTH = 64;
const SEVERE_OLDEST_AGE_MS = 300;

interface QueuedChunk {
  text: string;
  queuedAt: number;
}

function splitIntoChunks(text: string, sliceChars: number): string[] {
  if (!text) return [];
  if (text.length <= sliceChars) return [text];
  const chunks: string[] = [];
  let cursor = 0;
  while (cursor < text.length) {
    chunks.push(text.slice(cursor, cursor + sliceChars));
    cursor += sliceChars;
  }
  return chunks;
}

export function createStreamingTextBuffer(
  options: StreamingTextBufferOptions,
): StreamingTextBuffer {
  const intervalMs = Math.max(10, options.intervalMs ?? 45);
  const sliceChars = Math.max(20, options.sliceChars ?? 120);

  let pendingText = "";
  let queue: QueuedChunk[] = [];
  let timer: ReturnType<typeof setTimeout> | null = null;
  let activeFlush: Promise<void> | null = null;
  let mode: ChunkingMode = "smooth";
  let belowExitThresholdSince: number | null = null;
  let lastCatchUpExitAt: number | null = null;

  const schedule = () => {
    if (timer) return;
    timer = setTimeout(() => {
      timer = null;
      void flush(false);
    }, intervalMs);
  };

  const enqueue = (text: string, queuedAt = Date.now()) => {
    for (const chunk of splitIntoChunks(text, sliceChars)) {
      queue.push({ text: chunk, queuedAt });
    }
  };

  const moveReadyTextToQueue = (forcePartial: boolean) => {
    if (!pendingText) return;

    let committedUpTo = 0;
    let newlineIndex = pendingText.indexOf("\n");
    while (newlineIndex !== -1) {
      const segment = pendingText.slice(committedUpTo, newlineIndex + 1);
      if (segment) enqueue(segment);
      committedUpTo = newlineIndex + 1;
      newlineIndex = pendingText.indexOf("\n", committedUpTo);
    }

    if (committedUpTo > 0) {
      pendingText = pendingText.slice(committedUpTo);
    }

    if (
      pendingText &&
      (forcePartial || pendingText.length >= sliceChars * 2)
    ) {
      const partial = pendingText;
      pendingText = "";
      enqueue(partial);
    }
  };

  const getOldestAgeMs = (now: number): number | null => {
    const oldest = queue[0];
    return oldest ? Math.max(0, now - oldest.queuedAt) : null;
  };

  const isSevereBacklog = (queuedLines: number, oldestAgeMs: number | null): boolean =>
    queuedLines >= SEVERE_QUEUE_DEPTH ||
    (oldestAgeMs !== null && oldestAgeMs >= SEVERE_OLDEST_AGE_MS);

  const decideDrainCount = (now: number): number => {
    if (queue.length === 0) {
      if (mode === "catch_up") {
        lastCatchUpExitAt = now;
      }
      mode = "smooth";
      belowExitThresholdSince = null;
      return 0;
    }

    const oldestAgeMs = getOldestAgeMs(now);

    if (mode === "smooth") {
      const shouldEnter =
        queue.length >= ENTER_QUEUE_DEPTH ||
        (oldestAgeMs !== null && oldestAgeMs >= ENTER_OLDEST_AGE_MS);
      const reentryBlocked =
        lastCatchUpExitAt !== null &&
        now - lastCatchUpExitAt < REENTER_HOLD_MS &&
        !isSevereBacklog(queue.length, oldestAgeMs);
      if (shouldEnter && !reentryBlocked) {
        mode = "catch_up";
        belowExitThresholdSince = null;
        lastCatchUpExitAt = null;
      }
    } else {
      const shouldExit =
        queue.length <= EXIT_QUEUE_DEPTH &&
        (oldestAgeMs === null || oldestAgeMs <= EXIT_OLDEST_AGE_MS);
      if (!shouldExit) {
        belowExitThresholdSince = null;
      } else if (belowExitThresholdSince === null) {
        belowExitThresholdSince = now;
      } else if (now - belowExitThresholdSince >= EXIT_HOLD_MS) {
        mode = "smooth";
        belowExitThresholdSince = null;
        lastCatchUpExitAt = now;
      }
    }

    return mode === "catch_up" ? queue.length : 1;
  };

  const flush = async (force: boolean): Promise<void> => {
    if (activeFlush) {
      if (force) await activeFlush;
      return;
    }

    activeFlush = (async () => {
      moveReadyTextToQueue(force);

      while (queue.length > 0) {
        const drainCount = force ? queue.length : decideDrainCount(Date.now());
        if (drainCount <= 0) break;

        const batch = queue.splice(0, drainCount).map((item) => item.text);
        if (batch.length === 0) break;
        options.onFlush(batch.join(""));

        if (!force) break;
        await new Promise((resolve) => setTimeout(resolve, 8));
      }

      if (pendingText.length > 0 || queue.length > 0) {
        schedule();
      }
    })();

    await activeFlush;
    activeFlush = null;
  };

  return {
    append(chunk: string) {
      if (!chunk) return;
      pendingText += chunk;
      schedule();
    },
    flushNow() {
      return flush(true);
    },
    async close() {
      if (timer) {
        clearTimeout(timer);
        timer = null;
      }
      await flush(true);
    },
  };
}

import { describe, expect, it, vi } from "vitest";
import {
  buildTerminalToolExcerpt,
  readTerminalTranscriptSlice,
} from "./terminal-tool-transcript";

describe("terminal-tool-transcript", () => {
  it("reads only output after the provided start offset", () => {
    const readCleanOutputSince = vi.fn((offset: number, maxChars: number) => ({
      text: offset === 20 ? "owned output\n" : "wrong output\n",
      nextOffset: 33,
      truncatedBeforeOffset: false,
    }));
    const session = {
      readCleanOutputSince,
    };

    const result = readTerminalTranscriptSlice(session, 20, 4000);

    expect(readCleanOutputSince).toHaveBeenCalledWith(20, 4000);
    expect(result).toEqual({
      text: "owned output\n",
      nextOffset: 33,
      truncatedBeforeOffset: false,
    });
  });

  it("builds a bounded excerpt without mixing old output", () => {
    const excerpt = buildTerminalToolExcerpt("a\nb\nc\nd\ne", 2);
    expect(excerpt).toBe("d\ne");
  });

  it("preserves truncation signal for caller handling", () => {
    const session = {
      readCleanOutputSince: () => ({
        text: "partial\n",
        nextOffset: 99,
        truncatedBeforeOffset: true,
      }),
    };

    expect(readTerminalTranscriptSlice(session, 40, 4000).truncatedBeforeOffset).toBe(true);
  });
});

export interface LoopTerminalOutcome {
  status: 'completed' | 'failed' | 'cancelled';
  reason: string;
  assistantMessage?: string;
  streamState?: 'completed' | 'failed' | 'cancelled' | 'interrupted';
  streamIssue?: string;
  loopStateMeta?: Record<string, unknown>;
  finalizeMeta?: Record<string, unknown>;
  loopLogLevel?: 'info' | 'warn' | 'error';
  loopLogEvent?: string;
  loopLogDetails?: Record<string, unknown>;
  toast?: { message: string; type: 'warning' | 'error' };
  outputLog?: string;
}

export interface LoopFinalizerAdapter {
  updateAssistantMessage: (messageId: string, content: string, streaming: boolean) => void;
  markAssistantMessageStreamState: (
    messageId: string,
    state: 'completed' | 'failed' | 'cancelled' | 'interrupted',
    issue?: string,
  ) => void;
  setAgentLoopState: (state: any, meta?: Record<string, unknown>) => void;
  finalizeOutcome: (
    status: 'completed' | 'failed' | 'cancelled',
    reason: string,
    meta?: Record<string, unknown>,
  ) => void;
  loopLog: (
    level: 'info' | 'warn' | 'error',
    event: string,
    details?: Record<string, unknown>,
  ) => void;
  showToast: (toast: { message: string; type: 'warning' | 'error' }) => void;
  logOutput?: (message: string) => void;
}

export function applyLoopTerminalOutcome(
  messageId: string,
  outcome: LoopTerminalOutcome,
  adapter: LoopFinalizerAdapter,
): void {
  if (outcome.assistantMessage !== undefined) {
    adapter.updateAssistantMessage(messageId, outcome.assistantMessage, false);
  }
  if (outcome.streamState) {
    adapter.markAssistantMessageStreamState(messageId, outcome.streamState, outcome.streamIssue);
  }
  adapter.setAgentLoopState(outcome.status, {
    reason: outcome.reason,
    ...(outcome.loopStateMeta ?? {}),
  });
  adapter.finalizeOutcome(outcome.status, outcome.reason, outcome.finalizeMeta);
  if (outcome.loopLogLevel && outcome.loopLogEvent) {
    adapter.loopLog(outcome.loopLogLevel, outcome.loopLogEvent, outcome.loopLogDetails);
  }
  if (outcome.outputLog && adapter.logOutput) {
    adapter.logOutput(outcome.outputLog);
  }
  if (outcome.toast) {
    adapter.showToast(outcome.toast);
  }
}

